//   н•ҙкІ°: л¶Җмһ‘мҡ©мқ„ _cliBootstrap() мңјлЎң л¬¶кі  нҢҢмқј лҒқ require.main к°Җл“ңм—җм„ңл§Ң нҳём¶ң. import/лӢЁмң„н…ҢмҠӨнҠёлҠ” л¶Җмһ‘мҡ© 0.
// 1.9.249 (UR-0018): н„°лҜёл„җ м¶ңл Ҙ н•ңкөӯм–ҙ к№Ём§җ мӮ¬м „ л°©м§Җ (stdout UTF-8 + Windows л№„-65001 мӢң chcp 65001 мһҗлҸҷ, opt-out LEERNESS_NO_AUTOCHCP=1).
function _ensureStdoutEncoding() {
  try {
    if (process.stdout && process.stdout.setEncoding) process.stdout.setEncoding('utf8');
    if (process.stderr && process.stderr.setEncoding) process.stderr.setEncoding('utf8');
  } catch {}
  if (process.platform !== 'win32') return;
  if (process.env.LEERNESS_NO_AUTOCHCP === '1') return;
  if (process.env._LEERNESS_CHCP_DONE === '1') return;  // мһҗмӢқ spawn л¬ҙн•ң мһ¬нҳём¶ң л°©м§Җ
  try {
    const r = cp.spawnSync('chcp.com', [], { encoding: 'utf8', timeout: 2000, shell: true });
    const out = (r.stdout || '') + (r.stderr || '');
    const m = out.match(/(\d+)\s*$/m);
    const code = m ? parseInt(m[1], 10) : null;
    // 65001 = UTF-8, 949 = CP949 (н•ңкөӯ), 932 = CP932 (мқјліё), 936 = CP936 (мӨ‘көӯ)
    if (code && code !== 65001) {
      try {
        cp.spawnSync('chcp.com', ['65001'], { encoding: 'utf8', timeout: 2000, shell: true, stdio: 'ignore' });
        process.env._LEERNESS_AUTOCHCP_APPLIED = String(code);  // м§„лӢЁмҡ© вҖ” handoff body м—җм„ң л…ём¶ң
      } catch {}
    }
    process.env._LEERNESS_CHCP_DONE = '1';
  } catch {}
}
