function selfTestCmd(opts = {}) {
  const isTty = process.stdout && process.stdout.isTTY;
  const gr = s => isTty ? `\x1b[32m${s}\x1b[0m` : s;
  const rd = s => isTty ? `\x1b[31m${s}\x1b[0m` : s;
  const cy = s => isTty ? `\x1b[36m${s}\x1b[0m` : s;
  const dm = s => isTty ? `\x1b[2m${s}\x1b[0m` : s;
  const cases = _selfTestCases();
  const results = cases.map(c => {
    let ok = false, err = null;
    try { ok = c.run() === true; } catch (e) { ok = false; err = e.message; }
    return { name: c.name, ok, err };
  });
  const pass = results.filter(r => r.ok).length;
  const fail = results.length - pass;
  if (opts.json) {
    log(JSON.stringify({ version: VERSION, total: results.length, pass, fail, ok: fail === 0, results }, null, 2));
    if (fail > 0) process.exitCode = 1;
    return;
  }
  log(cy(`# leerness selftest (1.9.258) вҖ” мҪ”м–ҙ н•ЁмҲҳ л¬ҙкІ°м„ұ кІҖмҰқ (v${VERSION})`));
  log('');
  results.forEach(r => {
    if (r.ok) log(`  ${gr('вң“')} ${r.name}`);
    else log(`  ${rd('вң—')} ${r.name}${r.err ? dm(' вҖ” ' + r.err) : ''}`);
  });
  log('');
  if (fail === 0) {
    log(gr(`  вң“ м „мІҙ ${results.length}кұҙ нҶөкіј вҖ” leerness м„Өм№ҳ м •мғҒ`));
  } else {
    log(rd(`  вң— ${fail}/${results.length}кұҙ мӢӨнҢЁ вҖ” м„Өм№ҳ мҶҗмғҒ мқҳмӢ¬`));
    log(dm(`     вҶ’ мһ¬м„Өм№ҳ: npm i -g leerness@latest  В·  м§„лӢЁ: leerness which`));
    process.exitCode = 1;
  }
}

// 1.9.260: shell-guard вҖ” н„°лҜёл„җ лӘ…л № м…ё нҳёнҷҳм„ұ лҰ°н„° + мӢӨнҢЁ л©”лӘЁлҰ¬ (мӮ¬мҡ©мһҗ лӘ…мӢң UR-0020)
//   л°°кІҪ: leerness м Ғмҡ© н”„лЎңм қнҠём—җм„ң н„°лҜёл„җ лӘ…л №мқҙ м…ё м°Ёмқҙ(PowerShell 5.1 && лҜём§Җмӣҗ л“ұ)лЎң мӢӨнҢЁ.
//   leerness лҠ” м…ёмқ„ м§Ғм ‘ к°ҖлЎңмұҢ мҲҳ м—ҶмңјлҜҖлЎң(0-dep Node CLI) вҶ’ мӢӨн–ү м „ м •м Ғ л¶„м„қ + мӢӨнҢЁ кё°лЎқ/нҡҢмҲҳлЎң лҢҖмқ‘.
