  // 1.9.353 (UR-0070 мҷёл¶ҖлҰ¬л·°): --shell лЎң лҢҖмғҒ м…ё лӘ…мӢң вҖ” мһҗлҸҷ к°җм§Җ(git-bash кІҪмң  л“ұ)к°Җ мӢӨм ң мӢӨн–ү м…ёкіј лӢ¬лқј PS5.1 && к°Җл“ңк°Җ л¬ҙл Ҙнҷ”лҗҳлҠ” кІғ л°©м§Җ
  const ctx = opts.shell ? { shell: opts.shell, psVersion: opts.shell === 'powershell' ? (opts.psVersion || '5') : null } : _detectShellCtx();
