// 1.9.374 (UR-0074): release cadence вҖ” лҰҙлҰ¬мҠӨ л№ҲлҸ„ м§„лӢЁ + к¶ҢмһҘ (мҷёл¶ҖлҰ¬л·° л°ҳліө м§Җм Ғ "лҰҙлҰ¬мҠӨ мјҖмқҙлҚҳмҠӨ кіјлӢӨ" к°ҖмӢңнҷ”). git tag мһ¬мӮ¬мҡ©, мқҪкё° м „мҡ©.
function releaseCadenceCmd(root) {
  root = absRoot(root);
  const rh = _computeRoundHistory(root);
  const a = _cadenceAssessment(rh.avgRoundsPerDay, rh.roundCount, rh.daysActive);
  if (has('--json')) { log(JSON.stringify({ version: VERSION, currentVersion: rh.currentVersion, baselineVersion: rh.baselineVersion, ...a }, null, 2)); return; }
  log(`# leerness release cadence (1.9.374, UR-0074) вҖ” лҰҙлҰ¬мҠӨ л№ҲлҸ„ м§„лӢЁ (мқҪкё° м „мҡ©)`);
  log(`  лҲ„м Ғ лҰҙлҰ¬мҠӨ: ${a.total}  В·  нҷңлҸҷмқј: ${a.daysActive}мқј  В·  л№ҲлҸ„: ${a.releasesPerDay}/day`);
  log(`  мҲҳмӨҖ: ${a.level}`);
  log(`  к¶ҢмһҘ: ${a.recommendation}`);
  log(`\n  кҙҖл Ё: leerness release channel (stable/next м •мұ…)  В·  leerness install-safety (кіөкёүл§қ мӢ лў°)`);
}
function roundHistoryCmd(root) {
  root = absRoot(root);
  const isTty = process.stdout && process.stdout.isTTY;
  const cy = s => isTty ? `\x1b[36m${s}\x1b[0m` : s;
  const gr = s => isTty ? `\x1b[32m${s}\x1b[0m` : s;
  const yl = s => isTty ? `\x1b[33m${s}\x1b[0m` : s;
  const dm = s => isTty ? `\x1b[2m${s}\x1b[0m` : s;
  const data = _computeRoundHistory(root);
  if (has('--json')) { log(JSON.stringify(data, null, 2)); return; }
  log(cy(`# leerness round-history (1.9.226) вҖ” мһҗмңЁ лқјмҡҙл“ң нҶөкі„`));
  log('');
  log(`  рҹ“Ұ нҳ„мһ¬ лІ„м „: ${gr(data.currentVersion)}`);
  log(`  рҹ”„ лҲ„м Ғ лқјмҡҙл“ң: ${gr(String(data.roundCount))}`);
  if (data.baselineVersion) log(`  рҹ“Қ baseline: v${data.baselineVersion} (${(data.firstTagAt || '').split('T')[0]})`);
  if (data.latestTagAt) log(`  вҸ° мөңк·ј tag: ${(data.latestTagAt || '').split('T')[0]}`);
  if (data.daysActive > 0) log(`  рҹ“Ҡ нҷңлҸҷ: ${data.daysActive}мқј / нҸүк·  ${gr(data.avgRoundsPerDay + ' rounds/day')}`);
  log('');
  if (data.nextMilestone != null) {
    log(yl(`  рҹҺҜ лӢӨмқҢ л§ҲмқјмҠӨнҶӨ: R${data.nextMilestone} (${data.roundsToNextMilestone} лқјмҡҙл“ң лӮЁмқҢ)`));
  } else {
    log(gr(`  рҹҺү лӘЁл“  л§ҲмқјмҠӨнҶӨ лӢ¬м„ұ (500+)`));
  }
  log('');
  log(`  мөңк·ј 10 tags:`);
  data.latestTags.forEach(t => log(`    вҖў v${t.version} (${t.date})`));
}

// 1.9.208: н”Ңлһ«нҸј/API м ңм•Ҫ мӮ¬м „ мІҙнҒ¬ (мӮ¬мҡ©мһҗ лӘ…мӢң)
//   "мӮ¬мҡ©мһҗмқҳ лӘ…л №мқ„ л°ӣмңјл©ҙ, кі л Өн•ҙм•јн•ҳлҠ” л¶Җл¶„мқ„ лЁјм Җ нҷ•мқён•ҳкі  м§„н–үн•ҳкІҢ н•ҳл©ҙ м–ҙл–Ём§Җ"
//   "нҠ№м • н”Ңлһ«нҸјмқҳ API ... нҳём¶ңмҶҚлҸ„к°Җ мҙҲлӢ№ 5нҡҢ мқҙн•ҳлЎңл§Ң н•ҙм•јн•ңлӢӨлҠ” к·ңм •мқ„ лЁјм Җ нҷ•мқё"
//   .harness/platform-constraints.json м—җ н”Ңлһ«нҸјлі„ м ңм•Ҫ catalog м ҖмһҘ вҶ’ мҡ”мІӯ н…ҚмҠӨнҠё нӮӨмӣҢл“ң л§Өм№ӯ вҶ’ м Ғмҡ© к°ҖлҠҘн•ң м ңм•Ҫ ліҙкі 
//   кё°ліё catalog 6мў…: Stripe / OpenAI / Anthropic / GitHub / Discord / Twitter
function _platformConstraintsPath(root) { return path.join(root, '.harness', 'platform-constraints.json'); }
// 1.9.333 (UR-0025 мӢ¬мёө): _DEFAULT_PLATFORM_CONSTRAINTS вҶ’ lib/catalogs.js лЎң мқҙлҸҷ (мҲңмҲҳ лҚ°мқҙн„°, require мӮ¬мҡ©).
function _loadPlatformConstraints(root) {
  try {
    const fp = _platformConstraintsPath(root);
    if (!exists(fp)) return _DEFAULT_PLATFORM_CONSTRAINTS;
    const j = JSON.parse(read(fp));
    // user catalog мҷҖ default merge вҖ” user override мҡ°м„ 
    const merged = { ...JSON.parse(JSON.stringify(_DEFAULT_PLATFORM_CONSTRAINTS)) };
    if (j.platforms) {
      for (const k of Object.keys(j.platforms)) {
        merged.platforms[k] = j.platforms[k];
      }
    }
    return merged;
  } catch { return _DEFAULT_PLATFORM_CONSTRAINTS; }
}
function _writePlatformConstraints(root, catalog) {
  try {
    mkdirp(path.join(root, '.harness'));
    writeUtf8(_platformConstraintsPath(root), JSON.stringify({ ...catalog, updatedAt: new Date().toISOString() }, null, 2));
    return true;
  } catch { return false; }
}
// мӮ¬мҡ©мһҗ мҡ”мІӯ н…ҚмҠӨнҠём—җм„ң н”Ңлһ«нҸј alias л§Өм№ӯ вҶ’ м Ғмҡ© м ңм•Ҫ лӘ©лЎқ л°ҳнҷҳ
// 1.9.333 (UR-0025 мӢ¬мёө): л§Өм№ӯ лЎңм§ҒмқҖ мҲңмҲҳ _matchConstraints(catalog, text) (lib/pure-utils) вҖ” fs(load)лҠ” м—¬кё°м„ң мЈјмһ….
function _checkRequestConstraints(root, text) {
  return _matchConstraints(_loadPlatformConstraints(root), text);
}

// 1.9.209: pre-wake sub-agent audit (мӮ¬мҡ©мһҗ лӘ…мӢң)
//   "л©”мқё м—җмқҙм „нҠёк°Җ мҠ¬лҰҪм „м—җ м„ңлёҢм—җмқҙм „нҠёлҘј нҳём¶ңн•ҙм„ң лҜёл№„лҗң л¶Җл¶„мқҙ мһҲлҠ”м§Җ, м¶©лҸҢлӮҳлҠ” л¶Җл¶„мқҙ мһҲлҠ”м§Җ,
//    мқҙм „м—җ лҲ„лқҪлҗң мһ‘м—…мқҙ мһҲлҠ”м§Җ л“ұл“ұ м—¬лҹ¬л¶Җл¶„мқ„ нғҗмғүн•ҳл©ҙм„ң н•„мҡ”н•ң лӮҙмҡ©мқ„ м •лҰ¬н•ҳкі 
//    л©”мқё м—җмқҙм „нҠёк°Җ к№Ём–ҙлӮ¬мқ„л•Ң, м„ңлёҢм—җмқҙм „нҠёк°Җ м •лҰ¬н•ң лӮҙмҡ©мқ„ нҷ•мқён•ҙліҙкұ°лӮҳ н•ҳлҠ” кё°лҠҘ"
//   .harness/pre-wake-report.json м—җ sleep м „ audit кІ°кіј лҲ„м Ғ (мөңк·ј 10к°ң мң м§Җ) вҶ’
//   лӢӨмқҢ handoff м—җм„ң мһҗлҸҷ л…ём¶ң вҶ’ к№Ём–ҙлӮЁ м§Ғнӣ„ л©”мқё м—җмқҙм „нҠёк°Җ кІҖнҶ  к°ҖлҠҘ
//   audit мҳҒм—ӯ: лҜёлӢө мҡ”мІӯ / 24h+ л¬ҙм§„мІҷ task / drift мӢ нҳё / feature_graph м¶©лҸҢ / н”Ңлһ«нҸј м ңм•Ҫ лҲ„лқҪ
function _preWakeReportPath(root) { return path.join(root, '.harness', 'pre-wake-report.json'); }
function _loadPreWakeReport(root) {
  try {
    const fp = _preWakeReportPath(root);
    if (!exists(fp)) return { reports: [] };
    const j = JSON.parse(read(fp));
    return { reports: Array.isArray(j.reports) ? j.reports : [] };
  } catch { return { reports: [] }; }
}
function _writePreWakeReport(root, reports) {
  try {
    mkdirp(path.join(root, '.harness'));
    writeUtf8(_preWakeReportPath(root), JSON.stringify({ reports, updatedAt: new Date().toISOString() }, null, 2));
    return true;
  } catch { return false; }
}
// мӢӨм ң audit мӢӨн–ү вҖ” sub-agent м—ӯн•  (лӢЁмқј н”„лЎңм„ёмҠӨм—җм„ң syncлЎң лӢӨм–‘н•ң мӢ нҳё мҲҳм§‘)
function _runPreWakeAudit(root) {
  const audit = {
    auditedAt: new Date().toISOString(),
    auditVersion: VERSION,
    findings: { critical: [], warning: [], info: [] }
  };
  // 1) лҜёлӢө мӮ¬мҡ©мһҗ мҡ”мІӯ (1.9.207)
  try {
    const reqAudit = _auditUserRequests(root);
    if (reqAudit.missing && reqAudit.missing.length > 0) {
      audit.findings.critical.push({
        kind: 'missing-user-requests',
        count: reqAudit.missing.length,
        detail: `${reqAudit.missing.length}кұҙ мӮ¬мҡ©мһҗ мҡ”мІӯмқҙ task-log/plan/decisions м—җ л§Өм№ӯ м•Ҳ лҗЁ`,
        items: reqAudit.missing.slice(0, 5).map(r => ({ id: r.id, text: r.text.slice(0, 80) }))
      });
    }
    if (reqAudit.stale && reqAudit.stale.length > 0) {
      audit.findings.warning.push({
        kind: 'stale-user-requests',
        count: reqAudit.stale.length,
        detail: `${reqAudit.stale.length}кұҙ мӮ¬мҡ©мһҗ мҡ”мІӯмқҙ 7мқј+ open мғҒнғң`
      });
    }
  } catch (e) { audit.findings.info.push({ kind: 'audit-error', area: 'user-requests', error: String(e.message || e) }); }

  // 2) 24h+ л¬ҙм§„мІҷ task вҖ” progress-tracker кІҖмӮ¬
  try {
    const ptPath = path.join(root, '.harness', 'progress-tracker.md');
    if (exists(ptPath)) {
      const content = read(ptPath);
      const stat = fs.statSync(ptPath);
      const ageMin = Math.floor((Date.now() - stat.mtimeMs) / 60000);
      // in-progress нғңк·ёк°Җ мһҲлҠ”лҚ° 24h+ к°ұмӢ  м—ҶмқҢ
      const inProgressCount = (content.match(/status:\s*in-progress/gi) || []).length;
      if (inProgressCount > 0 && ageMin > 24 * 60) {
        audit.findings.warning.push({
          kind: 'stale-in-progress',
          count: inProgressCount,
          detail: `${inProgressCount}кұҙ in-progress task, ${Math.floor(ageMin/60)}h к°ұмӢ  м—ҶмқҢ`,
          ageMin
        });
      }
    }
  } catch {}

  // 3) drift мӢ нҳё вҖ” session-handoff/progress-tracker stale кІҖмӮ¬
  try {
    const handoffPath = path.join(root, '.harness', 'session-handoff.md');
    if (exists(handoffPath)) {
      const stat = fs.statSync(handoffPath);
      const ageDay = (Date.now() - stat.mtimeMs) / 86400000;
      if (ageDay > 5) {
        audit.findings.warning.push({
          kind: 'drift-handoff-stale',
          ageDay: Math.round(ageDay * 10) / 10,
          detail: `session-handoff.md ${ageDay.toFixed(1)}мқј stale вҖ” drift мң„н—ҳ`
        });
      }
    }
  } catch {}

  // 4) лӢӨмқҢ лқјмҡҙл“ң plan м Ғмҡ© к°ҖлҠҘ м—¬л¶Җ (1.9.203)
  try {
    const plan = _loadAutoResumePlan(root);
    if (!plan) {
      audit.findings.info.push({ kind: 'no-auto-resume-plan', detail: 'auto-resume-plan.json м—ҶмқҢ вҖ” лӢӨмқҢ лқјмҡҙл“ң м§„мһ… мӢң manual context' });
    } else if (plan.ageMin > 12 * 60) {
      audit.findings.warning.push({ kind: 'auto-resume-plan-stale', detail: `plan ${plan.ageMin}л¶„ м „ мһ‘м„ұ вҖ” outdated к°ҖлҠҘ` });
    } else {
      audit.findings.info.push({ kind: 'auto-resume-plan-ready', detail: `nextRoundVersion=${plan.nextRoundVersion}, focus=${(plan.focus||'').slice(0,50)}` });
    }
  } catch {}

  // 5) Active wakeup мғҒнғң (1.9.205)
  try {
    const wkStat = _analyzeWakeupStatus(root);
    if (wkStat.hasWakeup && wkStat.kind === 'missed') {
      audit.findings.critical.push({
        kind: 'wakeup-missed',
        deltaMin: wkStat.deltaMin,
        detail: `wakeup ${wkStat.deltaMin}л¶„ м§ҖлӮЁ вҖ” лӢӨмқҢ лқјмҡҙл“ң м§„мһ… лҠҰмқҢ`
      });
    }
  } catch {}

  // 6) next-action queue мһ”м—¬ (1.9.201)
  try {
    const q = _loadNextActionQueue(root);
    if (q && q.pending && q.pending.length > 0) {
      audit.findings.info.push({
        kind: 'next-action-pending',
        count: q.pending.length,
        detail: `${q.pending.length}кұҙ next-action лҢҖкё° вҖ” leerness next-action take лЎң мҰүмӢң мІҳлҰ¬`
      });
    }
  } catch {}

  // 7) нҶөн•© мҡ”м•Ҫ
  audit.summary = {
    criticalCount: audit.findings.critical.length,
    warningCount: audit.findings.warning.length,
    infoCount: audit.findings.info.length,
    needsAttention: audit.findings.critical.length > 0 || audit.findings.warning.length >= 2
  };
  return audit;
}
function _saveAndAppendPreWakeReport(root, audit) {
  const state = _loadPreWakeReport(root);
  state.reports.push(audit);
  // мөңк·ј 10к°ңл§Ң мң м§Җ
  if (state.reports.length > 10) state.reports = state.reports.slice(-10);
  _writePreWakeReport(root, state.reports);
  return audit;
}

// 1.9.220: л№„м •мғҒ мў…лЈҢ к°җм§Җ + мһҗмңЁ мһ¬к°ң (мӮ¬мҡ©мһҗ лӘ…мӢң)
//   "м Ҳм „лӘЁл“ң/мӢңмҠӨн…ңмў…лЈҢ/AIм—җмқҙм „нҠё м„ём…ҳмў…лЈҢлЎң л№„м •мғҒ мў…лЈҢлҗң нӣ„ мһ¬мӢӨн–ү мӢң мӨ‘лӢЁм§Җм җ/лҲ„лқҪмһ‘м—… к°җм§Җ"
//   5мӢ нҳё мў…н•© л¶„м„қ:
//     1) last-handoff gap > 60min (1.9.199, 25min interval кё°лҢҖ лҢҖл№„ 2.4л°°+)
//     2) wakeup miss (active-wakeups pending вҶ’ 30min+ м§ҖлӮЁ, 1.9.205)
//     3) in-progress task 24h+ к°ұмӢ  м—ҶмқҢ (stale, progress-tracker mtime)
//     4) auto-resume-plan мЎҙмһ¬ + ageMin > 60min (1.9.203, мӮ¬мҡ© м•Ҳ лҗЁ)
//     5) release/X.X.X branch мһҲмқҢ + main лҜёлЁём§Җ (release sync-main лҲ„лқҪ)
//   кІ°кіј: { abnormalShutdown: true/false, signals: [...], severity, resumeGuide }
function _detectAbnormalShutdown(root) {
  const result = {
    detectedAt: new Date().toISOString(),
    signals: [],
    severity: 'none',
    abnormalShutdown: false,
    resumeGuide: []
  };
  const now = Date.now();

  // 1) last-handoff gap > 60min (м •мғҒ 25min interval лҢҖл№„)
  try {
    const lhFp = path.join(root, '.harness', 'last-handoff.json');
    if (exists(lhFp)) {
      const j = JSON.parse(read(lhFp));
      const last = j.lastAt || (j.history && j.history.length > 0 ? j.history[j.history.length - 1] : null);
      if (last) {
        const lastMs = new Date(last).getTime();
        const gapMin = Math.floor((now - lastMs) / 60000);
        if (gapMin > 60) {
          result.signals.push({
            kind: 'last-handoff-stale',
            gapMin,
            detail: `last handoff ${gapMin}л¶„ м „ (м •мғҒ 25min к°„кІ© лҢҖл№„ ${Math.round(gapMin/25)}x мҙҲкіј) вҖ” м Ҳм „/мў…лЈҢ мқҳмӢ¬`,
            severity: gapMin > 240 ? 'high' : 'medium'
          });
        }
      }
    }
  } catch {}

  // 2) wakeup miss (active-wakeups pending вҶ’ 30min+ м§ҖлӮЁ)
  try {
    const wkStat = _analyzeWakeupStatus(root);
    if (wkStat.hasWakeup && wkStat.deltaMin > 30 && wkStat.kind === 'missed') {
      result.signals.push({
        kind: 'wakeup-missed',
        gapMin: wkStat.deltaMin,
        detail: `wakeup ${wkStat.deltaMin}л¶„ м§ҖлӮЁ (status=pending) вҖ” мһҗлҸҷ мһ¬к°ң мӢӨнҢЁ`,
        severity: wkStat.deltaMin > 120 ? 'high' : 'medium'
      });
    }
  } catch {}

  // 3) in-progress task 24h+ stale (progress-tracker mtime + нҷңм„ұ task м№ҙмҡҙнҠё)
  try {
    const ptPath = path.join(root, '.harness', 'progress-tracker.md');
    if (exists(ptPath)) {
      const stat = fs.statSync(ptPath);
      const ageMin = Math.floor((now - stat.mtimeMs) / 60000);
      const content = read(ptPath);
      const inProgress = (content.match(/^\|\s*T-\d{4,}\s*\|\s*in-progress\s*\|/gm) || []).length;
      if (inProgress > 0 && ageMin > 24 * 60) {
        result.signals.push({
          kind: 'in-progress-stale',
          inProgressCount: inProgress,
          ageMin,
          detail: `${inProgress}кұҙ in-progress task, progress-tracker ${Math.floor(ageMin/60)}h к°ұмӢ  м—ҶмқҢ`,
          severity: 'high'
        });
      }
    }
  } catch {}

  // 4) auto-resume-plan мЎҙмһ¬ + ageMin > 60min (мӮ¬мҡ© м•Ҳ лҗЁ)
  try {
    const plan = _loadAutoResumePlan(root);
    if (plan && plan.ageMin > 60) {
      result.signals.push({
        kind: 'auto-resume-plan-unused',
        ageMin: plan.ageMin,
        nextRound: plan.nextRoundVersion,
        detail: `auto-resume-plan ${plan.ageMin}л¶„ м „ мһ‘м„ұ (${plan.nextRoundVersion}) вҖ” мӮ¬мҡ© м•Ҳ лҗЁ`,
        severity: plan.ageMin > 240 ? 'medium' : 'low'
      });
    }
  } catch {}

  // 5) release/X.X.X branch мһҲмқҢ + main лҜёлЁём§Җ (git мғҒнғң)
  try {
    const r = cp.spawnSync('git', ['branch', '--list', 'release/*'], { cwd: root, encoding: 'utf8', timeout: 3000 });
    if (r.status === 0) {
      const branches = (r.stdout || '').split('\n').map(s => s.trim().replace(/^\*?\s*/, '')).filter(b => b.startsWith('release/'));
      if (branches.length >= 2) {  // 2к°ң мқҙмғҒмқҙл©ҙ лҲ„лқҪ к°ҖлҠҘм„ұ
        result.signals.push({
          kind: 'release-branch-pending',
          count: branches.length,
          recent: branches.slice(-3),
          detail: `${branches.length}кұҙ release/* branch (sync-main лҲ„лқҪ к°ҖлҠҘ)`,
          severity: 'low'
        });
      }
    }
  } catch {}

  // мў…н•© нҢҗлӢЁ
  const high = result.signals.filter(s => s.severity === 'high').length;
  const medium = result.signals.filter(s => s.severity === 'medium').length;
  if (high > 0) { result.severity = 'high'; result.abnormalShutdown = true; }
  else if (medium > 0) { result.severity = 'medium'; result.abnormalShutdown = true; }
  else if (result.signals.length > 0) result.severity = 'low';

  // мһ¬к°ң к°Җмқҙл“ң
  if (result.abnormalShutdown) {
    result.resumeGuide.push('1. leerness handoff . вҖ” нҳ„мһ¬ мғҒнғң мў…н•© нҷ•мқё');
    if (result.signals.some(s => s.kind === 'auto-resume-plan-unused')) {
      result.resumeGuide.push('2. leerness resume вҖ” м ҖмһҘлҗң auto-resume-plan м Ғмҡ© (1.9.203)');
    }
    if (result.signals.some(s => s.kind === 'in-progress-stale')) {
      result.resumeGuide.push('3. leerness task list --status in-progress вҖ” stale task кІҖнҶ  (drop or мһ¬к°ң)');
    }
    if (result.signals.some(s => s.kind === 'wakeup-missed')) {
      result.resumeGuide.push('4. ScheduleWakeup мһ¬л“ұлЎқ (мӮ¬мҡ©мһҗ нҠёлҰ¬кұ° лҳҗлҠ” R-0001 лЈ°)');
    }
    if (result.signals.some(s => s.kind === 'release-branch-pending')) {
      result.resumeGuide.push('5. git branch -aлЎң release/* нҷ•мқё + leerness release sync-main мһ¬мӢӨн–ү');
    }
    result.resumeGuide.push('6. leerness pre-wake-audit вҖ” лҲ„лқҪ мһ‘м—… / м¶©лҸҢ мў…н•© м җкІҖ');
    result.resumeGuide.push('7. leerness requests audit вҖ” лҜёлӢө мӮ¬мҡ©мһҗ мҡ”мІӯ нҷ•мқё');
  } else {
    result.resumeGuide.push('м •мғҒ мҡҙмҳҒ мӨ‘ вҖ” л№„м •мғҒ мў…лЈҢ мӢ нҳё м—ҶмқҢ');
  }
  return result;
}

// 1.9.210: adaptive wakeup interval (мӮ¬мҡ©мһҗ лӘ…мӢң)
//   "wakeup 30л¶„л“ұ кёҙ мӢңк°„мқҙ н•„мҡ”м—ҶлӢӨл©ҙ к°„кІ©мқ„ нғҖмқҙнҠён•ҳкІҢ мһҗлҸҷмңјлЎң мЎ°м Ҳн•ҳлҸ„лЎқ"
//   мӮ¬мҡ©мһҗ нҷңлҸҷлҹү кё°л°ҳ к¶ҢмһҘ interval кі„мӮ° вҶ’ ScheduleWakeup мӢң мһҗлҸҷ м Ғмҡ© (R-0001 лЈ° мҷё лҸҷм Ғ ліҙм •)
//   .harness/wakeup-history.json м—җ fire мқҙл Ҙ лҲ„м Ғ вҶ’ мөңк·ј Nк°ң мӮ¬мқҙ нҸүк·  user-trigger gap л¶„м„қ
//   opt-out: LEERNESS_FIXED_INTERVAL=1 (env) лҳҗлҠ” leerness wakeup-interval set <secs>
function _wakeupHistoryPath(root) { return path.join(root, '.harness', 'wakeup-history.json'); }
function _loadWakeupHistory(root) {
  try {
    const fp = _wakeupHistoryPath(root);
    if (!exists(fp)) return { fires: [], override: null };
    const j = JSON.parse(read(fp));
    return { fires: Array.isArray(j.fires) ? j.fires : [], override: j.override || null };
  } catch { return { fires: [], override: null }; }
}
function _writeWakeupHistory(root, state) {
  try {
    mkdirp(path.join(root, '.harness'));
    writeUtf8(_wakeupHistoryPath(root), JSON.stringify({ ...state, updatedAt: new Date().toISOString() }, null, 2));
    return true;
  } catch { return false; }
}
function _recordWakeupFire(root, kind) {
  // kind: 'auto' (scheduled), 'user-trigger' (мӮ¬мҡ©мһҗ лӘ…мӢң лӢӨмқҢлқјмҡҙл“ң), 'wakeup-miss'
  const state = _loadWakeupHistory(root);
  state.fires.push({ at: new Date().toISOString(), kind: kind || 'auto' });
  // мөңк·ј 50к°ңл§Ң мң м§Җ
  if (state.fires.length > 50) state.fires = state.fires.slice(-50);
  _writeWakeupHistory(root, state);
  return state;
}
// к¶ҢмһҘ interval кі„мӮ° (sec)
//   user-trigger л№ҲлҸ„ + pre-wake critical + мөңк·ј нҸүк·  gap кё°л°ҳ
//   лІ”мң„: 600 (10min) ~ 2700 (45min)
function _computeAdaptiveInterval(root) {
  const DEFAULT = 1500; // 25min
  const MIN = 600;      // 10min
  const MAX = 2700;     // 45min

  // 1) opt-out вҖ” env or override
  if (process.env.LEERNESS_FIXED_INTERVAL && process.env.LEERNESS_FIXED_INTERVAL !== '0') {
    const fixed = Number(process.env.LEERNESS_FIXED_INTERVAL);
    if (!isNaN(fixed) && fixed >= 60) return { interval: fixed, reason: 'env LEERNESS_FIXED_INTERVAL', adaptive: false };
    return { interval: DEFAULT, reason: 'env override (default)', adaptive: false };
  }
  const state = _loadWakeupHistory(root);
  if (state.override && Number(state.override) >= 60) {
    return { interval: Number(state.override), reason: 'wakeup-history.json override', adaptive: false };
  }

  // 2) нҷңлҸҷлҹү л¶„м„қ вҖ” мөңк·ј 2мӢңк°„ user-trigger мҲҳ
  const now = Date.now();
  const recent = state.fires.filter(f => (now - new Date(f.at).getTime()) < 2 * 60 * 60 * 1000);
  const userTriggers = recent.filter(f => f.kind === 'user-trigger').length;
  const totalRecent = recent.length;

  // 3) нҸүк·  user-trigger gap (л¶„)
  const userFires = state.fires.filter(f => f.kind === 'user-trigger').slice(-5);
  let avgGapMin = null;
  if (userFires.length >= 2) {
    let totalGap = 0;
    for (let i = 1; i < userFires.length; i++) {
      totalGap += new Date(userFires[i].at).getTime() - new Date(userFires[i - 1].at).getTime();
    }
    avgGapMin = Math.floor((totalGap / (userFires.length - 1)) / 60000);
  }

  // 4) pre-wake critical signal (1.9.209)
  let criticalSignal = false;
  try {
    const pw = _loadPreWakeReport(root);
    if (pw.reports.length > 0) {
      const latest = pw.reports[pw.reports.length - 1];
      if (latest.summary && latest.summary.criticalCount > 0) criticalSignal = true;
    }
  } catch {}

  // 5) кі„мӮ°
  let interval = DEFAULT;
  const reasons = [];
  if (userTriggers >= 3) {
    interval = Math.max(MIN, 900); // 15min вҖ” нҷңл°ңн•ң мӮ¬мҡ©мһҗ нҷңлҸҷ
    reasons.push(`user-trigger ${userTriggers}нҡҢ (2h)`);
  } else if (userTriggers === 0 && totalRecent <= 1) {
    interval = Math.min(MAX, 2100); // 35min вҖ” н•ңмӮ°
    reasons.push('user-trigger м—ҶмқҢ (2h)');
  } else {
    interval = DEFAULT;
    reasons.push('default 25min');
  }
  // avgGap кё°л°ҳ лҜём„ё мЎ°м •
  if (avgGapMin !== null && avgGapMin < 20) {
    interval = Math.max(MIN, Math.min(interval, avgGapMin * 60));
    reasons.push(`avg user gap ${avgGapMin}min`);
  }
  // critical мӢ нҳё мӢң м§§кІҢ
  if (criticalSignal && interval > 1200) {
    interval = 1200; // 20min
    reasons.push('pre-wake critical detected');
  }

  return {
    interval,
    reason: reasons.join(' + '),
    adaptive: true,
    stats: {
      recentTotal: totalRecent,
      userTriggers,
      avgUserGapMin: avgGapMin,
      criticalSignal
    }
  };
}

// 1.9.211: .harness вҶ’ .leerness rename + migration + AI м°ёмЎ° к°Җмқҙл“ң (мӮ¬мҡ©мһҗ лӘ…мӢң)
//   "leernessм„Өм№ҳмӢң мғқм„ұлҗҳлҠ” .harnessлҘј .leernessмңјлЎң ліҖкІҪн•  мҲҳ мһҲмқ„к№Ң / кё°мЎҙ лІ„м „м—җм„ңлҸ„ л§Ҳмқҙк·ёл Ҳмқҙм…ҳмӢң AIк°Җ м°ёмЎ°н•  мҲҳ мһҲкё°лҸ„н•ҳл©ҙ м–ҙл–Ёк№Ң"
//   м ‘к·ј л°©мӢқ: opt-in л§Ҳмқҙк·ёл Ҳмқҙм…ҳ (breaking change мөңмҶҢнҷ”)
//   - default: .harness мң м§Җ (226+ path reference м•Ҳм •)
//   - LEERNESS_WORKSPACE_DIR env лҳҗлҠ” .leerness/MARKER мЎҙмһ¬ мӢң .leerness мӮ¬мҡ©
//   - leerness migrate-workspace-dir CLI: .harness вҶ’ .leerness copy + AI reference guide мғқм„ұ
//   - AI м°ёмЎ° к°Җмқҙл“ң: WHERE_TO_FIND.md (л””л үнҶ лҰ¬ кө¬мЎ° + нҢҢмқјлі„ м—ӯн•  + л§Ҳмқҙк·ёл Ҳмқҙм…ҳ history)
function _workspaceDirName(root) {
  // 1) env override
  if (process.env.LEERNESS_WORKSPACE_DIR) {
    const v = process.env.LEERNESS_WORKSPACE_DIR.trim();
    if (v) return v;
  }
  // 2) .leerness л§Ҳмқҙк·ёл Ҳмқҙм…ҳ л§Ҳм»Ө мЎҙмһ¬ мӢң .leerness мҡ°м„ 
  try {
    if (root && exists(path.join(root, '.leerness', 'MIGRATED_FROM_HARNESS'))) {
      return '.leerness';
    }
  } catch {}
  // 3) default
  return '.harness';
}
function _workspaceDirAbs(root) {
  return path.join(root, _workspaceDirName(root));
}
// .harness вҶ’ .leerness л§Ҳмқҙк·ёл Ҳмқҙм…ҳ (copy + reference guide мғқм„ұ)
function _migrateWorkspaceDir(root, opts = {}) {
  const dryRun = opts.dryRun === true;
  const srcDir = path.join(root, '.harness');
  const dstDir = path.join(root, '.leerness');
  const report = {
    at: new Date().toISOString(),
    version: VERSION,
    src: srcDir,
    dst: dstDir,
    srcExists: exists(srcDir),
    dstExists: exists(dstDir),
    copiedFiles: [],
    skippedFiles: [],
    errors: [],
    dryRun
  };
  if (!report.srcExists) {
    report.errors.push('source .harness not found');
    return report;
  }
  if (!dryRun) {
    mkdirp(dstDir);
  }
  // мһ¬к·Җ copy н—¬нҚј
  function copyRec(rel) {
    const srcAbs = path.join(srcDir, rel);
    const dstAbs = path.join(dstDir, rel);
    let stat;
    try { stat = fs.statSync(srcAbs); } catch (e) { report.errors.push(`stat ${rel}: ${e.message}`); return; }
    if (stat.isDirectory()) {
      if (!dryRun) mkdirp(dstAbs);
      let entries;
      try { entries = fs.readdirSync(srcAbs); } catch (e) { report.errors.push(`readdir ${rel}: ${e.message}`); return; }
      for (const e of entries) copyRec(path.join(rel, e));
    } else if (stat.isFile()) {
      // кё°мЎҙ dst нҢҢмқјмқҙ мһҲкі  мҡ°лҰ¬к°Җ forceк°Җ м•„лӢҲл©ҙ skip
      if (exists(dstAbs) && !opts.force) {
        report.skippedFiles.push(rel);
        return;
      }
      if (!dryRun) {
        try {
          fs.copyFileSync(srcAbs, dstAbs);
          report.copiedFiles.push(rel);
        } catch (e) {
          report.errors.push(`copy ${rel}: ${e.message}`);
        }
      } else {
        report.copiedFiles.push(rel);
      }
    }
  }
  copyRec('');
  // л§Ҳмқҙк·ёл Ҳмқҙм…ҳ л§Ҳм»Ө + AI м°ёмЎ° к°Җмқҙл“ң мһ‘м„ұ
  if (!dryRun) {
    const marker = `Migrated from .harness at ${report.at} by leerness ${VERSION}\n`;
    try { writeUtf8(path.join(dstDir, 'MIGRATED_FROM_HARNESS'), marker); } catch (e) { report.errors.push(`marker: ${e.message}`); }
    const guide = _buildWorkspaceReferenceGuide(root, '.leerness');
    try { writeUtf8(path.join(dstDir, 'WHERE_TO_FIND.md'), guide); } catch (e) { report.errors.push(`guide: ${e.message}`); }
    // .harness м—җлҸ„ redirect м•ҲлӮҙ м¶”к°Җ (AIк°Җ .harness лЁјм Җ лҙҗлҸ„ .leerness лЎң к°ҖкІҢ)
    try {
      const redirect = `# .harness вҶ’ .leerness migration (${report.at})\n\n` +
        `мқҙ мӣҢнҒ¬мҠӨнҺҳмқҙмҠӨлҠ” \`.harness\` вҶ’ \`.leerness\` лЎң л§Ҳмқҙк·ёл Ҳмқҙм…ҳлҗҳм—ҲмҠөлӢҲлӢӨ (leerness ${VERSION}).\n\n` +
        `**AI м—җмқҙм „нҠёлҠ” ${'.leerness/'} л””л үнҶ лҰ¬лҘј мҡ°м„  м°ёмЎ°н•ҳмӢӯмӢңмҳӨ.**\n\n` +
        `- мӢ к·ң л©”нғҖнҢҢмқј мң„м№ҳ: \`.leerness/\`\n` +
        `- м°ёмЎ° к°Җмқҙл“ң: \`.leerness/WHERE_TO_FIND.md\`\n` +
        `- л§Ҳмқҙк·ёл Ҳмқҙм…ҳ л§Ҳм»Ө: \`.leerness/MIGRATED_FROM_HARNESS\`\n\n` +
        `\`.harness/\` лҠ” backward compatibility лҘј мң„н•ҙ ліҙмЎҙлҗ©лӢҲлӢӨ (read-only к¶ҢмһҘ).\n`;
      writeUtf8(path.join(srcDir, 'MIGRATED_TO_LEERNESS.md'), redirect);
    } catch (e) { report.errors.push(`redirect: ${e.message}`); }
  }
  return report;
}
// AI м°ёмЎ° к°Җмқҙл“ң л№ҢлҚ” вҖ” мӣҢнҒ¬мҠӨнҺҳмқҙмҠӨ л””л үнҶ лҰ¬ кө¬мЎ° + нҢҢмқјлі„ м—ӯн•  л§Өн•‘
// 1.9.377 (UR-0025): мҲңмҲҳ мҪ”м–ҙ _renderWorkspaceReferenceGuide (lib/pure-utils) + м–ҮмқҖ лһҳнҚј (root лҜёмӮ¬мҡ©, version/timestamp мЈјмһ…).
function _buildWorkspaceReferenceGuide(root, dirName) {
  return _renderWorkspaceReferenceGuide(dirName, VERSION, new Date().toISOString());
}

// 1.9.213: intent inference + scope expansion кІҢмқҙнҠё (мӮ¬мҡ©мһҗ лӘ…мӢң)
//   "мӮ¬мҡ©мһҗк°Җ л§җн•ң лӮҙмҡ©л§Ң мҲҳм •н•ҙм•јн•ҳлҠ” кІҪмҡ°лҸ„ мһҲм§Җл§Ң, кҙҖл ЁмһҲлҠ”кІғмқҙлӮҳ ліҙк°•н•ҳл©ҙ мўӢмқ„ л¶Җл¶„мқ„ нҢҢм•…н•ҳм—¬ м§„н–ү"
//   "кІҢмһ„ к°ңл°ңм—җм„ң л§ө+мәҗлҰӯн„°+кё°ліёкё°лҠҘ мҡ”мІӯ мӢң мқҳлҸ„ нҢҢм•…"
//   3мӣҗм№ҷ: (1) Always-Off Opt-In, (2) Dry-run кё°ліё (мӢӨн–ү X), (3) лӘ…мӢң vs м¶”лЎ  л¶„лҰ¬ лқјлІЁл§Ғ
//   .harness/domain-catalog.json мӮ¬мҡ©мһҗ нҺём§‘ к°ҖлҠҘ + default catalog 5мў… (game/web/api/cli/data)
function _domainCatalogPath(root) { return path.join(root, '.harness', 'domain-catalog.json'); }
// 1.9.333 нҢЁн„ҙ м Ғмҡ©: _DEFAULT_DOMAIN_CATALOG вҶ’ lib/catalogs.js лЎң мқҙлҸҷ (мҲңмҲҳ лҚ°мқҙн„°, require мӮ¬мҡ©).
function _loadDomainCatalog(root) {
  try {
    const fp = _domainCatalogPath(root);
    if (!exists(fp)) return _DEFAULT_DOMAIN_CATALOG;
    const j = JSON.parse(read(fp));
    // user catalog merge вҖ” user override мҡ°м„ 
    const merged = JSON.parse(JSON.stringify(_DEFAULT_DOMAIN_CATALOG));
    if (j.domains) {
      for (const k of Object.keys(j.domains)) merged.domains[k] = j.domains[k];
    }
    return merged;
  } catch { return _DEFAULT_DOMAIN_CATALOG; }
}
function _writeDomainCatalog(root, catalog) {
  try {
    mkdirp(path.join(root, '.harness'));
    writeUtf8(_domainCatalogPath(root), JSON.stringify({ ...catalog, updatedAt: new Date().toISOString() }, null, 2));
    return true;
  } catch { return false; }
}
// 1.9.325 (UR-0025): _classifyIntent вҶ’ lib/pure-utils.js лЎң мқҙлҸҷ (мҲңмҲҳ intent л¶„лҘҳ, require мӮ¬мҡ©).
function _detectDomain(text, root) {
  return _matchDomain(_loadDomainCatalog(root), text);
}
function _inferScopeExpansion(text, root) {
  const classify = _classifyIntent(text);
  const det = _detectDomain(text, root);
  const result = {
    text,
    intent: classify.intent,
    intentSignals: classify.signals,
    domain: det.domain,
    matchedAlias: det.alias,
    explicitMentions: [],
    expansionCandidates: [],
    mode: 'dry-run'  // н•ӯмғҒ dry-run вҖ” мӢӨн–ү X
  };
  if (!det.domain || !det.components) {
    result.note = 'лҸ„л©”мқё лҜёнғҗм§Җ вҖ” лӘ…мӢң мҡ”мІӯл§Ң м§„н–ү (нҷ•мһҘ нӣ„ліҙ м—ҶмқҢ)';
    return result;
  }
  // мӮ¬мҡ©мһҗ н…ҚмҠӨнҠём—җм„ң component key м§Ғм ‘ м–ёкёү м¶”м¶ң
  const lowerText = text.toLowerCase();
  for (const c of det.components) {
    const mentionPatterns = [c.key.toLowerCase(), ...(c.desc.split(/[\s/()]/).filter(w => w.length >= 2).map(w => w.toLowerCase()))];
    const mentioned = mentionPatterns.some(p => lowerText.includes(p));
    if (mentioned) {
      result.explicitMentions.push({ key: c.key, desc: c.desc, source: 'user-explicit' });
    } else {
      result.expansionCandidates.push({ key: c.key, desc: c.desc, source: 'ai-inference' });
    }
  }
  // intent === precise л©ҙ expansion л№„м–ҙмһҲкІҢ (мқҳлҸ„ ліҙнҳё)
  if (classify.intent === 'precise') {
    result.expansionCandidates = [];
    result.note = `intent: precise вҖ” лӘ…мӢң мҡ”мІӯл§Ң м§„н–ү, AI м¶”лЎ  нҷ•мһҘ л№„нҷңм„ұ (мӮ¬мҡ©мһҗ мқҳлҸ„ ліҙнҳё)`;
  } else if (classify.intent === 'broad') {
    result.note = `intent: broad вҖ” ${result.expansionCandidates.length} нҷ•мһҘ нӣ„ліҙ м ңмӢң (--expand-all лҳҗлҠ” --select N мңјлЎң лӘ…мӢң мҠ№мқё н•„мҡ”)`;
  } else {
    result.note = `intent: default вҖ” лӘ…мӢң ${result.explicitMentions.length}кұҙл§Ң мҡ°м„ , нҷ•мһҘ нӣ„ліҙ ${result.expansionCandidates.length}кұҙ кІҖнҶ мҡ©`;
  }
  return result;
}

// 1.9.203: мһҗлҸҷ лқјмҡҙл“ң plan м •лҰ¬ вҖ” мӮ¬мҡ©мһҗ лӘ…мӢң
//   "л°ұк·ёлқјмҡҙл“ңм—җ лӢӨмқҢ мһ‘м—…мқҙ мӢңмһ‘к°ҖлҠҘн•ң мҳҲмғҒ мӢңк°„ + мқјм–ҙлӮ¬мқ„л•Ң н•ҙм•јн•ҳлҠ” мқјмқ„ м •лҰ¬"
//   лқјмҡҙл“ң л§Ҳл¬ҙлҰ¬ мӢң .harness/auto-resume-plan.json мһҗлҸҷ м ҖмһҘ вҶ’ лӢӨмқҢ wakeup мӢң мҰүмӢң мӢӨн–ү к°ҖлҠҘ
//   plan кө¬мЎ°: { savedAt, nextRoundVersion, expectedFireAt, focus, contextSnapshot, nextActions }
function _autoResumePlanPath(root) { return path.join(root, '.harness', 'auto-resume-plan.json'); }
function _loadAutoResumePlan(root) {
  try {
    const fp = _autoResumePlanPath(root);
    if (!exists(fp)) return null;
    const j = JSON.parse(read(fp));
    if (!j.savedAt) return null;
    const ageMs = Date.now() - new Date(j.savedAt).getTime();
    const expiredMs = j.expectedFireAt ? Date.now() - new Date(j.expectedFireAt).getTime() : 0;
    return { ...j, ageMs, ageMin: Math.floor(ageMs / 60000), elapsedFromExpected: Math.floor(expiredMs / 60000) };
  } catch { return null; }
}
function _writeAutoResumePlan(root, plan) {
  try {
    mkdirp(path.join(root, '.harness'));
    const payload = { savedAt: new Date().toISOString(), ...plan };
    writeUtf8(_autoResumePlanPath(root), JSON.stringify(payload, null, 2));
    return true;
  } catch { return false; }
}
// нҳ„мһ¬ мӣҢнҒ¬мҠӨнҺҳмқҙмҠӨ мғҒнғңм—җм„ң лӢӨмқҢ лқјмҡҙл“ң plan мһҗлҸҷ мғқм„ұ (нҳ„мһ¬ task / matrix / handoff gap / next-action queue кІ°н•©)
function _buildAutoResumePlan(root, opts) {
  opts = opts || {};
  const intervalMin = opts.intervalMin || 25;  // R-0001 мҳҒкө¬ лЈ°
  const now = Date.now();
  const expectedFireAt = new Date(now + intervalMin * 60 * 1000).toISOString();
  // нҳ„мһ¬ in-progress task
  const rows = readProgressRows(root);
  const active = rows.find(r => r.status === 'in-progress' || r.status === '[м§„н–ү]');
  // нҳ„мһ¬ VERSION
  const currentVersion = VERSION;
  // next-action queue snapshot
  const queueState = _loadNextActionQueue(root);
  const queueTop = queueState.queue.length > 0 ? queueState.queue[queueState.queue.length - 1] : null;
  // memory surface counts
  const memorySurface = {
    tasksInProgress: rows.filter(r => r.status === 'in-progress').length,
    decisions: _loadDecisions(root).length,  // 1.9.339 (UR-0053): canonical лӢЁмқј м§„мӢӨмҶҢмҠӨ
    rulesActive: readRules(root).filter(r => r.status === 'active').length,
    lessons: _loadLessons(root).length
  };
  return {
    nextRoundVersion: opts.nextRoundVersion || `next after ${currentVersion}`,
    expectedFireAt,
    intervalMin,
    focus: opts.focus || (active ? `${active.id} вҖ” ${(active.request || '').slice(0, 80)}` : 'мӮ¬мҡ©мһҗ лӘ…мӢң лҢҖкё° лҳҗлҠ” 5м¶• л§ӨнҠёлҰӯмҠӨ ліҙк°•'),
    contextSnapshot: {
      currentVersion,
      activeTaskId: active ? active.id : null,
      activeTaskRequest: active ? (active.request || '').slice(0, 200) : null,
      memorySurface,
      r0001Rule: '25л¶„ к°„кІ© (мӮ¬мҡ©мһҗ лӘ…мӢң, R-0001)'
    },
    nextActions: (queueState.queue || []).slice(-3).map(a => ({ icon: a.icon, title: a.title, command: a.command || null })),
    note: opts.note || 'лӢӨмқҢ wakeup мӢң leerness resume лҳҗлҠ” leerness handoff мӢӨн–ү вҶ’ plan мһҗлҸҷ м Ғмҡ©'
  };
}

// 1.9.203: leerness resume мӢ к·ң CLI вҖ” auto-resume-plan мқҪкі  мҰүмӢң м§„н–үн•  мқј м•ҲлӮҙ
function resumeCmd(root) {
  root = absRoot(root);
  const plan = _loadAutoResumePlan(root);
  if (!plan) {
    log(`# leerness resume (1.9.203)`);
    log(`  (auto-resume-plan м—ҶмқҢ вҖ” мІ« лқјмҡҙл“ң)`);
    log(`  вҶ’ leerness handoff . лЎң мӢңмһ‘`);
    return;
  }
  if (has('--json')) { log(JSON.stringify(plan, null, 2)); return; }
  const isTty = process.stdout && process.stdout.isTTY;
  const cyan = s => isTty ? `\x1b[36m${s}\x1b[0m` : s;
  const grn = s => isTty ? `\x1b[32m${s}\x1b[0m` : s;
  const yel = s => isTty ? `\x1b[33m${s}\x1b[0m` : s;
  const dim = s => isTty ? `\x1b[2m${s}\x1b[0m` : s;
  log(cyan(`# рҹ”„ leerness resume (1.9.203 мһҗлҸҷ лқјмҡҙл“ң plan м Ғмҡ©)`));
  log('');
  log(`  рҹ“… plan м ҖмһҘ: ${_formatLocal(plan.savedAt)}  (${plan.ageMin}л¶„ м „)`);
  log(`  вҸ° мҳҲмғҒ fire: ${_formatLocal(plan.expectedFireAt)}` + (plan.elapsedFromExpected > 0 ? yel(`  (${plan.elapsedFromExpected}л¶„ м§Җм—°)`) : ' (м •мӢң)'));
  log(`  рҹҺҜ focus: ${plan.focus}`);
  log('');
  log(grn(`## лӢӨмқҢ лқјмҡҙл“ң: ${plan.nextRoundVersion}`));
  if (plan.contextSnapshot) {
    const c = plan.contextSnapshot;
    log(`  нҳ„мһ¬ лІ„м „: ${c.currentVersion}`);
    if (c.activeTaskId) log(`  нҷңм„ұ task: ${c.activeTaskId} вҖ” ${(c.activeTaskRequest || '').slice(0, 70)}`);
    const m = c.memorySurface || {};
    log(`  memory: T${m.tasksInProgress || 0}/D${m.decisions || 0}/R${m.rulesActive || 0}/L${m.lessons || 0}`);
    log(`  лЈ°: ${c.r0001Rule || '-'}`);
  }
  if (plan.nextActions && plan.nextActions.length > 0) {
    log('');
    log(grn(`## мӮ¬м „ м •лҰ¬лҗң next-actions (${plan.nextActions.length}кұҙ)`));
    for (const a of plan.nextActions) {
      log(`  ${a.icon || 'вҖў'} ${a.title}`);
      if (a.command) log(dim(`     \`${a.command}\``));
    }
    log('');
    log(dim(`  вҶ’ мҰүмӢң task м¶”к°Җ: leerness next-action take`));
  }
  log('');
  log(dim(plan.note || ''));
  log('');
  log(grn(`вң“ resume мӨҖл№„ мҷ„лЈҢ вҖ” к¶ҢмһҘ: leerness handoff . лҳҗлҠ” leerness next-action take`));
}

// 1.9.207: leerness requests <sub> вҖ” мӮ¬мҡ©мһҗ мҡ”мІӯ лҲ„лқҪ нҷ•мқё м Ҳм°Ё CLI (мӮ¬мҡ©мһҗ лӘ…мӢң)
//   audit  вҶ’ open мҡ”мІӯ мӨ‘ task-log/plan/decisions м—җ л§Өм№ӯ м•Ҳ лҗҳлҠ” н•ӯлӘ© ліҙкі  (лҲ„лқҪ нӣ„ліҙ)
//   add    вҶ’ мӮ¬мҡ©мһҗ мҡ”мІӯ мҲҳлҸҷ кё°лЎқ (мҳҲ: leerness requests add "API rate limit 5/s м Ғмҡ©")
//   list   вҶ’ лӘЁл“  мҡ”мІӯ м¶ңл Ҙ (--json мҳөм…ҳ)
//   complete <id> вҶ’ мҡ”мІӯ мҷ„лЈҢ н‘ңмӢң
//   drop <id>     вҶ’ мҡ”мІӯ л“ңлЎӯ н‘ңмӢң (мӮ¬мҡ©мһҗ лӘ…мӢң м·ЁмҶҢ)
function requestsCmd(root, sub, ...rest) {
  root = absRoot(root);
  const isTty = process.stdout && process.stdout.isTTY;
  const cyan = s => isTty ? `\x1b[36m${s}\x1b[0m` : s;
  const grn = s => isTty ? `\x1b[32m${s}\x1b[0m` : s;
  const yel = s => isTty ? `\x1b[33m${s}\x1b[0m` : s;
  const red = s => isTty ? `\x1b[31m${s}\x1b[0m` : s;
  const dim = s => isTty ? `\x1b[2m${s}\x1b[0m` : s;

  if (!sub || sub === 'help' || sub === '--help') {
    log(`# leerness requests (1.9.207) вҖ” мӮ¬мҡ©мһҗ мҡ”мІӯ лҲ„лқҪ нҷ•мқё м Ҳм°Ё`);
    log('');
    log(`  audit            вҶ’ лҲ„лқҪ нӣ„ліҙ + tracked + stale ліҙкі  (--json к°ҖлҠҘ)`);
    log(`  add "<text>"     вҶ’ мӮ¬мҡ©мһҗ мҡ”мІӯ мҲҳлҸҷ кё°лЎқ`);
    log(`  list             вҶ’ м „мІҙ мҡ”мІӯ м¶ңл Ҙ (--json к°ҖлҠҘ, --status open|completed|dropped)`);
    log(`  complete <id>    вҶ’ мҡ”мІӯ мҷ„лЈҢ н‘ңмӢң (мҳҲ: UR-0003)`);
    log(`  drop <id>        вҶ’ мҡ”мІӯ л“ңлЎӯ н‘ңмӢң`);
    log(`  auto-complete    вҶ’ "Round X.Y.Z вҖ” кө¬нҳ„ мҷ„лЈҢ" нҢЁн„ҙ мһҗлҸҷ к°җм§Җ (default: dry-run, --apply мӢң м Ғмҡ©) [1.9.223]`);
    return;
  }

  // 1.9.223: auto-complete вҖ” мһҗкё°-кё°лЎқлҗң "кө¬нҳ„ мҷ„лЈҢ" нҢЁн„ҙ мһҗлҸҷ м •лҰ¬ (default dry-run)
  if (sub === 'auto-complete') {
    const apply = has('--apply');
    const detected = _detectDeliveredRequests(root);
    if (has('--json')) {
      const result = { ...detected, applied: false, completedIds: [] };
      if (apply) {
        for (const c of detected.candidates) {
          const u = _updateUserRequest(root, c.id, { status: 'completed', autoCompletedAt: new Date().toISOString(), autoCompleteReason: 'delivered-pattern-1.9.223' });
          if (u) result.completedIds.push(c.id);
        }
        result.applied = true;
      }
      log(JSON.stringify(result, null, 2));
      return;
    }
    log(cyan(`# leerness requests auto-complete (1.9.223) вҖ” delivered pattern мһҗлҸҷ к°җм§Җ`));
    log('');
    log(`  нҳ„мһ¬ лІ„м „: ${detected.currentVersion} В· open ${detected.total} В· нӣ„ліҙ ${detected.candidates.length}кұҙ`);
    log('');
    if (detected.candidates.length === 0) {
      log(grn(`  вң“ delivered нҢЁн„ҙ нӣ„ліҙ м—ҶмқҢ вҖ” open мҡ”мІӯмқҖ лӘЁл‘җ мғҲлЎңмҡҙ мһ‘м—…`));
      return;
    }
    log(yel(`  рҹ“Ҙ delivered нҢЁн„ҙ нӣ„ліҙ ${detected.candidates.length}кұҙ:`));
    detected.candidates.forEach(c => {
      log(`    вҖў [${c.id}] v${c.claimedVersion} (${c.deliveredKeyword}) вҖ” ${c.text.slice(0, 80)}вҖҰ`);
    });
    log('');
    if (apply) {
      let ok = 0;
      for (const c of detected.candidates) {
        const u = _updateUserRequest(root, c.id, { status: 'completed', autoCompletedAt: new Date().toISOString(), autoCompleteReason: 'delivered-pattern-1.9.223' });
        if (u) ok++;
      }
      log(grn(`  вң“ мһҗлҸҷ мҷ„лЈҢ ${ok}/${detected.candidates.length}кұҙ`));
    } else {
      log(dim(`  вҶ’ м Ғмҡ©н•ҳл Өл©ҙ: leerness requests auto-complete --apply`));
      log(dim(`  вҶ’ м•Ҳм „ мӣҗм№ҷ: кё°ліё dry-run (ліҖкІҪ X), --apply лӘ…мӢң мӢңм—җл§Ң м Ғмҡ©`));
    }
    return;
  }

  if (sub === 'add') {
    // 1.9.416 (UR-0122): flag/кІҪлЎң break(кё°мЎҙ filter лҠ” кІҪлЎңнҳ• positional мқ„ text м—җ нқЎмҲҳ) + л№Ҳ мһ…л Ҙ кұ°л¶Җ
    const text = _parseAddTitle(rest, 0);
    if (!text) { failJson(has('--json'), 'empty_request', 'leerness requests add "<мҡ”мІӯ>" н•„мҡ” (л№Ҳ/кІҪлЎң-only кұ°л¶Җ)'); return process.exit(process.exitCode || 1); }
    const entry = _recordUserRequest(root, text);
    if (!entry) { console.error('failed to record'); process.exit(1); }
    if (has('--json')) { log(JSON.stringify(entry, null, 2)); return; }
    log(grn(`вң“ recorded ${entry.id}: ${entry.text}`));
    return;
  }

  if (sub === 'list') {
    const state = _loadUserRequests(root);
    const filterStatus = arg('--status', null);
    let list = state.requests;
    if (filterStatus) list = list.filter(r => r.status === filterStatus);
    if (has('--json')) { log(JSON.stringify({ total: state.requests.length, filtered: list.length, requests: list }, null, 2)); return; }
    log(cyan(`# leerness requests list (1.9.207)`));
    log(`  total ${state.requests.length}${filterStatus ? ` В· filter status=${filterStatus} вҶ’ ${list.length}` : ''}`);
    log('');
    if (list.length === 0) { log(dim('  (м—ҶмқҢ)')); return; }
    for (const r of list) {
      const statusIcon = r.status === 'completed' ? 'вң“' : (r.status === 'dropped' ? 'вң—' : (r.status === 'in-progress' ? 'в–¶' : 'в—Ҝ'));
      const recordedDay = (r.recordedAt || '').slice(0, 10);
      log(`  ${statusIcon} [${r.id}] ${dim(recordedDay)} ${r.text.slice(0, 100)}${r.text.length > 100 ? 'вҖҰ' : ''}`);
      if (r.linkedTaskIds && r.linkedTaskIds.length > 0) log(dim(`       linked tasks: ${r.linkedTaskIds.join(', ')}`));
    }
    return;
  }

  if (sub === 'complete') {
    const id = rest[0];
    if (!id) { console.error('Usage: leerness requests complete <id>'); process.exit(1); }
    const updated = _updateUserRequest(root, id, { status: 'completed' });
    if (!updated) { console.error(`request not found: ${id}`); process.exit(1); }
    if (has('--json')) { log(JSON.stringify(updated, null, 2)); return; }
    log(grn(`вң“ completed ${updated.id}`));
    return;
  }

  if (sub === 'drop') {
    const id = rest[0];
    if (!id) { console.error('Usage: leerness requests drop <id>'); process.exit(1); }
    const updated = _updateUserRequest(root, id, { status: 'dropped' });
    if (!updated) { console.error(`request not found: ${id}`); process.exit(1); }
    if (has('--json')) { log(JSON.stringify(updated, null, 2)); return; }
    log(yel(`вң“ dropped ${updated.id}`));  // 1.9.354 (UR-0072 мҷёл¶ҖлҰ¬л·°): м„ұкіө лҸҷмһ‘м—җ мӢӨнҢЁ м•„мқҙмҪҳ(вң—) лҢҖмӢ  вң“
    return;
  }

  if (sub === 'audit') {
    const audit = _auditUserRequests(root);
    if (has('--json')) { log(JSON.stringify(audit, null, 2)); return; }
    log(cyan(`# leerness requests audit (1.9.207) вҖ” мӮ¬мҡ©мһҗ мҡ”мІӯ лҲ„лқҪ нҷ•мқё м Ҳм°Ё`));
    log('');
    log(`  рҹ“Ҡ нҶөкі„: total ${audit.total} В· open ${audit.open} В· completed ${audit.completed} В· dropped ${audit.dropped}`);
    log('');
    if (audit.missing.length === 0) {
      log(grn(`  вң“ лҲ„лқҪ м—ҶмқҢ вҖ” open мҡ”мІӯ лӘЁл‘җ task-log/plan/decisions м—җ нқ”м Ғ мһҲмқҢ`));
    } else {
      log(red(`  вҡ  лҲ„лқҪ нӣ„ліҙ ${audit.missing.length}кұҙ (open мғҒнғңмқҙлӮҳ task/plan/decisions л§Өм№ӯ м—ҶмқҢ):`));
      for (const m of audit.missing) {
        log(`    вҖў [${m.id}] ${m.text.slice(0, 90)}${m.text.length > 90 ? 'вҖҰ' : ''}`);
        log(dim(`         ${m.recordedAt.slice(0, 10)} В· hits=${m.hits}/${m.words}`));
      }
      log('');
      log(dim(`  вҶ’ к¶ҢмһҘ: лҲ„лқҪ н•ӯлӘ©лі„ leerness task add "<мҡ”мІӯ>" лҳҗлҠ” leerness requests complete <id>`));
    }
    if (audit.tracked.length > 0) {
      log('');
      log(grn(`  вң“ tracked ${audit.tracked.length}кұҙ (open + task/plan/decisions л§Өм№ӯлҗЁ):`));
      for (const t of audit.tracked.slice(0, 5)) {
        log(`    вҖў [${t.id}] ${t.text.slice(0, 80)}${t.text.length > 80 ? 'вҖҰ' : ''} ${dim(`(hits=${t.hits})`)}`);
      }
    }
    if (audit.stale.length > 0) {
      log('');
      log(yel(`  вҸі stale ${audit.stale.length}кұҙ (7мқј+ open):`));
      for (const s of audit.stale.slice(0, 5)) {
        const days = Math.floor((Date.now() - new Date(s.recordedAt).getTime()) / 86400000);
        log(`    вҖў [${s.id}] ${days}мқј ${s.text.slice(0, 70)}вҖҰ`);
      }
    }
    return;
  }

  console.error(`Unknown subcommand: ${sub}`);
  console.error(`Run: leerness requests help`);
  process.exit(1);
}

// 1.9.220: leerness session-resume вҖ” л№„м •мғҒ мў…лЈҢ к°җм§Җ + мһҗмңЁ мһ¬к°ң к°Җмқҙл“ң (мӮ¬мҡ©мһҗ лӘ…мӢң)
// 1.9.222: --auto-fix мҳөм…ҳ м¶”к°Җ вҖ” м•Ҳм „н•ң мһҗлҸҷ нҡҢліө (wakeup supersede)
function sessionResumeCmd(root) {
  root = absRoot(root);
  const isTty = process.stdout && process.stdout.isTTY;
  const cyan = s => isTty ? `\x1b[36m${s}\x1b[0m` : s;
  const grn = s => isTty ? `\x1b[32m${s}\x1b[0m` : s;
  const yel = s => isTty ? `\x1b[33m${s}\x1b[0m` : s;
  const red = s => isTty ? `\x1b[31m${s}\x1b[0m` : s;
  const dim = s => isTty ? `\x1b[2m${s}\x1b[0m` : s;

  const result = _detectAbnormalShutdown(root);

  // 1.9.222: --auto-fix вҖ” м•Ҳм „н•ң мӢ нҳёлі„ мһҗлҸҷ нҡҢліө
  const autoFix = has('--auto-fix');
  if (autoFix && result.abnormalShutdown) {
    result.autoFixed = [];
    // 1) wakeup-missed вҶ’ мҳӨлһҳлҗң pending wakeup supersede (м•Ҳм „: лӢЁмҲң мғҒнғң ліҖкІҪ)
    if (result.signals.some(s => s.kind === 'wakeup-missed')) {
      try {
        const state = _loadActiveWakeups(root);
        let fixed = 0;
        state.wakeups = state.wakeups.map(w => {
          if (w.status === 'pending') {
            const expectedMs = new Date(w.expectedFireAt).getTime();
            const deltaMin = Math.floor((Date.now() - expectedMs) / 60000);
            if (deltaMin > 30) {
              w.status = 'superseded';
              w.supersededReason = 'auto-fix-1.9.222-abnormal-shutdown';
              w.supersededAt = new Date().toISOString();
              fixed++;
            }
          }
          return w;
        });
        if (fixed > 0) {
          _writeActiveWakeups(root, state.wakeups);
          result.autoFixed.push({ kind: 'wakeup-missed', action: 'superseded', count: fixed });
        }
      } catch {}
    }
    // 2) auto-resume-plan-unused вҶ’ 60min+ лҜёмӮ¬мҡ©мқҖ м•ҲлӮҙл§Ң (мһҗлҸҷ мӮӯм ң X, мӮ¬мҡ©мһҗк°Җ кІҖнҶ н•ҙм•ј н•Ё)
    if (result.signals.some(s => s.kind === 'auto-resume-plan-unused')) {
      result.autoFixed.push({ kind: 'auto-resume-plan-unused', action: 'guidance-only', detail: 'leerness resume мңјлЎң м Ғмҡ© кІҖнҶ ' });
    }
    // 3) in-progress-stale вҶ’ drop кІ°м •мқҖ мӮ¬мҡ©мһҗ мҳҒм—ӯ (мһҗлҸҷ X)
    if (result.signals.some(s => s.kind === 'in-progress-stale')) {
      result.autoFixed.push({ kind: 'in-progress-stale', action: 'guidance-only', detail: 'leerness task list --status in-progress нӣ„ мӮ¬мҡ©мһҗ кІ°м • н•„мҡ”' });
    }
  }

  if (has('--json')) { log(JSON.stringify(result, null, 2)); return; }
  log(cyan(`# leerness session-resume (1.9.220) вҖ” л№„м •мғҒ мў…лЈҢ к°җм§Җ + мһҗмңЁ мһ¬к°ң`));
  log(`  detected at: ${result.detectedAt}`);
  log('');
  if (!result.abnormalShutdown) {
    log(grn(`  вң“ л№„м •мғҒ мў…лЈҢ мӢ нҳё м—ҶмқҢ вҖ” м •мғҒ мҡҙмҳҒ мӨ‘`));
    if (result.signals.length > 0) {
      log(dim(`     (low-severity мӢ нҳё ${result.signals.length}кұҙ вҖ” л¬ҙмӢң к°ҖлҠҘ)`));
    }
    log('');
    log(dim(`  вҶ’ нҸүмҶҢлҢҖлЎң leerness handoff . лЎң мӢңмһ‘`));
    return;
  }
  const sevIcon = result.severity === 'high' ? 'рҹҡЁ' : 'вҡ ';
  const sevColor = result.severity === 'high' ? red : yel;
  log(sevColor(`  ${sevIcon} л№„м •мғҒ мў…лЈҢ к°җм§Җ вҖ” severity: ${result.severity} (signals: ${result.signals.length})`));
  log('');
  log(`## к°җм§Җ мӢ нҳё`);
  for (const s of result.signals) {
    const icon = s.severity === 'high' ? 'рҹҡЁ' : (s.severity === 'medium' ? 'вҡ ' : 'в„№');
    const c = s.severity === 'high' ? red : (s.severity === 'medium' ? yel : dim);
    log(c(`  ${icon} [${s.kind}] ${s.detail}`));
  }
  log('');
  log(`## мһ¬к°ң к°Җмқҙл“ң`);
  for (const g of result.resumeGuide) {
    log(`  ${g}`);
  }
  // 1.9.222: --auto-fix кІ°кіј л…ём¶ң
  if (result.autoFixed && result.autoFixed.length > 0) {
    log('');
    log(grn(`## рҹ”§ auto-fix кІ°кіј (${result.autoFixed.length})`));
    for (const af of result.autoFixed) {
      const icon = af.action === 'superseded' ? 'вң“' : 'в„№';
      log(`  ${icon} [${af.kind}] ${af.action}${af.count ? ` (count: ${af.count})` : ''}`);
      if (af.detail) log(dim(`     ${af.detail}`));
    }
  } else if (autoFix) {
    log(dim(`  (auto-fix м Ғмҡ© лҢҖмғҒ м—ҶмқҢ)`));
  }
}

// 1.9.208: leerness constraints <list|check|add> вҖ” н”Ңлһ«нҸј/API м ңм•Ҫ мӮ¬м „ мІҙнҒ¬ CLI (мӮ¬мҡ©мһҗ лӘ…мӢң)
//   "нҠ№м • н”Ңлһ«нҸјмқҳ API ... нҳём¶ңмҶҚлҸ„к°Җ мҙҲлӢ№ 5нҡҢ мқҙн•ҳлЎңл§Ң н•ҙм•јн•ңлӢӨлҠ” к·ңм •мқ„ лЁјм Җ нҷ•мқё"
//   list           вҶ’ л“ұлЎқлҗң лӘЁл“  н”Ңлһ«нҸј catalog м¶ңл Ҙ
//   check "<req>"  вҶ’ мӮ¬мҡ©мһҗ мҡ”мІӯ н…ҚмҠӨнҠём—җм„ң н”Ңлһ«нҸј л§Өм№ӯ вҶ’ м ңм•Ҫ ліҙкі  (--json к°ҖлҠҘ)
//   add <id> --aliases ... --constraint "kind:detail" вҶ’ мӮ¬мҡ©мһҗ м •мқҳ н”Ңлһ«нҸј м¶”к°Җ
function constraintsCmd(root, sub, ...rest) {
  root = absRoot(root);
  const isTty = process.stdout && process.stdout.isTTY;
  const cyan = s => isTty ? `\x1b[36m${s}\x1b[0m` : s;
  const grn = s => isTty ? `\x1b[32m${s}\x1b[0m` : s;
  const yel = s => isTty ? `\x1b[33m${s}\x1b[0m` : s;
  const red = s => isTty ? `\x1b[31m${s}\x1b[0m` : s;
  const dim = s => isTty ? `\x1b[2m${s}\x1b[0m` : s;

  if (!sub || sub === 'help' || sub === '--help') {
    log(`# leerness constraints (1.9.208) вҖ” н”Ңлһ«нҸј/API м ңм•Ҫ мӮ¬м „ мІҙнҒ¬`);
    log('');
    log(`  list                  вҶ’ л“ұлЎқлҗң лӘЁл“  н”Ңлһ«нҸј catalog м¶ңл Ҙ (--json к°ҖлҠҘ)`);
    log(`  check "<request>"     вҶ’ мӮ¬мҡ©мһҗ мҡ”мІӯм—җм„ң н”Ңлһ«нҸј л§Өм№ӯ вҶ’ м ңм•Ҫ ліҙкі  (--json к°ҖлҠҘ)`);
    log(`  add <id> --constraint "kind:detail" --alias name`);
    log('');
    log(dim(`  мҳҲ: leerness constraints check "Stripe API м—°лҸҷ кІ°м ң лӘЁл“Ҳ"`));
    return;
  }

  if (sub === 'list') {
    const catalog = _loadPlatformConstraints(root);
    if (has('--json')) { log(JSON.stringify(catalog, null, 2)); return; }
    log(cyan(`# leerness constraints list (1.9.208)`));
    log(`  total platforms: ${Object.keys(catalog.platforms).length}`);
    log('');
    for (const [pid, plat] of Object.entries(catalog.platforms)) {
      log(grn(`  рҹ“Ұ ${pid}`) + dim(`  aliases: ${(plat.aliases || []).join(', ')}`));
      log(dim(`     docs: ${plat.docs || '-'}`));
      for (const c of plat.constraints || []) {
        const icon = c.kind === 'rate-limit' ? 'рҹҡҰ' : (c.kind === 'cost' ? 'рҹ’°' : (c.kind === 'auth' ? 'рҹ”җ' : 'рҹ“Ӣ'));
        log(`     ${icon} [${c.kind}] ${c.detail}`);
      }
      log('');
    }
    return;
  }

  if (sub === 'check') {
    const text = rest.filter(x => !x.startsWith('-')).join(' ');
    if (!text) { console.error('Usage: leerness constraints check "<request text>"'); process.exit(1); }
    const result = _checkRequestConstraints(root, text);
    if (has('--json')) { log(JSON.stringify({ query: text, ...result }, null, 2)); return; }
    log(cyan(`# leerness constraints check (1.9.208)`));
    log(`  query: ${text.slice(0, 80)}${text.length > 80 ? 'вҖҰ' : ''}`);
    log('');
    if (result.matched.length === 0) {
      log(grn(`  вң“ л§Өм№ӯлҗң н”Ңлһ«нҸј м—ҶмқҢ (catalog ${result.totalPlatforms}мў… кІҖнҶ  мҷ„лЈҢ)`));
      if (result.suggestions.length) {
        log('');
        log(yel(`  рҹ’Ў м ңм•Ҳ:`));
        result.suggestions.forEach(s => log(`     вҖў ${s}`));
      }
      return;
    }
    log(red(`  вҡ  ${result.matched.length}к°ң н”Ңлһ«нҸј л§Өм№ӯ вҖ” м ңм•Ҫ мӮ¬м „ нҷ•мқё н•„мҡ”:`));
    log('');
    for (const m of result.matched) {
      log(grn(`  рҹ“Ұ ${m.platform}`) + dim(` (matched: "${m.matchedAlias}")`));
      log(dim(`     docs: ${m.docs || '-'}`));
      for (const c of m.constraints || []) {
        const icon = c.kind === 'rate-limit' ? 'рҹҡҰ' : (c.kind === 'cost' ? 'рҹ’°' : (c.kind === 'auth' ? 'рҹ”җ' : 'рҹ“Ӣ'));
        log(`     ${icon} [${c.kind}] ${c.detail}`);
      }
      log('');
    }
    log(dim(`  вҶ’ кө¬нҳ„ м „ мң„ м ңм•Ҫмқ„ л°ҳмҳҒн•ң м„Өкі„ к¶ҢмһҘ (rate limiter / idempotency key / л№„мҡ© м¶”м •)`));
    return;
  }

  if (sub === 'add') {
    const id = rest[0];
    if (!id) { console.error('Usage: leerness constraints add <platform-id> --constraint "kind:detail"'); process.exit(1); }
    const catalog = _loadPlatformConstraints(root);
    const aliases = (arg('--alias', '') || '').split(',').map(s => s.trim()).filter(Boolean);
    const detailRaw = arg('--constraint', '');
    if (!detailRaw) { console.error('--constraint "kind:detail" required'); process.exit(1); }
    const [kind, ...rest2] = detailRaw.split(':');
    const detail = rest2.join(':').trim();
    if (!catalog.platforms[id]) catalog.platforms[id] = { aliases: [], constraints: [] };
    if (aliases.length) catalog.platforms[id].aliases = [...new Set([...(catalog.platforms[id].aliases || []), ...aliases])];
    if (kind && detail) catalog.platforms[id].constraints.push({ kind: kind.trim(), detail });
    _writePlatformConstraints(root, catalog);
    if (has('--json')) { log(JSON.stringify(catalog.platforms[id], null, 2)); return; }
    log(grn(`вң“ platform "${id}" к°ұмӢ  вҖ” constraints: ${catalog.platforms[id].constraints.length}`));
    return;
  }

  console.error(`Unknown subcommand: ${sub}`);
  console.error(`Run: leerness constraints help`);
  process.exit(1);
}

// 1.9.209: leerness pre-wake-audit вҖ” sleep м „ sub-agent audit CLI (мӮ¬мҡ©мһҗ лӘ…мӢң)
//   "л©”мқё м—җмқҙм „нҠёк°Җ мҠ¬лҰҪм „м—җ м„ңлёҢм—җмқҙм „нҠёлҘј нҳём¶ңн•ҙм„ң лҜёл№„лҗң л¶Җл¶„мқҙ мһҲлҠ”м§Җ, м¶©лҸҢлӮҳлҠ” л¶Җл¶„мқҙ мһҲлҠ”м§Җ,
//    мқҙм „м—җ лҲ„лқҪлҗң мһ‘м—…мқҙ мһҲлҠ”м§Җ л“ұл“ұ м—¬лҹ¬л¶Җл¶„мқ„ нғҗмғүн•ҳл©ҙм„ң н•„мҡ”н•ң лӮҙмҡ©мқ„ м •лҰ¬"
//   кё°ліё: мғҲ audit мӢӨн–ү + м ҖмһҘ + м¶ңл Ҙ
//   --last: мөңк·ј м ҖмһҘлҗң audit н‘ңмӢң (мӮ¬мҡ©мһҗ к№Ём–ҙлӮ¬мқ„ л•Ң кІҖнҶ мҡ©)
//   --json: JSON м¶ңл Ҙ
function preWakeAuditCmd(root, sub) {
  root = absRoot(root);
  const isTty = process.stdout && process.stdout.isTTY;
  const cyan = s => isTty ? `\x1b[36m${s}\x1b[0m` : s;
  const grn = s => isTty ? `\x1b[32m${s}\x1b[0m` : s;
  const yel = s => isTty ? `\x1b[33m${s}\x1b[0m` : s;
  const red = s => isTty ? `\x1b[31m${s}\x1b[0m` : s;
  const dim = s => isTty ? `\x1b[2m${s}\x1b[0m` : s;

  // --last лҳҗлҠ” review/show вҖ” к°ҖмһҘ мөңк·ј audit н‘ңмӢң (мӢӨн–ү м•Ҳ н•Ё)
  if (has('--last') || sub === 'show' || sub === 'review') {
    const state = _loadPreWakeReport(root);
    if (state.reports.length === 0) {
      log(cyan(`# leerness pre-wake-audit (1.9.209) вҖ” review`));
      log(dim(`  (м ҖмһҘлҗң audit м—ҶмқҢ вҖ” leerness pre-wake-audit мңјлЎң мғҲ мӢӨн–ү)`));
      return;
    }
    const latest = state.reports[state.reports.length - 1];
    if (has('--json')) { log(JSON.stringify(latest, null, 2)); return; }
    log(cyan(`# leerness pre-wake-audit (1.9.209) вҖ” review (latest)`));
    log(dim(`  audited at: ${latest.auditedAt}  (version ${latest.auditVersion})`));
    log('');
    const sum = latest.summary || {};
    log(`  рҹ“Ҡ ${red(`critical ${sum.criticalCount || 0}`)} В· ${yel(`warning ${sum.warningCount || 0}`)} В· info ${sum.infoCount || 0}`);
    if (sum.needsAttention) log(yel(`  вҡ  needsAttention=true вҖ” л©”мқё м—җмқҙм „нҠё кІҖнҶ  н•„мҡ”`));
    log('');
    if (latest.findings.critical && latest.findings.critical.length) {
      log(red(`## рҹҡЁ critical (${latest.findings.critical.length})`));
      latest.findings.critical.forEach(f => log(`  - [${f.kind}] ${f.detail}`));
      log('');
    }
    if (latest.findings.warning && latest.findings.warning.length) {
      log(yel(`## вҡ  warning (${latest.findings.warning.length})`));
      latest.findings.warning.forEach(f => log(`  - [${f.kind}] ${f.detail}`));
      log('');
    }
    if (latest.findings.info && latest.findings.info.length) {
      log(dim(`## в„№ info (${latest.findings.info.length})`));
      latest.findings.info.forEach(f => log(dim(`  - [${f.kind}] ${f.detail}`)));
    }
    return;
  }

  // кё°ліё: мғҲ audit мӢӨн–ү + м ҖмһҘ
  const audit = _runPreWakeAudit(root);
  _saveAndAppendPreWakeReport(root, audit);

  if (has('--json')) { log(JSON.stringify(audit, null, 2)); return; }
  log(cyan(`# leerness pre-wake-audit (1.9.209) вҖ” sleep м „ sub-agent audit`));
  log(dim(`  audited at: ${audit.auditedAt}`));
  log('');
  const sum = audit.summary;
  log(`  рҹ“Ҡ ${red(`critical ${sum.criticalCount}`)} В· ${yel(`warning ${sum.warningCount}`)} В· info ${sum.infoCount}`);
  if (sum.needsAttention) {
    log(yel(`  вҡ  needsAttention=true вҖ” к№Ём–ҙлӮң нӣ„ л©”мқё м—җмқҙм „нҠё кІҖнҶ  н•„мҲҳ`));
  } else {
    log(grn(`  вң“ мһ мһ¬ мқҙмҠҲ м—ҶмқҢ вҖ” sleep м•Ҳм „`));
  }
  log('');
  if (audit.findings.critical.length) {
    log(red(`## рҹҡЁ critical (${audit.findings.critical.length})`));
    audit.findings.critical.forEach(f => {
      log(`  - [${f.kind}] ${f.detail}`);
      if (f.items) f.items.forEach(i => log(dim(`       вҖў ${i.id}: ${i.text}`)));
    });
    log('');
  }
  if (audit.findings.warning.length) {
    log(yel(`## вҡ  warning (${audit.findings.warning.length})`));
    audit.findings.warning.forEach(f => log(`  - [${f.kind}] ${f.detail}`));
    log('');
  }
  if (audit.findings.info.length) {
    log(dim(`## в„№ info (${audit.findings.info.length})`));
    audit.findings.info.forEach(f => log(dim(`  - [${f.kind}] ${f.detail}`)));
    log('');
  }
  log(dim(`  вҶ’ м ҖмһҘ: .harness/pre-wake-report.json (мөңк·ј 10к°ң мң м§Җ)`));
  log(dim(`  вҶ’ к№Ём–ҙлӮң нӣ„: leerness pre-wake-audit --last`));
}

// 1.9.210: leerness wakeup-interval <get|set|auto|history|record> вҖ” adaptive wakeup interval (мӮ¬мҡ©мһҗ лӘ…мӢң)
//   "wakeup 30л¶„л“ұ кёҙ мӢңк°„мқҙ н•„мҡ”м—ҶлӢӨл©ҙ к°„кІ©мқ„ нғҖмқҙнҠён•ҳкІҢ мһҗлҸҷмңјлЎң мЎ°м Ҳн•ҳлҸ„лЎқ"
//   get      вҶ’ нҳ„мһ¬ к¶ҢмһҘ interval + л¶„м„қ stats (--json к°ҖлҠҘ)
//   set N    вҶ’ wakeup-history.json override м„Өм • (мҙҲ)
//   auto     вҶ’ override н•ҙм ң (мһҗлҸҷ кі„мӮ° лӘЁл“ң ліөк·Җ)
//   history  вҶ’ мөңк·ј fire мқҙл Ҙ м¶ңл Ҙ
//   record <kind> вҶ’ fire кё°лЎқ (user-trigger / auto / wakeup-miss)
function wakeupIntervalCmd(root, sub, val) {
  root = absRoot(root);
  const isTty = process.stdout && process.stdout.isTTY;
  const cyan = s => isTty ? `\x1b[36m${s}\x1b[0m` : s;
  const grn = s => isTty ? `\x1b[32m${s}\x1b[0m` : s;
  const yel = s => isTty ? `\x1b[33m${s}\x1b[0m` : s;
  const dim = s => isTty ? `\x1b[2m${s}\x1b[0m` : s;

  if (!sub || sub === 'help' || sub === '--help') {
    log(`# leerness wakeup-interval (1.9.210) вҖ” adaptive wakeup к°„кІ©`);
    log('');
    log(`  get              вҶ’ нҳ„мһ¬ к¶ҢмһҘ interval + stats (--json к°ҖлҠҘ)`);
    log(`  set <secs>       вҶ’ override м„Өм • (мҳҲ: leerness wakeup-interval set 900)`);
    log(`  auto             вҶ’ override н•ҙм ң + мһҗлҸҷ кі„мӮ° лӘЁл“ң`);
    log(`  history          вҶ’ мөңк·ј fire мқҙл Ҙ м¶ңл Ҙ`);
    log(`  record <kind>    вҶ’ fire кё°лЎқ (user-trigger / auto / wakeup-miss)`);
    log('');
    log(dim(`  opt-out: env LEERNESS_FIXED_INTERVAL=1500 (мҙҲ) лҳҗлҠ” set <secs>`));
    return;
  }

  if (sub === 'get') {
    const result = _computeAdaptiveInterval(root);
    if (has('--json')) { log(JSON.stringify(result, null, 2)); return; }
    log(cyan(`# leerness wakeup-interval get (1.9.210)`));
    log(`  рҹ“Ҡ к¶ҢмһҘ interval: ${grn(`${result.interval}s (${Math.round(result.interval/60)}min)`)}`);
    log(`  mode: ${result.adaptive ? grn('adaptive') : yel('fixed')}`);
    log(`  reason: ${result.reason}`);
    if (result.stats) {
      log('');
      log(`  рҹ“Ҳ stats (recent 2h):`);
      log(`     вҖў total fires: ${result.stats.recentTotal}`);
      log(`     вҖў user triggers: ${result.stats.userTriggers}`);
      if (result.stats.avgUserGapMin !== null) log(`     вҖў avg user gap: ${result.stats.avgUserGapMin}min`);
      if (result.stats.criticalSignal) log(yel(`     вҖў pre-wake critical к°җм§Җ`));
    }
    log('');
    log(dim(`  вҶ’ ScheduleWakeup(delaySeconds: ${result.interval}) к¶ҢмһҘ`));
    return;
  }

  if (sub === 'set') {
    const n = Number(val);
    if (!val || isNaN(n) || n < 60) { console.error('Usage: leerness wakeup-interval set <secs вүҘ 60>'); process.exit(1); }
    const state = _loadWakeupHistory(root);
    state.override = n;
    _writeWakeupHistory(root, state);
    if (has('--json')) { log(JSON.stringify({ override: n }, null, 2)); return; }
    log(grn(`вң“ wakeup-interval override м„Өм •: ${n}s (${Math.round(n/60)}min)`));
    log(dim(`  н•ҙм ң: leerness wakeup-interval auto`));
    return;
  }

  if (sub === 'auto') {
    const state = _loadWakeupHistory(root);
    state.override = null;
    _writeWakeupHistory(root, state);
    const result = _computeAdaptiveInterval(root);
    if (has('--json')) { log(JSON.stringify({ override: null, current: result }, null, 2)); return; }
    log(grn(`вң“ override н•ҙм ң вҖ” мһҗлҸҷ кі„мӮ° лӘЁл“ң`));
    log(`  нҳ„мһ¬ к¶ҢмһҘ: ${result.interval}s (${Math.round(result.interval/60)}min) вҖ” ${result.reason}`);
    return;
  }

  if (sub === 'history') {
    const state = _loadWakeupHistory(root);
    if (has('--json')) { log(JSON.stringify({ override: state.override, fires: state.fires.slice(-20) }, null, 2)); return; }
    log(cyan(`# leerness wakeup-interval history (1.9.210)`));
    log(`  total fires: ${state.fires.length}${state.override ? ` В· override: ${state.override}s` : ''}`);
    log('');
    const recent = state.fires.slice(-15);
    if (recent.length === 0) { log(dim('  (м—ҶмқҢ)')); return; }
    for (const f of recent) {
      const icon = f.kind === 'user-trigger' ? 'рҹ‘Ҷ' : (f.kind === 'wakeup-miss' ? 'вқ—' : 'вҸ°');
      log(`  ${icon} ${f.at}  ${dim(f.kind)}`);
    }
    return;
  }

  if (sub === 'record') {
    const kind = val || 'auto';
    const validKinds = ['auto', 'user-trigger', 'wakeup-miss'];
    if (!validKinds.includes(kind)) { console.error(`kind must be: ${validKinds.join('/')}`); process.exit(1); }
    _recordWakeupFire(root, kind);
    if (has('--json')) { log(JSON.stringify({ recorded: kind, at: new Date().toISOString() }, null, 2)); return; }
    log(grn(`вң“ wakeup fire кё°лЎқ: ${kind}`));
    return;
  }

  console.error(`Unknown subcommand: ${sub}`);
  console.error(`Run: leerness wakeup-interval help`);
  process.exit(1);
}

// 1.9.211: leerness workspace-dir <get|guide> вҖ” мӣҢнҒ¬мҠӨнҺҳмқҙмҠӨ л””л үнҶ лҰ¬ м •ліҙ + AI м°ёмЎ° к°Җмқҙл“ң (мӮ¬мҡ©мһҗ лӘ…мӢң)
function workspaceDirCmd(root, sub) {
  root = absRoot(root);
  const isTty = process.stdout && process.stdout.isTTY;
  const cyan = s => isTty ? `\x1b[36m${s}\x1b[0m` : s;
  const grn = s => isTty ? `\x1b[32m${s}\x1b[0m` : s;
  const dim = s => isTty ? `\x1b[2m${s}\x1b[0m` : s;

  if (!sub || sub === 'get') {
    const dirName = _workspaceDirName(root);
    const dirAbs = _workspaceDirAbs(root);
    const hasHarness = exists(path.join(root, '.harness'));
    const hasLeerness = exists(path.join(root, '.leerness'));
    const migrated = exists(path.join(root, '.leerness', 'MIGRATED_FROM_HARNESS'));
    const result = { current: dirName, abs: dirAbs, hasHarness, hasLeerness, migrated };
    if (has('--json')) { log(JSON.stringify(result, null, 2)); return; }
    log(cyan(`# leerness workspace-dir (1.9.211)`));
    log(`  нҳ„мһ¬ л””л үнҶ лҰ¬: ${grn(dirName + '/')}`);
    log(`  abs: ${dirAbs}`);
    log(`  .harness мЎҙмһ¬: ${hasHarness ? 'вң“' : 'вң—'}`);
    log(`  .leerness мЎҙмһ¬: ${hasLeerness ? 'вң“' : 'вң—'}`);
    log(`  л§Ҳмқҙк·ёл Ҳмқҙм…ҳ мҷ„лЈҢ: ${migrated ? 'вң“' : 'вң—'}`);
    log('');
    if (hasHarness && !hasLeerness) {
      log(dim(`  вҶ’ л§Ҳмқҙк·ёл Ҳмқҙм…ҳ: leerness migrate-workspace-dir`));
    } else if (migrated) {
      log(dim(`  вҶ’ AI м°ёмЎ° к°Җмқҙл“ң: leerness workspace-dir guide`));
    }
    return;
  }

  if (sub === 'guide') {
    const dirName = _workspaceDirName(root);
    const guide = _buildWorkspaceReferenceGuide(root, dirName);
    if (has('--json')) { log(JSON.stringify({ workspaceDir: dirName, guide }, null, 2)); return; }
    log(guide);
    return;
  }

  console.error(`Usage: leerness workspace-dir [get|guide]`);
  process.exit(1);
}

// 1.9.211: leerness migrate-workspace-dir вҖ” .harness вҶ’ .leerness л§Ҳмқҙк·ёл Ҳмқҙм…ҳ (мӮ¬мҡ©мһҗ лӘ…мӢң)
function migrateWorkspaceDirCmd(root) {
  root = absRoot(root);
  const isTty = process.stdout && process.stdout.isTTY;
  const cyan = s => isTty ? `\x1b[36m${s}\x1b[0m` : s;
  const grn = s => isTty ? `\x1b[32m${s}\x1b[0m` : s;
  const yel = s => isTty ? `\x1b[33m${s}\x1b[0m` : s;
  const red = s => isTty ? `\x1b[31m${s}\x1b[0m` : s;
  const dim = s => isTty ? `\x1b[2m${s}\x1b[0m` : s;

  const dryRun = has('--dry-run');
  const force = has('--force');
  const report = _migrateWorkspaceDir(root, { dryRun, force });

  if (has('--json')) { log(JSON.stringify(report, null, 2)); return; }
  log(cyan(`# leerness migrate-workspace-dir (1.9.211)${dryRun ? ' [DRY-RUN]' : ''}`));
  log(`  src: ${report.src}  ${report.srcExists ? 'вң“' : red('вң— м—ҶмқҢ')}`);
  log(`  dst: ${report.dst}  ${report.dstExists ? yel('вҡ  мқҙлҜё мЎҙмһ¬') : '(мғқм„ұ)'}`);
  log('');
  log(`  рҹ“Ҡ copied: ${grn(report.copiedFiles.length)}, skipped: ${report.skippedFiles.length}, errors: ${report.errors.length}`);
  if (report.copiedFiles.length > 0 && report.copiedFiles.length <= 30) {
    log('');
    log(`  ліөмӮ¬лҗң нҢҢмқј:`);
    report.copiedFiles.slice(0, 20).forEach(f => log(dim(`    + ${f}`)));
    if (report.copiedFiles.length > 20) log(dim(`    ... +${report.copiedFiles.length - 20}кұҙ`));
  } else if (report.copiedFiles.length > 30) {
    log(dim(`    (${report.copiedFiles.length}к°ң вҖ” мғҒм„ёлҠ” --json)`));
  }
  if (report.skippedFiles.length > 0) {
    log('');
    log(yel(`  мҠӨнӮөлҗң нҢҢмқј (мқҙлҜё мЎҙмһ¬, --force лЎң лҚ®м–ҙм“°кё° к°ҖлҠҘ):`));
    report.skippedFiles.slice(0, 5).forEach(f => log(dim(`    - ${f}`)));
    if (report.skippedFiles.length > 5) log(dim(`    ... +${report.skippedFiles.length - 5}кұҙ`));
  }
  if (report.errors.length > 0) {
    log('');
    log(red(`  вҡ  м—җлҹ¬:`));
    report.errors.forEach(e => log(red(`    - ${e}`)));
  }
  log('');
  if (!dryRun && report.copiedFiles.length > 0) {
    log(grn(`вң“ л§Ҳмқҙк·ёл Ҳмқҙм…ҳ мҷ„лЈҢ вҖ” .leerness/WHERE_TO_FIND.md + MIGRATED_FROM_HARNESS л§Ҳм»Ө мғқм„ұ`));
    log(dim(`  вҶ’ лӢӨмқҢ handoffл¶Җн„° .leerness мҡ°м„  мӮ¬мҡ©`));
    log(dim(`  вҶ’ .harness/MIGRATED_TO_LEERNESS.md м•ҲлӮҙ м¶”к°ҖлҗЁ (backward compat ліҙмЎҙ)`));
  } else if (dryRun) {
    log(yel(`  (dry-run вҖ” мӢӨм ң ліҖкІҪ м—ҶмқҢ. мӢӨн–ү: leerness migrate-workspace-dir)`));
  }
}

// 1.9.212: leerness idempotency <audit> вҖ” л©ұл“ұм„ұ мң„л°ҳ нғҗм§Җ + к¶ҢмһҘ fix (мӮ¬мҡ©мһҗ лӘ…мӢң)
//   "лӢӨм–‘н•ң л¶Җл¶„м—җм„ң л©ұл“ұм„ұмқҙ н•„мҡ”н•ң л¶Җл¶„мқҙ кі л Өлҗҳкі мһҲлҠ”м§Җ нҷ•мқён•ҙмЈјкі  мҳ¬л°”лҘё л°©н–Ҙмқём§Җ нҢҗлӢЁ"
//   нғҗм§Җ мҳҒм—ӯ:
//     1. rules.md вҖ” к°ҷмқҖ description + trigger + active мӨ‘ліө
//     2. progress-tracker.md вҖ” к°ҷмқҖ request н…ҚмҠӨнҠё мӨ‘ліө (нҷңм„ұ мғҒнғң)
//     3. user-requests.json вҖ” лҸҷмқј н…ҚмҠӨнҠё + open (1.9.207 мһҗмІҙ dedup кІҖмҰқ)
//     4. active-wakeups.json вҖ” лҸҷмқј expectedFireAt мӨ‘ліө (1.9.205 dedup кІҖмҰқ)
//     5. next-action-queue.json вҖ” лҸҷмқј title мӨ‘ліө (1.9.201 dedup кІҖмҰқ)
function _runIdempotencyAudit(root) {
  const audit = {
    auditedAt: new Date().toISOString(),
    auditVersion: VERSION,
    violations: [],
    verified: []
  };
  // 1) rules.md dup кІҖмӮ¬
  try {
    const rules = readRules(root);
    const active = rules.filter(r => r.status === 'active');
    const seen = new Map();
    for (const r of active) {
      const key = `${r.trigger}::${r.rule}`;
      if (seen.has(key)) {
        audit.violations.push({
          kind: 'rule-duplicate',
          location: '.harness/rules.md',
          detail: `мӨ‘ліө лЈ°: ${r.id} == ${seen.get(key)} (${r.trigger}: ${r.rule.slice(0, 60)})`,
          severity: 'medium',
          fix: `leerness rule remove ${r.id}`
        });
      } else {
        seen.set(key, r.id);
      }
    }
    if (audit.violations.filter(v => v.kind === 'rule-duplicate').length === 0) {
      audit.verified.push({ kind: 'rules', detail: `${active.length} active rules, мӨ‘ліө 0кұҙ` });
    }
  } catch (e) { audit.violations.push({ kind: 'audit-error', area: 'rules', detail: String(e.message || e), severity: 'low' }); }

  // 2) progress-tracker.md мӨ‘ліө request кІҖмӮ¬
  //    нҸ¬л§·: | T-XXXX | status | request | evidence | nextAction | date |
  try {
    const pt = path.join(root, '.harness', 'progress-tracker.md');
    if (exists(pt)) {
      const content = read(pt);
      const lines = content.split(/\r?\n/);
      const requests = new Map(); // text вҶ’ { id, status, line }
      for (let i = 0; i < lines.length; i++) {
        if (!/^\|\s*T-\d{4,}\s*\|/.test(lines[i])) continue;
        const cells = lines[i].split('|').slice(1, -1).map(s => s.trim());
        if (cells.length < 3) continue;
        const id = cells[0];
        const status = (cells[1] || '').toLowerCase();
        const text = cells[2];
        if (text.length < 5) continue;
        const isActive = !/^(done|dropped|blocked|completed)$/i.test(status);
        if (!isActive) continue;
        if (requests.has(text)) {
          const prev = requests.get(text);
          audit.violations.push({
            kind: 'task-duplicate-request',
            location: '.harness/progress-tracker.md',
            detail: `мӨ‘ліө request: "${text.slice(0, 50)}вҖҰ" (${prev.id} & ${id})`,
            severity: 'medium',
            fix: `мӨ‘ліө task мӨ‘ н•ҳлӮҳлҘј leerness task drop <id> мІҳлҰ¬`
          });
        } else {
          requests.set(text, { id, status, line: i + 1 });
        }
      }
      if (audit.violations.filter(v => v.kind === 'task-duplicate-request').length === 0) {
        audit.verified.push({ kind: 'tasks', detail: `${requests.size} active tasks, request мӨ‘ліө 0кұҙ` });
      }
    }
  } catch (e) { audit.violations.push({ kind: 'audit-error', area: 'tasks', detail: String(e.message || e), severity: 'low' }); }

  // 3) user-requests.json мһҗмІҙ dedup кІҖмҰқ (1.9.207)
  try {
    const ur = _loadUserRequests(root);
    const seen = new Map();
    for (const r of ur.requests) {
      if (r.status !== 'open' && r.status !== 'in-progress') continue;
      const k = r.text.trim();
      if (seen.has(k)) {
        audit.violations.push({
          kind: 'user-request-duplicate',
          location: '.harness/user-requests.json',
          detail: `мӨ‘ліө open мҡ”мІӯ: ${r.id} == ${seen.get(k)} ("${k.slice(0, 50)}вҖҰ")`,
          severity: 'low',
          fix: `leerness requests drop ${r.id}`
        });
      } else {
        seen.set(k, r.id);
      }
    }
    if (audit.violations.filter(v => v.kind === 'user-request-duplicate').length === 0) {
      audit.verified.push({ kind: 'user-requests', detail: `${seen.size} open requests, мӨ‘ліө 0кұҙ (1.9.207 dedup OK)` });
    }
  } catch (e) { audit.violations.push({ kind: 'audit-error', area: 'user-requests', detail: String(e.message || e), severity: 'low' }); }

  // 4) active-wakeups.json кІҖмҰқ (1.9.205)
  try {
    const wk = _loadActiveWakeups(root);
    const pending = wk.wakeups.filter(w => w.status === 'pending');
    const seenT = new Map();
    for (const w of pending) {
      if (seenT.has(w.expectedFireAt)) {
        audit.violations.push({
          kind: 'wakeup-duplicate',
          location: '.harness/active-wakeups.json',
          detail: `лҸҷмқј expectedFireAt мӨ‘ліө: ${w.expectedFireAt}`,
          severity: 'high',
          fix: `leerness мһҗлҸҷ _recordWakeup filter dedup кІҖнҶ  н•„мҡ”`
        });
      } else {
        seenT.set(w.expectedFireAt, true);
      }
    }
    if (audit.violations.filter(v => v.kind === 'wakeup-duplicate').length === 0) {
      audit.verified.push({ kind: 'wakeups', detail: `${pending.length} pending wakeups, мӨ‘ліө 0кұҙ (1.9.205 dedup OK)` });
    }
  } catch {}

  audit.summary = {
    totalViolations: audit.violations.length,
    highSeverity: audit.violations.filter(v => v.severity === 'high').length,
    mediumSeverity: audit.violations.filter(v => v.severity === 'medium').length,
    lowSeverity: audit.violations.filter(v => v.severity === 'low').length,
    verifiedAreas: audit.verified.length,
    overall: audit.violations.length === 0 ? 'clean' : 'violations-found'
  };
  return audit;
}
// 1.9.293: idempotency audit --auto-fix вҖ” task/user-request мӨ‘ліө мһҗлҸҷ нҡҢліө.
//   л°°кІҪ: лЈ°(1.9.212)/wakeup(1.9.205)мқҖ dedup ліҙмң н•ҳлӮҳ task/user-request лҲ„м Ғ мӨ‘ліөмқҖ нғҗм§Җл§Ң лҗҗмқҢ(мҲҳлҸҷ drop н•„мҡ”).
//   м•Ҳм „: (1) мҷ„м „ лҸҷмқј н–үл§Ң м ңкұ°(мҲңмҲҳ мӨ‘ліө), (2) active лҸҷмқј-н…ҚмҠӨнҠёлҠ” status=dropped лЎң ліҙмЎҙ(id/нһҲмҠӨнҶ лҰ¬ мң м§Җ, мӮӯм ң X),
//         (3) git-tracked нҢҢмқјмқҙлқј нҡҢліө к°ҖлҠҘ, (4) л©ұл“ұ(2нҡҢ мӢӨн–ү = no-op).
function _autoFixIdempotency(root) {
  const fixed = [];
  // 1) progress-tracker.md task мӨ‘ліө
  try {
    const pt = path.join(root, '.harness', 'progress-tracker.md');
    if (exists(pt)) {
      const header = progressHeader(root);
      const rows = readProgressRows(root);
      const seenExact = new Set();
      const seenActiveText = new Map();
      const kept = [];
      let removedExact = 0, droppedSameText = 0;
      for (const r of rows) {
        const exactKey = `${r.id}|${r.status}|${r.request}|${r.evidence}|${r.nextAction}|${r.updated}`;
        if (seenExact.has(exactKey)) { removedExact++; continue; }  // мҷ„м „ лҸҷмқј н–ү = мҲңмҲҳ мӨ‘ліө вҶ’ м ңкұ°
        seenExact.add(exactKey);
        const isActive = !/^(done|dropped|blocked|completed|\[мҷ„лЈҢ\]|\[л“ңлһҚ\]|\[ліҙлҘҳ\])/i.test(r.status || '');
        if (isActive && r.request && r.request.length >= 5) {
          if (seenActiveText.has(r.request)) {
            r.status = 'dropped';
            r.nextAction = `(auto-dedup 1.9.293 вҖ” ${seenActiveText.get(r.request)} мҷҖ лҸҷмқј)`;
            droppedSameText++;
          } else {
            seenActiveText.set(r.request, r.id);
          }
        }
        kept.push(r);
      }
      if (removedExact > 0 || droppedSameText > 0) {
        writeProgressRows(root, header, kept);
        fixed.push({ kind: 'task-duplicate-request', action: 'deduped', removedExact, droppedSameText });
      }
    }
  } catch (e) { fixed.push({ kind: 'task-duplicate-request', action: 'error', detail: String(e.message || e) }); }
  // 2) user-requests.json open мӨ‘ліө вҖ” лҸҷмқј н…ҚмҠӨнҠё мӨ‘ мөңмҙҲл§Ң open мң м§Җ, лӮҳлЁём§Җ dropped(ліҙмЎҙ)
  try {
    const ur = _loadUserRequests(root);
    const seen = new Map();
    let droppedReq = 0;
    for (const r of ur.requests) {
      if (r.status !== 'open' && r.status !== 'in-progress') continue;
      const k = (r.text || '').trim();
      if (seen.has(k)) { r.status = 'dropped'; r.droppedReason = `auto-dedup-1.9.293 (== ${seen.get(k)})`; droppedReq++; }
      else seen.set(k, r.id);
    }
    if (droppedReq > 0) {
      _writeUserRequests(root, ur.requests);
      fixed.push({ kind: 'user-request-duplicate', action: 'dropped', count: droppedReq });
    }
  } catch (e) { fixed.push({ kind: 'user-request-duplicate', action: 'error', detail: String(e.message || e) }); }
  return fixed;
}
function idempotencyCmd(root, sub) {
  root = absRoot(root);
  const isTty = process.stdout && process.stdout.isTTY;
  const cyan = s => isTty ? `\x1b[36m${s}\x1b[0m` : s;
  const grn = s => isTty ? `\x1b[32m${s}\x1b[0m` : s;
  const yel = s => isTty ? `\x1b[33m${s}\x1b[0m` : s;
  const red = s => isTty ? `\x1b[31m${s}\x1b[0m` : s;
  const dim = s => isTty ? `\x1b[2m${s}\x1b[0m` : s;

  if (!sub || sub === 'help' || sub === '--help') {
    log(`# leerness idempotency (1.9.212) вҖ” л©ұл“ұм„ұ мң„л°ҳ нғҗм§Җ`);
    log('');
    log(`  audit               вҶ’ мӣҢнҒ¬мҠӨнҺҳмқҙмҠӨ л©ұл“ұм„ұ м җкІҖ (rules / tasks / user-requests / wakeups)  (--json к°ҖлҠҘ)`);
    log(`  audit --auto-fix    вҶ’ task мҷ„м „мӨ‘ліө н–ү м ңкұ° + active лҸҷмқјн…ҚмҠӨнҠё dropped мІҳлҰ¬ + user-request open мӨ‘ліө м •лҰ¬ (1.9.293)`);
    log('');
    log(dim(`  dedup м Ғмҡ© мҳҒм—ӯ: ruleAdd / taskAdd (1.9.212) + _recordUserRequest (1.9.207) + _recordWakeup (1.9.205)`));
    log(dim(`  --auto-fix м•Ҳм „: мҷ„м „ лҸҷмқј н–үл§Ң м ңкұ° / лҸҷмқјн…ҚмҠӨнҠёлҠ” status=dropped лЎң ліҙмЎҙ(id мң м§Җ) / git нҡҢліө к°ҖлҠҘ / л©ұл“ұ`));
    log(dim(`  мһҗлҸҷнҷ”: drift check --auto-fix к°Җ idempotency мӨ‘ліөлҸ„ мһҗлҸҷ м •лҰ¬ (1.9.293)`));
    log(dim(`  opt-out: --force н”Ңлһҳк·ёлЎң dedup мҡ°нҡҢ к°ҖлҠҘ`));
    return;
  }

  if (sub === 'audit') {
    const autoFix = has('--auto-fix');
    const fixes = autoFix ? _autoFixIdempotency(root) : [];
    const audit = _runIdempotencyAudit(root);  // auto-fix нӣ„ мғҒнғң л°ҳмҳҒ
    if (autoFix) audit.autoFixed = fixes;
    if (has('--json')) { log(JSON.stringify(audit, null, 2)); return; }
    log(cyan(`# leerness idempotency audit (1.9.212)`));
    log(`  audited at: ${audit.auditedAt}`);
    log('');
    const s = audit.summary;
    if (s.overall === 'clean') {
      log(grn(`  вң“ л©ұл“ұм„ұ мң„л°ҳ м—ҶмқҢ вҖ” verified ${s.verifiedAreas} мҳҒм—ӯ`));
    } else {
      log(red(`  вҡ  ${s.totalViolations} мң„л°ҳ л°ңкІ¬ (high: ${s.highSeverity}, medium: ${s.mediumSeverity}, low: ${s.lowSeverity})`));
    }
    log('');
    if (audit.verified.length) {
      log(grn(`## вң… verified (${audit.verified.length})`));
      audit.verified.forEach(v => log(dim(`  - [${v.kind}] ${v.detail}`)));
      log('');
    }
    if (audit.violations.length) {
      log(red(`## вҡ  violations (${audit.violations.length})`));
      audit.violations.forEach(v => {
        const icon = v.severity === 'high' ? 'рҹҡЁ' : (v.severity === 'medium' ? 'вҡ ' : 'в„№');
        log(`  ${icon} [${v.kind}] (${v.severity})`);
        log(dim(`     ${v.location}`));
        log(`     ${v.detail}`);
        if (v.fix) log(dim(`     fix: ${v.fix}`));
      });
    }
    if (autoFix) {
      log('');
      if (fixes.length) {
        log(grn(`## рҹ”§ auto-fix м Ғмҡ© (${fixes.length})`));
        fixes.forEach(f => {
          if (f.kind === 'task-duplicate-request') log(`  - [tasks] мҷ„м „мӨ‘ліө ${f.removedExact || 0}н–ү м ңкұ° В· лҸҷмқјн…ҚмҠӨнҠё ${f.droppedSameText || 0}кұҙ dropped мІҳлҰ¬`);
          else if (f.kind === 'user-request-duplicate') log(`  - [user-requests] open мӨ‘ліө ${f.count || 0}кұҙ dropped мІҳлҰ¬`);
          else log(dim(`  - [${f.kind}] ${f.action}${f.detail ? ' вҖ” ' + f.detail : ''}`));
        });
      } else {
        log(dim('  рҹ”§ auto-fix: м Ғмҡ©н•  мӨ‘ліө м—ҶмқҢ (мқҙлҜё м •н•©)'));
      }
    }
    return;
  }

  console.error(`Unknown subcommand: ${sub}`);
  console.error(`Run: leerness idempotency help`);
  process.exit(1);
}

// 1.9.213: leerness intent <classify|expand|domains> CLI вҖ” intent inference + scope expansion (мӮ¬мҡ©мһҗ лӘ…мӢң)
function intentCmd(root, sub, ...rest) {
  root = absRoot(root);
  const isTty = process.stdout && process.stdout.isTTY;
  const cyan = s => isTty ? `\x1b[36m${s}\x1b[0m` : s;
  const grn = s => isTty ? `\x1b[32m${s}\x1b[0m` : s;
  const yel = s => isTty ? `\x1b[33m${s}\x1b[0m` : s;
  const red = s => isTty ? `\x1b[31m${s}\x1b[0m` : s;
  const dim = s => isTty ? `\x1b[2m${s}\x1b[0m` : s;

  if (!sub || sub === 'help' || sub === '--help') {
    log(`# leerness intent (1.9.213) вҖ” мӮ¬мҡ©мһҗ мқҳлҸ„ нҢҢм•… + scope expansion кІҢмқҙнҠё`);
    log('');
    log(`  classify "<request>"      вҶ’ intent л¶„лҘҳ (precise/broad/default) + мӢ нҳё (--json к°ҖлҠҘ)`);
    log(`  expand "<request>"        вҶ’ лҸ„л©”мқё нғҗм§Җ + нҷ•мһҘ нӣ„ліҙ dry-run (--json к°ҖлҠҘ)`);
    log(`  domains                   вҶ’ л“ұлЎқлҗң лҸ„л©”мқё catalog м¶ңл Ҙ (game/web/api/cli/data)`);
    log('');
    log(dim(`  3мӣҗм№ҷ: (1) Always-Off Opt-In  (2) Dry-run кё°ліё (мӢӨн–ү X)  (3) лӘ…мӢң vs м¶”лЎ  л¶„лҰ¬ лқјлІЁл§Ғ`));
    log(dim(`  мҳҲ: leerness intent expand "л§өкіј мәҗлҰӯн„° + кё°ліё кІҢмһ„ кё°лҠҘ л§Ңл“Өм–ҙмӨҳ"`));
    return;
  }

  if (sub === 'classify') {
    const text = rest.filter(x => !x.startsWith('-')).join(' ');
    if (!text) { console.error('Usage: leerness intent classify "<request text>"'); process.exit(1); }
    const result = _classifyIntent(text);
    if (has('--json')) { log(JSON.stringify({ text, ...result }, null, 2)); return; }
    log(cyan(`# leerness intent classify (1.9.213)`));
    log(`  text: ${text.slice(0, 100)}${text.length > 100 ? 'вҖҰ' : ''}`);
    log('');
    const icon = result.intent === 'precise' ? 'рҹҺҜ' : (result.intent === 'broad' ? 'рҹҢҗ' : 'рҹ”Қ');
    log(`  ${icon} intent: ${grn(result.intent)} (precise=${result.preciseCount} / broad=${result.broadCount})`);
    if (result.signals.length) {
      log('');
      log(`  рҹ“Ў мӢ нҳё:`);
      result.signals.forEach(s => log(dim(`     вҖў [${s.kind}] "${s.match}"`)));
    }
    return;
  }

  if (sub === 'expand') {
    const text = rest.filter(x => !x.startsWith('-')).join(' ');
    if (!text) { console.error('Usage: leerness intent expand "<request text>"'); process.exit(1); }
    const result = _inferScopeExpansion(text, root);
    if (has('--json')) { log(JSON.stringify(result, null, 2)); return; }
    log(cyan(`# leerness intent expand (1.9.213) [DRY-RUN]`));
    log(`  text: ${text.slice(0, 100)}${text.length > 100 ? 'вҖҰ' : ''}`);
    log('');
    const iIcon = result.intent === 'precise' ? 'рҹҺҜ' : (result.intent === 'broad' ? 'рҹҢҗ' : 'рҹ”Қ');
    log(`  ${iIcon} intent: ${grn(result.intent)}` + (result.domain ? `  рҹ“Ұ domain: ${grn(result.domain)}` + (result.matchedAlias ? dim(` (matched: "${result.matchedAlias}")`) : '') : `  ${dim('domain лҜёнғҗм§Җ')}`));
    log('');
    if (result.explicitMentions.length) {
      log(grn(`## рҹ‘Ө мӮ¬мҡ©мһҗ лӘ…мӢң (${result.explicitMentions.length})`));
      result.explicitMentions.forEach(m => log(`  вҖў ${m.key} вҖ” ${m.desc}`));
      log('');
    }
    if (result.expansionCandidates.length) {
      log(yel(`## рҹӨ– AI м¶”лЎ  нҷ•мһҘ нӣ„ліҙ (${result.expansionCandidates.length}, dry-run)`));
      result.expansionCandidates.forEach((c, i) => log(`  [${i + 1}] ${c.key} вҖ” ${c.desc}`));
      log('');
      log(dim(`  вҶ’ м§„н–ү мӢң лӘ…мӢң мҠ№мқё н•„мҡ”: leerness task add "<м„ нғқн•ң нӣ„ліҙ мҡ”мІӯ>"`));
      log(dim(`  вҶ’ м „л¶Җ л¬ҙмӢңн•ҳл Өл©ҙ м¶”к°Җ task add м—Ҷмқҙ лӘ…мӢң мҡ”мІӯл§Ң м§„н–ү`));
    } else if (result.domain && result.intent === 'precise') {
      log(red(`  рҹӣЎ intent: precise вҖ” AI м¶”лЎ  нҷ•мһҘ л№„нҷңм„ұ (мӮ¬мҡ©мһҗ мқҳлҸ„ ліҙнҳё)`));
    }
    if (result.note) {
      log('');
      log(dim(`  в„№ ${result.note}`));
    }
    return;
  }

  if (sub === 'domains') {
    const catalog = _loadDomainCatalog(root);
    if (has('--json')) { log(JSON.stringify(catalog, null, 2)); return; }
    log(cyan(`# leerness intent domains (1.9.213)`));
    log(`  total domains: ${Object.keys(catalog.domains).length}`);
    log('');
    for (const [name, info] of Object.entries(catalog.domains)) {
      log(grn(`  рҹ“Ұ ${name}`) + dim(`  aliases: ${(info.aliases || []).join(', ')}`));
      for (const c of info.components || []) {
        log(`     вҖў ${c.key.padEnd(12)} ${dim(c.desc)}`);
      }
      log('');
    }
    return;
  }

  console.error(`Unknown subcommand: ${sub}`);
  console.error(`Run: leerness intent help`);
  process.exit(1);
}

// 1.9.199: wakeup miss мһҗлҸҷ нҡҢліө к°•нҷ” вҖ” last-handoff timestamp кё°лЎқ + 25min кё°лҢҖ interval м •л°Җ мёЎм •
//   мӮ¬мҡ©мһҗ лӘ…мӢң (1.9.198 нӣ„мҶҚ): "22:01м—җ лқјмҡҙл“ңм—җ мһҗлҸҷм§„мһ…лҗҳм§Җм•Ҡм•ҳм–ҙ"
//   1.9.196 task-log mtime кё°л°ҳ detector лҠ” task-log к°Җ мһҗмЈј м•Ҳ м—…лҚ°мқҙнҠёлҗҳл©ҙ false positive.
//   last-handoff.json м¶”к°ҖлЎң м •нҷ•лҸ„ вҶ‘ + R-0001 лЈ° (25min) лҢҖл№„ actual gap мёЎм •.
function _lastHandoffPath(root) { return path.join(root, '.harness', 'last-handoff.json'); }
function _recordLastHandoff(root) {
  try {
    mkdirp(path.join(root, '.harness'));
    const fp = _lastHandoffPath(root);
    let history = [];
    if (exists(fp)) {
      try { const j = JSON.parse(read(fp)); if (Array.isArray(j.history)) history = j.history; } catch {}
    }
    const now = new Date().toISOString();
    history.push(now);
    // мөңк·ј 10к°ңл§Ң мң м§Җ
    if (history.length > 10) history = history.slice(-10);
    writeUtf8(fp, JSON.stringify({ last: now, history }, null, 2));
    return true;
  } catch { return false; }
}
function _getLastHandoffGap(root) {
  try {
    const fp = _lastHandoffPath(root);
    if (!exists(fp)) return { hasLast: false };
    const j = JSON.parse(read(fp));
    if (!j.last) return { hasLast: false };
    const lastMs = new Date(j.last).getTime();
    const gapMs = Date.now() - lastMs;
    const gapMin = Math.floor(gapMs / 60000);
    // R-0001 мҳҒкө¬ лЈ°: 25л¶„ (1500s). gap > 35л¶„ (140% buffer) вҶ’ wakeup miss мқҳмӢ¬
    const expected = 25;
    const isMiss = gapMin > 35;
    const isLong = gapMin > 60;
    return { hasLast: true, lastAt: j.last, gapMin, expected, isMiss, isLong, history: j.history || [] };
  } catch { return { hasLast: false }; }
}

// 1.9.198: Bм¶• (л©ҖнӢ° Sub-Agent мҳӨмјҖмҠӨнҠёлқј) ліҙк°• вҖ” handoff м—җм„ң task keyword л§Өм№ӯ best agent м¶”мІң
//   1.9.193 м—җм„ң agents multi --execute кІ°кіјлҘј lessons.md м—җ кё°лЎқ вҶ’ мқҙлҘј keyword л§Өм№ӯн•ҳм—¬ м¶”м¶ң
//   мӮ¬мҡ©мһҗ/AI к°Җ к°ҷмқҖ task мһ¬мӢңлҸ„ мӢң "кіјкұ° best agent мҡ°м„  мӢңлҸ„" мҰүмӢң мқём§Җ
function _loadMultiAgentConsensusHistory(root, keyword) {
  try {
    const lp = lessonsPath(root);
    if (!exists(lp)) return [];
    const lt = read(lp);
    // 1.9.193 нҢЁн„ҙ: ### YYYY-MM-DD multi-agent consensus вҖ” best=<agent> (1.9.193)
    // blocks л¶„лҰ¬ нӣ„ keyword л§Өм№ӯ + best agent м¶”м¶ң
    const blocks = lt.split(/\n### /).slice(1).map(b => '### ' + b);
    const re193 = /multi-agent consensus вҖ” best=(\S+) \(1\.9\.193\)/;
    const fuzzyRe = keyword ? new RegExp(escapeRegex(keyword.slice(0, Math.max(4, Math.floor(keyword.length * 0.7)))), 'i') : null;
    const hits = [];
    for (const b of blocks) {
      const m = re193.exec(b);
      if (!m) continue;
      if (fuzzyRe && !fuzzyRe.test(b)) continue;
      // task / score м¶”м¶ң
      const taskM = b.match(/- task: ([^\n]+)/);
      const scoreM = b.match(/- best agent: \S+, score=([\d.]+)/);
      const dateM = b.match(/^### (\d{4}-\d{2}-\d{2})/);
      hits.push({
        date: dateM ? dateM[1] : '?',
        agent: m[1],
        task: taskM ? taskM[1].slice(0, 80) : '',
        score: scoreM ? Number(scoreM[1]) : null
      });
    }
    return hits;
  } catch { return []; }
}

// 1.9.201: Eм¶• (кІҢмңјлҰ„ л°©м§Җ) 9.5вҶ’10 ліҙк°• вҖ” next-action queue мһҗлҸҷ м ҖмһҘ + take лӘ…л №
//   handoff к°Җ м ңм•Ҳн•ң next-action top н•ӯлӘ©мқ„ .harness/next-action-queue.json м—җ м ҖмһҘ вҶ’
//   `leerness next-action take` нҳём¶ң мӢң нҒҗм—җм„ң pop + leerness task add мһҗлҸҷ мӢӨн–ү вҶ’
//   AI/мӮ¬мҡ©мһҗк°Җ м§Ғм ‘ м¶”м Ғ/нғҖмқҙн•‘ м—Ҷмқҙ 1-step мңјлЎң task м§„мһ…
function _nextActionQueuePath(root) { return path.join(root, '.harness', 'next-action-queue.json'); }
function _loadNextActionQueue(root) {
  try {
    const fp = _nextActionQueuePath(root);
    if (!exists(fp)) return { queue: [], at: null };
    const j = JSON.parse(read(fp));
    return { queue: Array.isArray(j.queue) ? j.queue : [], at: j.at || null };
  } catch { return { queue: [], at: null }; }
}
function _writeNextActionQueue(root, queue) {
  try {
    mkdirp(path.join(root, '.harness'));
    writeUtf8(_nextActionQueuePath(root), JSON.stringify({ queue, at: new Date().toISOString() }, null, 2));
    return true;
  } catch { return false; }
}
// handoff м—җм„ң м ңм•Ҳлҗң next-action л“Өмқ„ нҒҗм—җ мһҗлҸҷ м ҖмһҘ (мӨ‘ліө л°©м§Җ: мқҙлҜё мһҲлҠ” title мқҖ skip)
function _enqueueNextActions(root, actions) {
  if (!Array.isArray(actions) || actions.length === 0) return 0;
  const state = _loadNextActionQueue(root);
  const existingTitles = new Set(state.queue.map(a => a.title));
  let added = 0;
  for (const a of actions) {
    if (existingTitles.has(a.title)) continue;
    state.queue.push({ ...a, addedAt: new Date().toISOString() });
    existingTitles.add(a.title);
    added++;
  }
  // мөңк·ј 20к°ңл§Ң мң м§Җ
  if (state.queue.length > 20) state.queue = state.queue.slice(-20);
  if (added > 0) _writeNextActionQueue(root, state.queue);
  return added;
}

// 1.9.201: next-action CLI лӘ…л № вҖ” handoff к°Җ м ҖмһҘн•ң queue м—җм„ң take/list/clear
async function nextActionCmd(root, sub, ...rest) {
  root = absRoot(root);
  const state = _loadNextActionQueue(root);
  if (!sub || sub === 'list') {
    if (has('--json')) { log(JSON.stringify(state, null, 2)); return; }
    log(`# leerness next-action list (1.9.201)`);
    if (state.queue.length === 0) {
      log('  (нҒҗ л№„м–ҙмһҲмқҢ)');
      log(`  вҶ’ handoff к°Җ мһҗлҸҷмңјлЎң нҒҗм—җ м ҖмһҘн•©лӢҲлӢӨ. \`leerness handoff .\` нӣ„ лӢӨмӢң нҷ•мқё.`);
      return;
    }
    log(`  нҒҗ ${state.queue.length}кұҙ (мғқм„ұ: ${state.at || '?'})`);
    log('');
    for (let i = 0; i < state.queue.length; i++) {
      const a = state.queue[i];
      log(`  [${i}] ${a.icon || 'вҖў'} ${a.title}`);
      if (a.command) log(`      \`${a.command}\``);
    }
    log('');
    log(`  вҶ’ к°Җм ёмҳӨкё°: leerness next-action take [N]  (N мғқлһө мӢң мөңмӢ  [${state.queue.length - 1}])`);
    return;
  }
  if (sub === 'take') {
    const n = rest[0] !== undefined ? Number(rest[0]) : state.queue.length - 1;
    if (state.queue.length === 0) { fail('нҒҗ л№„м–ҙмһҲмқҢ вҖ” handoff лЁјм Җ мӢӨн–ү'); return process.exit(1); }
    if (isNaN(n) || n < 0 || n >= state.queue.length) { fail(`мһҳлӘ»лҗң index: ${n} (0~${state.queue.length - 1})`); return process.exit(1); }
    const action = state.queue[n];
    log(`# leerness next-action take [${n}] (1.9.201)`);
    log(`  ${action.icon || 'вҖў'} ${action.title}`);
    if (action.command) log(`  \`${action.command}\``);
    // task add мһҗлҸҷ нҳём¶ң
    try {
      const taskTitle = action.title.replace(/^[^\wк°Җ-нһЈ]+/, '').slice(0, 100);
      // нҒҗм—җм„ң м ңкұ° вҶ’ write
      state.queue.splice(n, 1);
      _writeNextActionQueue(root, state.queue);
      // leerness task add нҳём¶ң
      const taskResult = cp.spawnSync(process.execPath, [__filename, 'task', 'add', taskTitle, '--path', root], { encoding: 'utf8', timeout: 8000, env: { ...process.env, LEERNESS_INTERNAL: '1' } });
      if (taskResult.status === 0) {
        const m = (taskResult.stdout || '').match(/T-\d{4}/);
        log(`  вң“ task м¶”к°Җ: ${m ? m[0] : '?'} вҖ” "${taskTitle}"`);
        if (action.command) log(`  рҹ’Ў мӢӨн–ү лӘ…л №: ${action.command}`);
      } else {
        log(`  вҡ  task add мӢӨнҢЁ (exit ${taskResult.status}) вҖ” мҲҳлҸҷ: leerness task add "${taskTitle}"`);
      }
    } catch (e) {
      log(`  вҡ  мІҳлҰ¬ мӢӨнҢЁ: ${e.message}`);
    }
    return;
  }
  if (sub === 'clear') {
    _writeNextActionQueue(root, []);
    ok(`next-action нҒҗ мҙҲкё°нҷ” (${state.queue.length}кұҙ м ңкұ°)`);
    return;
  }
  if (sub === 'add') {
    const title = rest.filter(x => !x.startsWith('-')).join(' ').trim();
    if (!title) return fail('мӮ¬мҡ©лІ•: leerness next-action add "<text>"');
    _enqueueNextActions(root, [{ icon: 'рҹ“қ', title, command: null }]);
    ok(`next-action м¶”к°Җ: ${title}`);
    return;
  }
  fail(`м•Ң мҲҳ м—ҶлҠ” sub: ${sub} (list / take / clear / add)`);
}

// 1.9.194: Eм¶• (кІҢмңјлҰ„ л°©м§Җ) вҖ” handoff м—җм„ң лӢӨмқҢ лӢЁкі„ 1-3к°ң мһҗлҸҷ м ңм•Ҳ
//   нҳ„мһ¬ in-progress task description + Memory Surface (decisions/lessons/plan) мЎ°н•© вҶ’
//   "лӢӨмқҢ лӢЁкі„лЎң л¬ҙм—Үмқ„ н• м§Җ" м¶”лЎ  (мӮ¬мҡ©мһҗ/AI м§Ғм ‘ мһ…л Ҙ м—Ҷмқҙ мҰүмӢң л…ём¶ң)
//   м•Ңкі лҰ¬мҰҳ:
//     1) lessons.md м—җ keyword л§Өм№ӯ + мӢӨнҢЁ/лЎӨл°ұ нӮӨмӣҢл“ң вҶ’ "нҡҢн”ј м „лһө м Ғмҡ©"
//     2) plan.md м—җ keyword л§Өм№ӯ + M-XXXX вҶ’ "кі„нҡҚ milestone кІҖмҰқ"
//     3) decisions.md м—җ keyword л§Өм№ӯ вҶ’ "кІ°м • N мҳҒн–Ҙ нҷ•мқё"
//     4) review-evidence.md л¶Җмһ¬ вҶ’ "verify-code лҳҗлҠ” e2e мӢӨн–ү"
//     5) progress-tracker.md 24h+ м •мІҙ вҶ’ "task status к°ұмӢ "
//     6) CHANGELOG ліҙк°• л¶Җмһ¬ вҶ’ "лІ„м „ ліҖкІҪ мӢң CHANGELOG к°ұмӢ "
//     7) stress-vXXX лҲ„лқҪ вҶ’ "stress test мһ‘м„ұ"
//   1.9.116 brainstorm нҡҢмҲҳмҷҖ лӢӨлҘё м җ: brainstorm мқҖ "кҙҖл Ё hits нҡҢмҲҳ" / next-actions лҠ” "лӢӨмқҢ мӢӨн–ү лӘ…л № м ңм•Ҳ"
function _suggestNextActions(root, latestRow, keyword) {
  const actions = [];
  const taskText = String(latestRow.request || '').toLowerCase();
  const fuzzyRe = keyword ? new RegExp(escapeRegex(keyword.slice(0, Math.max(4, Math.floor(keyword.length * 0.7)))), 'i') : null;

  // 1) lessons.md мӢӨнҢЁ л§Өм№ӯ вҶ’ нҡҢн”ј м „лһө
  try {
    if (fuzzyRe && exists(lessonsPath(root))) {
      const lt = read(lessonsPath(root));
      const blocks = lt.split(/\n### /);
      const hits = blocks.filter(b => fuzzyRe.test(b) && /(мӢӨнҢЁ|fail|лЎӨл°ұ|лІ„к·ё|incomplete)/i.test(b));
      if (hits.length > 0) {
        actions.push({ icon: 'рҹӣЎ', title: `кіјкұ° мӢӨнҢЁ нҡҢн”ј вҖ” lessons.md м—җ "${keyword}" кҙҖл Ё ${hits.length}кұҙ`, command: `leerness lessons --auto --path .` });
      }
    }
  } catch {}

  // 2) plan.md milestone л§Өм№ӯ вҶ’ milestone кІҖмҰқ
  try {
    if (fuzzyRe && exists(planPath(root))) {
      const pt = read(planPath(root));
      const milestones = (pt.match(/^### (M-\d{4})\..*$/gm) || []).filter(l => fuzzyRe.test(l));
      if (milestones.length > 0) {
        const m = milestones[0].match(/M-\d{4}/);
        if (m) actions.push({ icon: 'рҹҺҜ', title: `plan.md milestone ${m[0]} кІҖмҰқ вҖ” "${keyword}" кҙҖл Ё`, command: `leerness plan list --filter "${keyword}"` });
      }
    }
  } catch {}

  // 3) decisions.md кІ°м • л§Өм№ӯ
  try {
    if (fuzzyRe && exists(decisionsPath(root))) {
      const dt = read(decisionsPath(root));
      const blocks = _extractDecisionBlocks(dt);
      const hits = blocks.filter(b => fuzzyRe.test(b));
      if (hits.length > 0) {
        actions.push({ icon: 'рҹ’ӯ', title: `decisions.md "${keyword}" кҙҖл Ё кІ°м • ${hits.length}кұҙ мҳҒн–Ҙ нҷ•мқё`, command: `leerness decision list --filter "${keyword}"` });
      }
    }
  } catch {}

  // 4) review-evidence.md л¶Җмһ¬ вҶ’ e2e
  try {
    if (!exists(evidencePath(root)) || fs.statSync(evidencePath(root)).size < 100) {
      actions.push({ icon: 'рҹ§Ә', title: `review-evidence.md л№„м–ҙмһҲмқҢ вҖ” e2e лҳҗлҠ” verify-code мӢӨн–ү`, command: `node ./scripts/e2e.js` });
    }
  } catch {}

  // 5) 24h+ м •мІҙ вҶ’ task status к°ұмӢ  (handoff lazy-warn кіј лі„к°ң вҖ” лӢӨмқҢ лӢЁкі„ лӘ…л №)
  try {
    const pp = progressPath(root);
    if (exists(pp)) {
      const ageHours = Math.floor((Date.now() - fs.statSync(pp).mtimeMs) / 3600000);
      if (ageHours >= 24 && latestRow.id) {
        actions.push({ icon: 'рҹ”„', title: `progress-tracker ${ageHours}h м •мІҙ вҖ” task ${latestRow.id} status к°ұмӢ `, command: `leerness task update ${latestRow.id} --status completed` });
      }
    }
  } catch {}

  // 6) CHANGELOG / README лІ„м „ мқјм№ҳ нҷ•мқё (1.9.X bump нӣ„ мһҗмЈј лҲ„лқҪлҗҳлҠ” лӢЁкі„)
  try {
    if (/(\d\.\d\.\d+)/.test(taskText) || /(bump|version|release)/i.test(taskText)) {
      actions.push({ icon: 'рҹ“қ', title: `лІ„м „ ліҖлҸҷ task вҖ” CHANGELOG.md / README.md к°ұмӢ  нҷ•мқё`, command: `leerness whats-new .` });
    }
  } catch {}

  // 7) stress test лҲ„лқҪ (мһҗмңЁ лқјмҡҙл“ң мһҗмЈј лҲ„лқҪ)
  try {
    const stressDir = path.resolve(root, '..', '_apps', 'leerness-stress', 'bin');
    if (exists(stressDir)) {
      const files = fs.readdirSync(stressDir).filter(f => /^stress-v\d+\.js$/.test(f));
      if (files.length > 0) {
        const versions = files.map(f => Number(f.match(/v(\d+)/)[1])).sort((a, b) => b - a);
        const latest = versions[0];
        // нҳ„мһ¬ лқјмҡҙл“ң = 1.9.X м—җм„ң stress-v(X-55) м •лҸ„? лӢЁмҲңнһҲ мөңмӢ  stress к°Җ 7мқј+ мҳӨлһҳлҗҳл©ҙ к¶ҢмһҘ
        const latestFile = path.join(stressDir, `stress-v${latest}.js`);
        const ageHours = Math.floor((Date.now() - fs.statSync(latestFile).mtimeMs) / 3600000);
        if (ageHours >= 24 && /(bump|version|ліҙк°•|м¶”к°Җ|кё°лҠҘ)/.test(taskText)) {
          actions.push({ icon: 'рҹ§¬', title: `stress-v${latest} л§Ҳм§Җл§ү к°ұмӢ  ${ageHours}h м „ вҖ” мғҲ stress test мһ‘м„ұ к¶ҢмһҘ`, command: `node _apps/leerness-stress/bin/stress-v${latest+1}.js` });
        }
      }
    }
  } catch {}

  // мӨ‘ліө м ңкұ° (icon+title кё°мӨҖ) + top 3
  const seen = new Set();
  return actions.filter(a => {
    const key = a.icon + a.title.slice(0, 30);
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  }).slice(0, 3);
}

// 1.9.182: handoff м»Ён…ҚмҠӨнҠё (нҳ„мһ¬ in-progress task) м—җм„ң мһҗлҸҷ query м¶”м¶ң
function _autoInstallQueryFromHandoff(root) {
  try {
    const rows = readProgressRows(root);
    const active = rows.find(r => r.status === '[м§„н–ү]' || r.status === '[in-progress]' || r.status === 'in_progress');
    if (active) return (active.request || '').split(/\s+/).slice(0, 3).join(' ');
  } catch {}
  return null;
}

// 1.9.192: кіөмӢқ organization skill catalog 24h мәҗмӢң вҖ” Cм¶• (кіөмӢқ н‘ңмӨҖ мҠӨнӮ¬ мһҗлҸҷ нҷңмҡ©) ліҙк°•
//   мӮ¬мҡ©мһҗ лӘ…мӢң (1.9.191): "кіөмӢқ н‘ңмӨҖнҷ”лҗң мҠӨнӮ¬мқ„ м Ғмһ¬м ҒмҶҢлЎң мһҗлҸҷ нҷңмҡ© ... кІҢмңјлҰ„ л°©м§Җл“ұл“ұ мөңкі мқҳ лҸ„кө¬"
//   handoff л§ҲлӢӨ GitHub Contents API нҳём¶ңн•ҳм§Җ м•ҠлҸ„лЎқ 24h TTL вҶ’ offline / rate-limit нҡҢн”ј
//   мәҗмӢң мң„м№ҳ: .harness/skill-auto-cache.json (мІҙнҒ¬мқё к°ҖлҠҘ вҖ” л№„мӢңнҒ¬лҰҝ)
const _OFFICIAL_SKILL_CACHE_TTL_MS = 24 * 3600 * 1000;
function _officialSkillCachePath(root) { return path.join(root, '.harness', 'skill-auto-cache.json'); }
function _loadOfficialSkillCache(root) {
  try {
    const fp = _officialSkillCachePath(root);
    if (!exists(fp)) return null;
    const j = JSON.parse(read(fp));
    if (!j.at || !Array.isArray(j.entries)) return null;
    const ageMs = Date.now() - new Date(j.at).getTime();
    return { ...j, ageMs, expired: ageMs > _OFFICIAL_SKILL_CACHE_TTL_MS };
  } catch { return null; }
}
function _writeOfficialSkillCache(root, entries, presets) {
  try {
    mkdirp(path.join(root, '.harness'));
    writeUtf8(_officialSkillCachePath(root), JSON.stringify({ at: new Date().toISOString(), presets, entries }, null, 2));
    return true;
  } catch { return false; }
}
async function _refreshOfficialSkillCache(root) {
  const presets = Object.keys(SKILL_CATALOG_PRESETS);
  const allEntries = [];
  for (const key of presets) {
    const p = SKILL_CATALOG_PRESETS[key];
    if (!p) continue;
    try {
      const r = await _fetchGitHubSkills(p.owner, p.repo, p.branch, p.path);
      if (r.ok) {
        for (const s of r.skills) allEntries.push({ ...s, preset: key });
      }
    } catch {}
  }
  if (allEntries.length > 0) _writeOfficialSkillCache(root, allEntries, presets);
  return allEntries;
}
// query (in-progress task keyword) мҷҖ л§Өм№ӯлҗҳлҠ” entries м¶”м¶ң
function _matchOfficialSkillsFromCache(root, query, max) {
  max = max || 3;
  const cache = _loadOfficialSkillCache(root);
  if (!cache || !cache.entries || cache.entries.length === 0) return { entries: [], total: 0, ageHours: null, expired: false, cacheTotal: 0 };
  const q = String(query || '').toLowerCase().split(/\s+/).filter(Boolean);
  let matched = cache.entries;
  if (q.length > 0) {
    matched = cache.entries.filter(e => {
      const hay = ((e.name || '') + ' ' + (e.description || '')).toLowerCase();
      return q.some(token => token.length >= 2 && hay.includes(token));
    });
  }
  return {
    entries: matched.slice(0, max),
    total: matched.length,
    ageHours: Math.floor(cache.ageMs / 3600000),
    expired: cache.expired,
    cacheTotal: cache.entries.length
  };
}

// skill export <id> вҖ” кё°мЎҙ мһҗмІҙ skillмқ„ agentskills.io н‘ңмӨҖ SKILL.mdлЎң export
function skillExportCmd(root, id) {
  if (!id) { fail('мӮ¬мҡ©лІ•: leerness skill export <id>'); return process.exit(1); }
  const data = loadUserSkill(root, id) || (skillCatalog[id] ? { ...skillCatalog[id], name: id } : null);
  if (!data) { fail(`skill м—ҶмқҢ: ${id}`); return process.exit(1); }
  const description = data.displayNameKo || data.description || (data.capabilities && data.capabilities[0]) || id;
  const body = `---\nname: ${id}\ndescription: ${description.slice(0, 200)}\n---\n\n# ${data.displayNameKo || id}\n\n## Capabilities\n${(data.capabilities || []).map(c => '- ' + c).join('\n') || '-'}\n\n## Sources\n${(data.sources || []).map(s => '- ' + (s.url || s)).join('\n') || '-'}\n\n## Patterns\n${(data.patterns || []).map(p => `- \`${p.command}\` вҖ” ${p.note || ''}`).join('\n') || '-'}\n`;
  const outDir = arg('--out', path.join(root, '.harness', 'skills-export', id));
  mkdirp(outDir);
  const outPath = path.join(outDir, 'SKILL.md');
  writeUtf8(outPath, body);
  log(`вң“ exported to ${rel(root, outPath)}`);
  log('');
  log(`рҹ’Ў кіөмң  к°ҖлҠҘ вҖ” лӢӨлҘё лҸ„кө¬к°Җ \`leerness skill install ${outPath}\` лҳҗлҠ” URLлЎң import`);
}

