// UR-0074 (1.9.359): install-safety вҖ” нҢЁнӮӨм§Җ м„Өм№ҳ м•Ҳм „ н”„лЎңн•„ нҲ¬лӘ… кіөк°ң (мҷёл¶ҖлҰ¬л·° м„Өм№ҳ мӢ лў°м„ұ мҡ°л Ө лҢҖмқ‘).
// leerness мқҳ н•өмӢ¬ м•Ҳм „ мҶҚм„ұ(0 лҹ°нғҖмһ„ мқҳмЎҙм„ұ В· 0 install-time мҠӨнҒ¬лҰҪнҠё)мқ„ мӮ¬мӢӨ к·ёлҢҖлЎң ліҙкі  + м•Ҳм „ м„Өм№ҳ мӣҢнҒ¬н”ҢлЎң м•ҲлӮҙ.
// нҡҢк·Җ к°Җл“ң м—ӯн• лҸ„ кІён•Ё: лҲ„кө°к°Җ лҹ°нғҖмһ„ deps/install hook лҘј м¶”к°Җн•ҳл©ҙ selftest/e2e к°Җ мӢӨнҢЁмӢңмјң мқҳмӢқм Ғ кІ°м •мқ„ к°•м ң.
function installSafetyCmd(opts = {}) {
  const pkgPath = path.join(__dirname, '..', 'package.json');
  let pkg = {};
  try { pkg = JSON.parse(read(pkgPath)); } catch {}
  const deps = Object.keys(pkg.dependencies || {});
  const scripts = pkg.scripts || {};
  const installHooks = ['preinstall', 'install', 'postinstall'].filter(h => scripts[h]);
  const profile = {
    version: VERSION,
    runtimeDeps: deps.length,
    runtimeDepList: deps,
    installScripts: installHooks,
    hasInstallScripts: installHooks.length > 0,
    node: (pkg.engines && pkg.engines.node) || null,
    offlineFirst: true,
    // 1.9.397 (6лІҲм§ё мҷёл¶ҖнҸүк°Җ/codex P1-A, UR-0098): л ҲмӢңн”јлҘј м…ё-л¬ҙкҙҖмңјлЎң вҖ” мў…м „ 'npm_config_x=true npx'(POSIX env-prefix)лҠ”
    //   PowerShell(Windows мЈјнҷҳкІҪ)м—җм„ң мӢӨнҢЁ. leerness лҠ” 0 deps/0 install-script лқј npx мӢң мӢӨн–үлҗ  мҠӨнҒ¬лҰҪнҠё мһҗмІҙк°Җ м—Ҷм–ҙ prefix л¶Ҳн•„мҡ”.
    //   нғҖ нҢЁнӮӨм§Җ лҢҖл№„ мқјл°ҳ н•ҳл“ңлӢқмқҖ м…ёлі„лЎң hardeningNote м°ёмЎ°.
    safeInstall: [
      'git checkout -b chore/leerness-update',
      'npx --yes leerness@latest migrate plan --path .   # мһ„мӢңнҸҙлҚ” л№„көҗ(мқҪкё° м „мҡ©, м…ё л¬ҙкҙҖ)',
      'npx --yes leerness@latest update --yes --path .',
      'git diff   # ліҖкІҪ кІҖнҶ  нӣ„ м»Өл°Ӣ лҳҗлҠ” лЎӨл°ұ',
    ],
    hardeningNote: 'leerness мһҗмІҙлҠ” 0 deps / 0 install-script лқј м„Өм№ҳ/м—…лҚ°мқҙнҠё мӢң мһ„мқҳмҪ”л“ң мӢӨн–ү м—ҶмқҢ. мқјл°ҳ npx н•ҳл“ңлӢқ(нғҖ нҢЁнӮӨм§Җ лҢҖл№„)мқҖ м…ёлі„ вҖ” bash: npm_config_ignore_scripts=true npx ... В· PowerShell: $env:npm_config_ignore_scripts=1; npx ... В· cmd: set npm_config_ignore_scripts=1 && npx ...',
  };
  if (opts.json) { log(JSON.stringify(profile, null, 2)); return; }
  log(`# leerness install-safety (1.9.359) вҖ” м„Өм№ҳ м•Ҳм „ н”„лЎңн•„`);
  log(`  лІ„м „: ${VERSION}  В·  Node: ${profile.node || '(лҜём§Җм •)'}`);
  log(`  лҹ°нғҖмһ„ мқҳмЎҙм„ұ: ${deps.length === 0 ? '0кұҙ (мҷёл¶Җ нҢЁнӮӨм§Җ м—ҶмқҢ вҖ” кіөкёүл§қ л…ём¶ң 0)' : deps.length + 'кұҙ вҖ” ' + deps.join(', ')}`);
  log(`  install-time мҠӨнҒ¬лҰҪнҠё: ${installHooks.length === 0 ? 'м—ҶмқҢ (preinstall/install/postinstall 0 вҖ” м„Өм№ҳ мӢң мһ„мқҳмҪ”л“ң мӢӨн–ү м—ҶмқҢ)' : installHooks.join(', ')}`);
  log(`  лҸҷмһ‘ л°©мӢқ: offline-first (м„Өм№ҳ мӢң л„ӨнҠёмӣҢнҒ¬/л№Ңл“ң л¶Ҳн•„мҡ”, лӢЁмқј bin + lib)`);
  log(`\n  м•Ҳм „ м„Өм№ҳ мӣҢнҒ¬н”ҢлЎң (кІҖнҶ  нӣ„ м Ғмҡ©):`);
  profile.safeInstall.forEach((s, i) => log(`    ${i + 1}. ${s}`));
  log(`\n  в“ҳ ${profile.hardeningNote}`);  // 1.9.397 (UR-0098): м…ёлі„ н•ҳл“ңлӢқ л…ёнҠё
  if (installHooks.length > 0) warn('install-time мҠӨнҒ¬лҰҪнҠё мЎҙмһ¬ вҖ” мң„ ignore-scripts safe-install к¶ҢмһҘ');
}
function debug(root) {
  root = absRoot(root); let warnings = 0, failures = 0;
  const checks = ['.harness/context-routing.md','.harness/writeback-policy.md','.harness/plan-progress-boundary.md','.harness/consistency-policy.md','.harness/reuse-map.md','.harness/leerness-maintenance.md','.harness/anti-lazy-work-policy.md','.harness/encoding-policy.md','.harness/secret-policy.md'];
  for (const f of checks) { if (exists(path.join(root,f))) ok(f); else { warnings++; warn('missing: ' + f); } }
  const pg = exists(planPath(root)) && exists(progressPath(root));
  if (pg) ok('plan/progress files exist'); else { failures++; fail('plan/progress missing'); }
  log(`Debug summary: warnings=${warnings} failures=${failures}`);
  if (failures) process.exitCode = 1;
}

