      const wslTag = runtimeEnv.locale.isWSL ? ' (WSL)' : '';
      log('');
      log(yl7(`## вҡ  н„°лҜёл„җ мқёмҪ”л”© вҖ” POSIX${wslTag} localeм—җ UTF-8 м—ҶмқҢ (1.9.250, UR-0018 2лӢЁкі„)`));
      log(dm7(`  LANG=${runtimeEnv.locale.LANG || 'unset'} В· LC_ALL=${runtimeEnv.locale.LC_ALL || 'unset'}`));
      log(dm7(`  вҶ’ к¶ҢмһҘ: export LANG=ko_KR.UTF-8  (лҳҗлҠ” export LC_ALL=C.UTF-8)`));
      log(dm7(`  вҶ’ мҳҒкө¬ м Ғмҡ©: ~/.bashrc лҳҗлҠ” ~/.zshrc м—җ м¶”к°Җ`));
