      const cyS = s => isTtyS ? `\x1b[36m${s}\x1b[0m` : s;
      const dmS = s => isTtyS ? `\x1b[2m${s}\x1b[0m` : s;
      log('');
      log(cyS(`## рҹӨ– CLI м—җмқҙм „нҠё мҠ¬лһҳмӢң лӘ…л № (1.9.265~266, UR-0021)`));
      log(dmS(`  нҷңм„ұ м—җмқҙм „нҠё ${enabledAgents.length}к°ң вҖ” sub-agent нҳём¶ң мӢң к°Ғмһҗ мҠ¬лһҳмӢң лӘ…л № мӮ¬мҡ©:`));
      for (const a of enabledAgents) {
        const hint = _agentSlashHint(root, a.id);
        if (hint && hint.commands.length) {
          const top = hint.commands.slice(0, 8).map(c => c.cmd).join(' ');
          log(dmS(`     ${a.id.padEnd(8)} ${top}${hint.invoke === 'subcommand' ? ' (н•ҳмң„лӘ…л №)' : ''}`));
        }
      }
      log(dmS(`  вҶ’ м „мІҙ/кё°лЎқ/мөңмӢ нҷ”: leerness slash-commands [agent] [--record]`));
