        log(dm5(`  вҶ’ мҲҳлҸҷ м •лҰ¬: leerness release cleanup --apply --keep 10`));
        log(dm5(`  вҶ’ л§Ҳк°җ мӢң мһҗлҸҷ: session close --auto-cleanup-branches`));
        log(dm5(`  вҶ’ drift мһҗлҸҷ нҡҢліө: drift check --auto-fix (1.9.236, 50+ мӢң)`));
