function stateCmd(root, sub, ...args) {
  root = absRoot(root || process.cwd());
  const json = has('--json');
  sub = sub || 'show';

  if (sub === 'start') {
    // 1.9.311 (UR-0047): state лҠ” .leerness substrate(standalone) вҖ” .harness init к°Җл“ң лҜём Ғмҡ© (нҡҢк·Җ л°©м§Җ)
    const goal = (args.find(a => a && !a.startsWith('-')) || arg('--goal', '')).trim();
    const state = _loadLeernessState(root);
    state.runCounter = (state.runCounter || 0) + 1;
    const run_id = `run-${String(state.runCounter).padStart(4, '0')}`;
    const rec = _newRunRecord({
      run_id, goal,
      task_id: arg('--task', null),
      agent_name: arg('--agent', null),
      model_name: arg('--model', null)
    });
    _saveRun(root, rec);
    state.currentRunId = run_id;
    _saveLeernessState(root, state);
    if (json) { log(JSON.stringify({ started: run_id, run: rec }, null, 2)); return; }
    ok(`run мӢңмһ‘: ${run_id}${rec.agent_name ? ' В· agent=' + rec.agent_name : ''}${rec.model_name ? ' В· model=' + rec.model_name : ''}`);
    if (goal) log(`  goal: ${goal}`);
    log(`  вҶ’ кё°лЎқ: leerness state record --files-changed "a,b" --commands "npm test" --decision "..."`);
    return;
  }

  const state = _loadLeernessState(root);
  const curId = state.currentRunId;
  if ((sub === 'record' || sub === 'verify' || sub === 'handoff') && !curId) {
    return fail('м§„н–ү мӨ‘ run м—ҶмқҢ вҖ” лЁјм Җ leerness state start "<goal>"');
  }

  if (sub === 'record') {
    const rec = _updateRun(root, curId, (rec) => {  // 1.9.303 (UR-0043): лқҪ м§Ғл ¬нҷ” RMW
      for (const [flag, key] of [['--files-read', 'files_read'], ['--files-changed', 'files_changed'], ['--commands', 'commands_run'], ['--tests', 'tests_run'], ['--errors', 'errors'], ['--decision', 'decisions']]) {
        const v = arg(flag, null); if (v) rec[key] = Array.from(new Set([...(rec[key] || []), ..._splitList(v)]));
      }
    });
    if (!rec) return fail(`run м—ҶмқҢ: ${curId}`);
    if (json) { log(JSON.stringify({ recorded: curId, run: rec }, null, 2)); return; }
    ok(`кё°лЎқ: ${curId} (files_changed ${rec.files_changed.length} В· commands ${rec.commands_run.length} В· tests ${rec.tests_run.length} В· decisions ${rec.decisions.length})`);
    return;
  }

  if (sub === 'verify') {
    const result = (arg('--result', '') || (args.find(a => a && !a.startsWith('-')) || '')).toLowerCase();
    if (result !== 'pass' && result !== 'fail') return fail('--result pass|fail н•„мҡ”');
    const note = arg('--note', null);
    const rec = _updateRun(root, curId, (rec) => {  // 1.9.303 (UR-0043): лқҪ м§Ғл ¬нҷ” RMW
      rec.verification_result = result;
      rec.status = result === 'pass' ? 'verified' : 'in-progress';
      if (note) rec.decisions = [...(rec.decisions || []), `verify(${result}): ${note}`];
    });
    if (!rec) return fail(`run м—ҶмқҢ: ${curId}`);
    if (json) { log(JSON.stringify({ verified: curId, result, run: rec, completion_claim_allowed: _completionClaimAllowed(rec) }, null, 2)); return; }
    (result === 'pass' ? ok : warn)(`кІҖмҰқ кІ°кіј: ${curId} вҶ’ ${result}`);
    return;
  }

  if (sub === 'handoff') {
    const summary = (args.find(a => a && !a.startsWith('-')) || arg('--summary', '')).trim();
    const rec = _updateRun(root, curId, (rec) => {  // 1.9.303 (UR-0043): лқҪ м§Ғл ¬нҷ” RMW
      rec.handoff_summary = summary || rec.handoff_summary || '(мҡ”м•Ҫ м—ҶмқҢ)';
      rec.ended_at = new Date().toISOString();
      rec.status = 'handed-off';
    });
    if (!rec) return fail(`run м—ҶмқҢ: ${curId}`);
    // лӢӨмқҢ м—җмқҙм „нҠёк°Җ мқҪмқ„ latest handoff (json + md)
    const hdir = path.join(_leernessStateDir(root), 'handoff'); mkdirp(hdir);
    // 1.9.443 (UR-0153): handoff evidence м—җ completion_claim_allowed нҸ¬н•Ё вҖ” лӢӨмқҢ м—җмқҙм „нҠё/PR мқҙ мҰқкұ° кІҢмқҙнҠёлҘј м§Ғм ‘ мқҪмқҢ.
    const _ccaH = _completionClaimAllowed(rec);
    writeUtf8(path.join(hdir, 'latest.json'), JSON.stringify({ ...rec, completion_claim_allowed: _ccaH }, null, 2) + '\n');
    writeUtf8(path.join(hdir, 'latest.md'),
      `# Handoff вҖ” ${rec.run_id}\n\n- task: ${rec.task_id || '-'}\n- agent: ${rec.agent_name || '-'} В· model: ${rec.model_name || '-'}\n- goal: ${rec.goal || '-'}\n- files_changed: ${rec.files_changed.join(', ') || '-'}\n- tests_run: ${rec.tests_run.join(', ') || '-'}\n- verification: ${rec.verification_result || '-'}\n- completion_claim_allowed: ${_ccaH.allowed ? 'yes' : 'no (' + _ccaH.reasons.join(', ') + ')'}\n\n## Summary\n${rec.handoff_summary}\n`);
    state.currentRunId = null;  // лӢӨмқҢ м—җмқҙм „нҠёк°Җ мғҲ run мӢңмһ‘
    _saveLeernessState(root, state);
    if (json) { log(JSON.stringify({ handoff: rec.run_id, run: rec, completion_claim_allowed: _ccaH }, null, 2)); return; }
    ok(`handoff мһ‘м„ұ: ${rec.run_id} вҶ’ .leerness/handoff/latest.{md,json}`);
    return;
  }

  // default: show
  const rec = curId ? _loadRun(root, curId) : null;
  // 1.9.443 (UR-0153): evidence-first мҷ„лЈҢ кІҢмқҙнҠё нҢҢмғқ л…ём¶ң.
  if (json) { log(JSON.stringify({ state, currentRun: rec, completion_claim_allowed: rec ? _completionClaimAllowed(rec) : null }, null, 2)); return; }
  log(`# leerness state (1.9.278, UR-0032) вҖ” .leerness/ кө¬мЎ°нҷ” мғҒнғң`);
  log(`project: ${state.project} В· runs лҲ„м Ғ: ${state.runCounter || 0} В· нҳ„мһ¬ run: ${curId || '(м—ҶмқҢ)'}`);
  if (rec) {
    log('');
    log(`## ${rec.run_id} [${rec.status}]`);
    log(`  goal: ${rec.goal || '-'}`);
    log(`  agent/model: ${rec.agent_name || '-'} / ${rec.model_name || '-'}`);
    log(`  files_changed: ${rec.files_changed.join(', ') || '-'}`);
    log(`  commands_run: ${rec.commands_run.join(', ') || '-'}`);
    log(`  tests_run: ${rec.tests_run.join(', ') || '-'} В· verification: ${rec.verification_result || '-'}`);
    if (rec.decisions.length) log(`  decisions: ${rec.decisions.length}`);
    const _cca = _completionClaimAllowed(rec);  // 1.9.443 (UR-0153): мҰқкұ° кё°л°ҳ мҷ„лЈҢ мЈјмһҘ к°ҖлҠҘ м—¬л¶Җ
    log(`  completion_claim_allowed: ${_cca.allowed ? 'yes вң“' : 'no вң— (' + _cca.reasons.join(', ') + ')'}`);
  } else {
    log(`  вҶ’ мӢңмһ‘: leerness state start "<goal>" [--agent claude --model claude-opus-4-7 --task T-0001]`);
  }
  return;
}

// ===== 1.9.280 (UR-0033, GPT-5.5 лІ”мҡ© н•ҳл„ӨмҠӨ): leerness adapter <tool> =====
//   лӘ©м Ғ: лҸ„кө¬лі„лЎң "н•„мҡ”н•ң м§Җм№Ё/м—°кІ° нҢҢмқјл§Ң" м„ нғқ мғқм„ұ (м „мІҙ init лҢҖмӢ ). --minimal + adapter мЎ°н•©мңјлЎң м№ЁнҲ¬м„ұвҶ“В·лІ”мҡ©м„ұвҶ‘.
//   MCP м§Җмӣҗ лҸ„кө¬лҠ” .mcp.json (leerness mcp serve л“ұлЎқ) лҸ„ мғқм„ұ вҶ’ UR-0031 мғҒнғң verb лҘј мҰүмӢң нҳём¶ң к°ҖлҠҘ.
//   нҢҢмқј н…ңн”ҢлҰҝмқҖ coreFiles() мһ¬мӮ¬мҡ©(лӢЁмқј м¶ңмІҳ). л№„нҢҢкҙҙ(writeIfSafe + mergeManaged).
// ADAPTERS вҶ’ lib/catalogs.js (1.9.295 UR-0025 4лӢЁкі„)
// _mcpJsonContent вҶ’ lib/pure-utils.js лЎң мқҙлҸҷ (1.9.283 UR-0025 2лӢЁкі„)
// .mcp.json лі‘н•© вҖ” кё°мЎҙ mcpServers ліҙмЎҙн•ҳкі  leerness н•ӯлӘ©л§Ң м¶”к°Җ/к°ұмӢ .
function _mergeMcpJson(root) {
  const f = path.join(absRoot(root), '.mcp.json');
  let obj = {};
  if (exists(f)) { try { obj = JSON.parse(read(f)); } catch { obj = {}; } }
  obj.mcpServers = obj.mcpServers || {};
  const already = !!obj.mcpServers.leerness;
  obj.mcpServers.leerness = { command: 'npx', args: ['leerness', 'mcp', 'serve'] };
  writeUtf8(f, JSON.stringify(obj, null, 2) + '\n');
  return { file: '.mcp.json', action: already ? 'updated' : 'created' };
}
function adapterCmd(root, tool, opts = {}) {
  root = absRoot(root || process.cwd());
  const json = has('--json');
  const dry = has('--dry-run') || opts.dryRun;
  if (!tool || tool === 'list') {
    if (json) { log(JSON.stringify({ adapters: Object.fromEntries(Object.entries(ADAPTERS).map(([k, v]) => [k, { label: v.label, files: v.keys, mcp: v.mcp }])) }, null, 2)); return; }
    log(`# leerness adapter (1.9.280, UR-0033) вҖ” лҸ„кө¬лі„ м„ нғқ м„Өм№ҳ`);
    log(`  init м „мІҙ лҢҖмӢ  нҠ№м • лҸ„кө¬мқҳ м§Җм№Ё/м—°кІ° нҢҢмқјл§Ң мғқм„ұн•©лӢҲлӢӨ. (к¶ҢмһҘ: leerness init . --minimal нӣ„ adapter)`);
    log('');
    for (const [id, a] of Object.entries(ADAPTERS)) {
      log(`  ${id.padEnd(9)} ${a.label}${a.mcp ? '  [+.mcp.json]' : ''}`);
      log(`     ${a.keys.join(', ')}`);
    }
    log(`\n  мӮ¬мҡ©: leerness adapter <tool> [--dry-run]`);
    return;
  }
  const a = ADAPTERS[tool];
  if (!a) return fail(`м•Ң мҲҳ м—ҶлҠ” adapter: ${tool} (к°ҖлҠҘ: ${Object.keys(ADAPTERS).join(', ')})`);
  const lang = exists(path.join(root, '.harness/LANGUAGE')) ? read(path.join(root, '.harness/LANGUAGE')).trim() : 'ko';
  const files = coreFiles(root, lang === 'en' ? 'en' : 'ko', []);
  const managedOverwrite = new Set(['AGENTS.md', 'CLAUDE.md', '.cursor/rules/leerness.mdc', '.github/copilot-instructions.md']);
  const planned = a.keys.filter(k => files[k] != null);
  if (a.mcp) planned.push('.mcp.json');
  if (dry) {
    if (json) { log(JSON.stringify({ adapter: tool, dryRun: true, files: planned }, null, 2)); return; }
    log(`# leerness adapter ${tool} [dry-run] вҖ” мғқм„ұ/к°ұмӢ  мҳҲм • ${planned.length}к°ң (мӢӨм ң ліҖкІҪ 0)`);
    planned.forEach(f => log(`  - ${f}`));
    log(`  вҶ’ мӢӨм ң м Ғмҡ©: leerness adapter ${tool}`);
    return;
  }
  const results = [];
  for (const k of a.keys) {
    if (files[k] == null) continue;
    results.push(writeIfSafe(root, k, files[k], { mergeManaged: managedOverwrite.has(k) }));
  }
  if (a.mcp) results.push(_mergeMcpJson(root));
  if (json) { log(JSON.stringify({ adapter: tool, files: results }, null, 2)); return; }
  ok(`adapter ${tool} (${a.label}) м Ғмҡ© вҖ” ${results.length}к°ң нҢҢмқј`);
  for (const r of results) log(`  ${r.action}: ${r.file}`);
  if (a.mcp) log(`  в„№ .mcp.json л“ұлЎқ вҖ” мқҙ лҸ„кө¬к°Җ leerness MCP verb(state_show/start/record/verify/handoff)лҘј м§Ғм ‘ нҳём¶ң к°ҖлҠҘ`);
  return;
}

// ===== 1.9.285 (UR-0023, GPT-5.5): мҷёл¶Җ OSS "л№Ңл“ң vs мһ¬мӮ¬мҡ©" кІ°м • кІҢмқҙнҠё =====
//   кё°лҠҘ кі„нҡҚ мӢң "мқҙлҜё кІҖмҰқлҗң OSS к°Җ мһҲлҠ”лҚ° мғҲлЎң л§Ңл“ңлҠ”к°Җ?" лҘј л¬»лҠ” мҳӨн”„лқјмқё кө¬мЎ°м Ғ кІҢмқҙнҠё.
//   л„ӨнҠёмӣҢнҒ¬ нҒ¬лЎӨлҹ¬к°Җ м•„лӢҳ(offline-first мң м§Җ) вҖ” нҳёмҠӨнҠё AI(л©”мқё)к°Җ мӢӨм ң OSS нғҗмғүмқ„ н•ҳлҗҳ, мқҙ кІҢмқҙнҠёк°Җ
//   м№ҙн…Ңкі лҰ¬ нӣ„ліҙ + м Ғн•©м„ұ мІҙнҒ¬лҰ¬мҠӨнҠёлҘј м ңкіөн•ҙ "мһ¬мӮ¬мҡ© кІҖнҶ  мғқлһө"мқ„ л°©м§Җ. кё°мЎҙ `reuse`(лӮҙл¶Җ мһҗмӣҗ)мҷҖ кө¬л¶„.
// REUSE_CATEGORIES вҶ’ lib/catalogs.js (1.9.295 UR-0025 4лӢЁкі„)
function _reuseDetect(feature) {
  const t = String(feature || '').toLowerCase();
  return REUSE_CATEGORIES.filter(c => c.kw.some(k => t.includes(k)));
}
// REUSE_CHECKLIST вҶ’ lib/catalogs.js (1.9.295 UR-0025 4лӢЁкі„)
function reuseCheckCmd(root, feature, opts = {}) {
  const json = has('--json');
  feature = String(feature || '').trim();
  if (!feature) { fail('reuse-check "<кө¬нҳ„н•ҳл ӨлҠ” кё°лҠҘ>" н•„мҡ” (мҳҲ: leerness reuse-check "JWT мқёмҰқ")'); process.exitCode = 1; return; }
  const matched = _reuseDetect(feature);
  if (json) {
    log(JSON.stringify({ feature, categories: matched.map(c => ({ key: c.key, candidates: c.candidates })), checklist: REUSE_CHECKLIST, network: false, note: 'мҳӨн”„лқјмқё кІҢмқҙнҠё вҖ” мӢӨм ң OSS нғҗмғү/кІҖмҰқмқҖ нҳёмҠӨнҠё AI(GitHub/HuggingFace л“ұ)к°Җ мҲҳн–ү' }, null, 2));
    return;
  }
  const isTty = process.stdout && process.stdout.isTTY;
  const cy = s => isTty ? `\x1b[36m${s}\x1b[0m` : s;
  const dm = s => isTty ? `\x1b[2m${s}\x1b[0m` : s;
  log(cy(`# leerness reuse-check (1.9.285, UR-0023) вҖ” л№Ңл“ң vs мһ¬мӮ¬мҡ© кІ°м • кІҢмқҙнҠё`));
  log(`кё°лҠҘ: ${feature}`);
  log('');
  if (matched.length) {
    log(`## лЁјм Җ кІҖнҶ н•  OSS м№ҙн…Ңкі лҰ¬ (${matched.length})`);
    for (const c of matched) log(`  вҖў ${c.key.padEnd(11)} нӣ„ліҙ: ${c.candidates}`);
  } else {
    log(`## мқјл°ҳ м№ҙн…Ңкі лҰ¬ лҜёл§Өм№ӯ вҖ” к·ёлһҳлҸ„ м•„лһҳлҘј кІҖнҶ `);
    log(dm(`  GitHub/HuggingFace/awesome-* лӘ©лЎқм—җм„ң мң мӮ¬ кө¬нҳ„мқ„ лЁјм Җ кІҖмғүн•ҳм„ёмҡ”.`));
  }
  log('');
  log(`## м Ғн•©м„ұ мІҙнҒ¬лҰ¬мҠӨнҠё (мһ¬мӮ¬мҡ© кІ°м • м „)`);
  for (const q of REUSE_CHECKLIST) log(`  [ ] ${q}`);
  log('');
  log(`## кІ°м •`);
  log(`  вҶ’ мң„ мІҙнҒ¬ нҶөкіјн•ҳлҠ” OSS к°Җ мһҲмңјл©ҙ мһ¬мӮ¬мҡ©, м—Ҷмңјл©ҙ мӢ к·ң кө¬нҳ„ (мқҙмң лҘј .harness/reuse-map.md лҳҗлҠ” decisions м—җ кё°лЎқ).`);
  log(dm(`  вҖ» мҳӨн”„лқјмқё кІҢмқҙнҠёмһ…лӢҲлӢӨ. мӢӨм ң GitHub/HuggingFace нғҗмғүВ·кІҖмҰқмқҖ нҳёмҠӨнҠё AI к°Җ мҲҳн–үн•ҳм„ёмҡ” (leerness лҠ” л„ӨнҠёмӣҢнҒ¬ мһҗлҸҷ нҳём¶ң м•Ҳ н•Ё).`));
  return;
}

// ===== 1.9.286 (UR-0024, GPT-5.5): мҠӨнӮ¬ м„Өм№ҳ мҳҒн–Ҙ кІҪлҹү мғҒкҙҖм¶”м Ғ =====
//   "м„Өм№ҳн•ң мҠӨнӮ¬мқҙ мҪ”л”© м„ұлҠҘ/м •нҷ•лҸ„м—җ кёҚм • мҳҒн–Ҙ?" вҖ” л¬ҙкұ°мҡҙ лІӨм№ҳ harness к°Җ м•„лӢҲлқј, кё°мЎҙ лҚ°мқҙн„°
//   (skill мӮ¬мҡ© л№ҲлҸ„ + review-evidence кІҖмҰқ нҶөкіјмңЁ)лҘј мғҒкҙҖ(мқёкіј м•„лӢҳ)мңјлЎң advisory м ңмӢң. offline.
// review-evidence.md нҢҢмӢұ (мҲңмҲҳ) вҖ” кІҖмҰқ н•ӯлӘ© мҲҳ + pass/fail м¶”м • (Exit 0 / 'PASS' vs 'fail'/Exit !=0).
// _parseEvidenceStats вҶ’ lib/analyzers.js (1.9.304 UR-0025)
function skillImpactCmd(root) {
  root = absRoot(root || process.cwd());
  const json = has('--json');
  // м„Өм№ҳ мҠӨнӮ¬ + мӮ¬мҡ© л№ҲлҸ„ (skill-suggestions.md rolling history мқҳ id м–ёкёү м№ҙмҡҙнҠё)
  let skills = [];
  try { skills = Object.entries(listAllSkills(root)).map(([k, s]) => ({ id: (s && (s.id || s.name)) || k, name: (s && (s.displayNameKo || s.name)) || k })).filter(s => s.id); } catch {}
  const histPath = path.join(absRoot(root), '.harness', 'skill-suggestions.md');
  const hist = exists(histPath) ? read(histPath) : '';
  const uses = {};
  for (const s of skills) { const re = new RegExp(String(s.id).replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g'); uses[s.id] = (hist.match(re) || []).length; }
  const ranked = skills.map(s => ({ ...s, uses: uses[s.id] || 0 })).sort((a, b) => b.uses - a.uses);
  const ev = _parseEvidenceStats(exists(evidencePath(root)) ? read(evidencePath(root)) : '');
  const sampleSize = ev.entries;
  const advisory = sampleSize < 5
    ? 'н‘ңліё л¶ҖмЎұ (кІҖмҰқ кё°лЎқ < 5) вҖ” нҢҗлӢЁ ліҙлҘҳ. лҚ” л§ҺмқҖ verify-code лҲ„м Ғ нӣ„ мһ¬нҷ•мқё.'
    : 'мғҒкҙҖм¶”м Ғ(мқёкіј м•„лӢҳ): мҠӨнӮ¬ мӮ¬мҡ© л№ҲлҸ„мҷҖ кІҖмҰқ нҶөкіјмңЁмқҖ м°ёкі  мӢ нҳёмқј лҝҗ, мқёкіјкҙҖкі„лҘј ліҙмһҘн•ҳм§Җ м•ҠмқҢ.';
  if (json) { log(JSON.stringify({ skills: ranked, usedCount: ranked.filter(s => s.uses > 0).length, evidence: ev, sampleSize, advisory, network: false }, null, 2)); return; }
  const isTty = process.stdout && process.stdout.isTTY;
  const cy = s => isTty ? `\x1b[36m${s}\x1b[0m` : s; const dm = s => isTty ? `\x1b[2m${s}\x1b[0m` : s;
  log(cy(`# leerness skill impact (1.9.286, UR-0024) вҖ” мҠӨнӮ¬ мҳҒн–Ҙ кІҪлҹү мғҒкҙҖм¶”м Ғ`));
  log(`м„Өм№ҳ мҠӨнӮ¬: ${skills.length} В· мӮ¬мҡ© мқҙл Ҙ мһҲлҠ” мҠӨнӮ¬: ${ranked.filter(s => s.uses > 0).length}`);
  log(`кІҖмҰқ кё°лЎқ(review-evidence): ${ev.entries}кұҙ В· нҶөкіјмңЁ: ${ev.rate === null ? 'N/A' : ev.rate + '%'} (pass ${ev.pass} / fail ${ev.fail})`);
  if (ranked.filter(s => s.uses > 0).length) {
    log('');
    log(`## мӮ¬мҡ© л№ҲлҸ„ top (skill-suggestions мқҙл Ҙ)`);
    for (const s of ranked.filter(x => x.uses > 0).slice(0, 8)) log(`  ${String(s.uses).padStart(3)}Г— ${s.id} ${dm(s.name)}`);
  }
  log('');
  log(dm(`  вҡ  ${advisory}`));
  log(dm(`  вҖ» HuggingFace/мҷёл¶Җ мҠӨнӮ¬ мҶҢмҠӨ нғҗмғүмқҖ нҳёмҠӨнҠё AI к°Җ мҲҳн–ү (leerness лҠ” л„ӨнҠёмӣҢнҒ¬ мһҗлҸҷ нҳём¶ң м•Ҳ н•Ё).`));
  return;
}

// 1.9.149+1.9.153: REPL лӘЁл“ң вҖ” leerness мһҗмңЁ AI м—җмқҙм „нҠё (multi-provider м„ём…ҳ)
async function _agentRepl(root, opts) {
  // 1.9.153: .env мһҗлҸҷ лЎңл“ң (REPL м§„мһ… м§Ғм „) вҖ” install м§Ғнӣ„ LEERNESS_ENABLE_* мҰүмӢң л°ҳмҳҒ
  try { _loadEnvFile(root); } catch {}
  const readline = require('readline');
  // 1.9.180: completer no-op вҖ” readline мқҳ Tab completion к°ҖлЎңмұ„кё°лҘј м°ЁлӢЁн•ҙ keypress лҰ¬мҠӨл„Ҳк°Җ Tab cycleмқ„ мІҳлҰ¬.
  //   (мӮ¬мҡ©мһҗ лӘ…мӢң: "лӘЁлҚё/н”„лЎңл°”мқҙлҚ” м „нҷҳмқҙ мӣҗнҷңн•ҳм§Җ м•ҠлӢӨ" вҖ” readline Tab completionмқҙ cycle нӮӨлҘј к°ҖлЎңмұ„лҠ” кІҪмҡ° fix)
  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
    completer: (line) => [[], line]  // л№Ҳ completion + мӣҗліё line л°ҳнҷҳ вҶ’ TabмқҖ keypress лҰ¬мҠӨл„ҲлЎңл§Ң мІҳлҰ¬
  });
  const isTty = process.stdout.isTTY;
  const C = isTty ? {
    cy: s => `\x1b[36m${s}\x1b[0m`, dim: s => `\x1b[2m${s}\x1b[0m`,
    bold: s => `\x1b[1m${s}\x1b[0m`, green: s => `\x1b[32m${s}\x1b[0m`,
    yel: s => `\x1b[33m${s}\x1b[0m`, mag: s => `\x1b[35m${s}\x1b[0m`
  } : { cy:s=>s, dim:s=>s, bold:s=>s, green:s=>s, yel:s=>s, mag:s=>s };
  // 1.9.181 fix: provider мһҗлҸҷ м„ нғқ вҖ” prompt лӢЁкі„ м ңкұ°н•ҳкі  мҰүмӢң мұ„нҢ… лӘЁл“ң м§„мһ… (мӮ¬мҡ©мһҗ лӘ…мӢң).
  //   м •мұ…: л№„-Ollama нҷңм„ұ CLI мҡ°м„  вҶ’ Ollama вҶ’ fallback. ліөмҲҳ нҷңм„ұ мӢң prompt м—Ҷмқҙ мІ« л№„-Ollama мһҗлҸҷ м„ нғқ.
  //   мӮ¬мҡ©мһҗ мқҳлҸ„: "н”„лЎңл°”мқҙлҚ” м „нҷҳ м„ нғқ лӢЁкі„м—Ҷмқҙ л°”лЎң мұ„нҢ… лӘЁл“ңлЎң м§„мһ…н•ҙлҸ„ лҗ кұ°к°ҷм•„" + "OllamaлҘј мҡ°м„  нҳём¶ң X".
  //   Tab мңјлЎң м–ём ңл“  cycle к°ҖлҠҘн•ҳлҜҖлЎң мһҗлҸҷ м„ нғқн•ҙлҸ„ мӮ¬мҡ©мһҗк°Җ мҰүмӢң м „нҷҳ к°ҖлҠҘ.
  let initialProvider = opts.provider;
  let _autoPickNote = '';
  if (!initialProvider) {
    const ready = EXTERNAL_AGENTS.map(a => ({ def: a, status: _checkAgent(a) }))
                                  .filter(x => x.status.status === 'ready');
    const nonOllama = ready.filter(x => x.def.id !== 'ollama');
    if (nonOllama.length >= 1) {
      // л№„-Ollama нҷңм„ұ вҶ’ мІ« лІҲм§ё мһҗлҸҷ (мӮ¬мҡ©мһҗ лӘ…мӢң: Ollama мҡ°м„  нҳём¶ң X)
      initialProvider = nonOllama[0].def.id;
      _autoPickNote = nonOllama.length === 1
        ? `${initialProvider} мһҗлҸҷ м„ нғқ (нҷңм„ұ CLI 1к°ң)`
        : `${initialProvider} мһҗлҸҷ м„ нғқ (нҷңм„ұ CLI ${nonOllama.length}к°ң В· TabмңјлЎң м „нҷҳ)`;
    } else if (ready.length === 1) {
      initialProvider = ready[0].def.id;  // ollama лӢЁлҸ…
      _autoPickNote = `${initialProvider} мһҗлҸҷ м„ нғқ`;
    } else {
      initialProvider = 'ollama';  // нҷңм„ұ 0к°ң вҶ’ fallback
      _autoPickNote = 'fallback ollama (нҷңм„ұ CLI м—ҶмқҢ вҖ” .env м—җм„ң LEERNESS_ENABLE_* нҷңм„ұнҷ” к¶ҢмһҘ)';
    }
  }
  // м„ём…ҳ state
  let state = {
    provider: initialProvider,
    model: opts.model || process.env.LEERNESS_OLLAMA_MODEL || null,
    role: opts.role || 'actor',
    history: [],   // [{role: 'user'|'assistant', content: ''}]
    startedAt: new Date().toISOString(),
    sessionId: 'sess-' + new Date().toISOString().replace(/[:.]/g, '-'),
    // 1.9.170: мӢӨмӢңк°„ мҠӨнҠёлҰ¬л°Қ лӘЁл“ң (мӮ¬мҡ©мһҗ лӘ…мӢң вҖ” м¶”лЎ мӨ‘/diff/thinking мӢӨмӢңк°„ н‘ңмӢң)
    streamMode: opts.stream !== false,  // default ON (env лЎң лҒ„л Өл©ҙ LEERNESS_REPL_STREAM=0)
    // 1.9.247 (UR-0016 2лӢЁкі„): multi-provider auto-fallback вҖ” default OFF (opt-in)
    autoFallback: opts.autoFallback === true || process.env.LEERNESS_REPL_AUTO_FALLBACK === '1'
  };
  if (process.env.LEERNESS_REPL_STREAM === '0') state.streamMode = false;
  const sessionPath = () => path.join(absRoot(root), '.harness', 'agent-sessions', `${state.sessionId}.jsonl`);
  const saveSession = () => {
    try {
      mkdirp(path.dirname(sessionPath()));
      const lines = state.history.map(m => JSON.stringify({ at: new Date().toISOString(), ...m })).join('\n');
      writeUtf8(sessionPath(), lines + '\n');
    } catch {}
  };
  // 1.9.179: нҷҳмҳҒ нҷ”л©ҙ мһ¬л””мһҗмқё (мӮ¬мҡ©мһҗ лӘ…мӢң вҖ” Hermes/Claude/Codex/Gemini мҠӨнғҖмқј).
  //   кё°мЎҙ лӢЁмҲң л°•мҠӨ вҶ’ н—ӨлҚ” л°•мҠӨ + Tips / What's new л°•мҠӨ + Slash м№ҙнғҲлЎңк·ё 5 к·ёлЈ№.
  const today = new Date().toISOString().slice(0, 10);
  const wsName = path.basename(absRoot(root));
  log('');
  log(C.bold(C.cy('  в•ӯв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв•®')));
  log(C.bold(C.cy(`  в”Ӯ  Leerness Agent  v${VERSION}  (${today})  В·  кІҖмҲҳВ·кё°м–өВ·мғҢл“ңл°•мҠӨ нҶөн•© AI  в”Ӯ`)));
  log(C.bold(C.cy('  в•°в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв•Ҝ')));
  log('');
  log(C.dim(`  в–ё Welcome back  В·  ${wsName} (${rel(process.cwd(), absRoot(root))})`));
  log(C.dim(`  в–ё Session: ${state.sessionId}`));
  if (_autoPickNote) log(C.dim(`  в–ё Provider: ${_autoPickNote}`));
  log('');
  // 1.9.181 fix: provider м§„мһ… мӢңм җ prompt лӢЁкі„ м ңкұ° вҖ” мһҗлҸҷ м „нҷҳл§Ң мҲҳн–ү (мӮ¬мҡ©мһҗ лӘ…мӢң вҖ” л°”лЎң мұ„нҢ… лӘЁл“ң м§„мһ…).
  if (state.provider === 'ollama' && !state.model) {
    // Ollama мӮ¬мҡ© к°ҖлҠҘ вҶ’ мІ« лӘЁлҚё мһҗлҸҷ м„ нғқ (мӮ¬мҡ©мһҗ prompt м—ҶмқҢ)
    const r = await _ollamaListModels();
    if (r.ok && r.models.length) {
      state.model = process.env.LEERNESS_OLLAMA_MODEL || r.models[0];
      log(C.dim(`  в–ё Model: ${state.model}  (Ollama ${r.models.length}к°ң catalog В· Shift+TabмңјлЎң ліҖкІҪ)`));
    } else {
      // Ollama лҜёк°ҖлҸҷ вҶ’ л№„-Ollama нҷңм„ұ CLI к°Җ мһҲмңјл©ҙ мһҗлҸҷ м „нҷҳ, м—Ҷмңјл©ҙ fallback ollama (warn)
      const readyCli = EXTERNAL_AGENTS.filter(a => a.id !== 'ollama')
                                       .map(a => ({ def: a, status: _checkAgent(a) }))
                                       .filter(x => x.status.status === 'ready');
      if (readyCli.length) {
        state.provider = readyCli[0].def.id;
        state.model = null;
        log(C.green(`  в–ё Ollama лҜёк°ҖлҸҷ вҶ’ ${state.provider} мһҗлҸҷ м „нҷҳ (TabмңјлЎң лӢӨлҘё provider м „нҷҳ к°ҖлҠҘ)`));
      } else {
        state.model = process.env.LEERNESS_OLLAMA_MODEL || 'llama3';
        log(C.yel(`  вҡ  Ollama лҜёк°ҖлҸҷ + нҷңм„ұ CLI м—ҶмқҢ вҖ” fallback ${state.model} (мӢӨ нҳём¶ң мӢӨнҢЁ мӢң :quit лҳҗлҠ” :provider)`));
      }
    }
  }
  // 1.9.179: Tips + What's new л°•мҠӨ (мӮ¬мҡ©мһҗ лӘ…мӢң вҖ” мІЁл¶Җ мқҙлҜём§Җ spirit л°ҳмҳҒ)
  log('');
  log(C.bold(C.yel('  в”Ңв”Җ Tips for getting started в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ')));
  log(C.yel('  в”Ӯ  ') + C.dim('Tab / Shift+Tab') + '   ' + C.dim('вҖ” provider / model м „нҷҳ (1.9.170)') + C.yel(' '.repeat(Math.max(1, 17)) + 'в”Ӯ'));
  log(C.yel('  в”Ӯ  ') + C.dim(':review "<req>"') + '   ' + C.dim('вҖ” л¬ҙмЎ°кұҙ кө¬нҳ„ м „ мӮ¬м „ кІҖнҶ  (1.9.176)') + C.yel(' '.repeat(Math.max(1, 13)) + 'в”Ӯ'));
  log(C.yel('  в”Ӯ  ') + C.dim(':permissions <m>') + '  ' + C.dim('вҖ” мҰүмӢң к¶Ңн•ң ліҖкІҪ basic|extended|full (1.9.174)') + C.yel(' в”Ӯ'));
  log(C.yel('  в”Ӯ  ') + C.dim(':stream on|off') + '    ' + C.dim('вҖ” мӢӨмӢңк°„ мҠӨнҠёлҰ¬л°Қ нҶ кёҖ (default ON, 1.9.170/172)') + C.yel(' в”Ӯ'));
  log(C.bold(C.yel('  в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ')));
  log('');
  log(C.bold(C.green('  в”Ңв”Җ What\'s new (1.9.170~178) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”җ')));
  log(C.green('  в”Ӯ  ') + C.dim('вҖў REPL Tab cycle + мӢӨмӢңк°„ мҠӨнҠёлҰ¬л°Қ (spinner / tool_use / diff мғүк№”)') + C.green('  в”Ӯ'));
  log(C.green('  в”Ӯ  ') + C.dim('вҖў Bridge slash :web/:pc/:lsp REPL мҰүмӢң нҳём¶ң + LSP лӢӨкөӯм–ҙ 5мў…') + C.green('        в”Ӯ'));
  log(C.green('  в”Ӯ  ') + C.dim('вҖў review-request мӮ¬м „ кІҖнҶ  + task add мһҗлҸҷ trigger') + C.green('                  в”Ӯ'));
  log(C.green('  в”Ӯ  ') + C.dim('вҖў release sync-main мһҗлҸҷ npm publish (.env NPM_TOKEN)') + C.green('               в”Ӯ'));
  log(C.green('  в”Ӯ  ') + C.dim('вҖў 6 лҠҘл Ҙ л§ӨнҠёлҰӯмҠӨ 72% production-ready В· MCP 54 лҸ„кө¬') + C.green('               в”Ӯ'));
  log(C.bold(C.green('  в””в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”ҳ')));
  log('');
  log(C.bold('  Available Slash (5 к·ёлЈ№)'));
  log(C.dim('    вҖў meta:        ') + ':help :model :role :provider :status :stream :clear :quit');
  log(C.dim('    вҖў internal:    ') + ':verify :audit :handoff :health');
  log(C.dim('    вҖў memory:      ') + ':lessons :brainstorm :tasks :plan');
  log(C.dim('    вҖў bridge:      ') + ':web :pc :lsp ' + C.dim('(к°Ғ sub: check/symbols/click/screenshot/...)'));
  log(C.dim('    вҖў review:      ') + ':review "<request>"  В·  :permissions [basic|extended|full]');
  log('');
  log(C.dim('  вҢЁ  Tab=provider cycle  В·  Shift+Tab=model  В·  Ctrl+C=quit'));
  log('');
  // 1.9.188 (мӮ¬мҡ©мһҗ лӘ…мӢң): state.model мқҙ л№„м–ҙмһҲмңјл©ҙ catalog мІ« лӘЁлҚё мһҗлҸҷ м„Өм • вҶ’ м„ёл¶Җ лӘЁлҚё н‘ңмӢң.
  //   "model=(кё°ліё)" к°ҷмқҖ лӘЁнҳён•ң н‘ңмӢң лҢҖмӢ  мӢӨм ң мӮ¬мҡ©лҗ  лӘЁлҚё мқҙлҰ„ (мҳҲ: claude-opus-4-7) лӘ…мӢң.
  if (!state.model) {
    const cat = _PROVIDER_MODEL_CATALOG[state.provider];
    if (cat && cat.length) state.model = cat[0].id;
  }
  // 1.9.179+1.9.188: мғҒнғңл°” н•ң мӨ„ вҖ” м„ёл¶Җ лӘЁлҚё + мғүк№”/кө¬л¶„мһҗ к°•нҷ”
  const permMode = _readPermissions(root).mode || 'basic';
  log('  ' + C.bold('вҡЎ ') + C.cy(`provider=${state.provider}`) + '  В·  '
    + C.mag(`model=${state.model || '(unknown)'}`) + '  В·  '
    + C.green(`role=${state.role}`) + '  В·  '
    + C.yel(`perms=${permMode}`) + '  В·  '
    + (state.streamMode ? C.green('в–¶ stream=on') : C.dim('в–Ў stream=off')));
  // 1.9.180: мұ„нҢ… мҳҒм—ӯ м§„мһ… separator (мӮ¬мҡ©мһҗ лӘ…мӢң вҖ” "кі м • н—ӨлҚ” + мұ„нҢ… нҳ•мӢқ")
  //   нҷҳмҳҒ нҷ”л©ҙ лҒқм—җ лӘ…нҷ•н•ң кө¬л¶„м„  + м•ҲлӮҙ вҶ’ мұ„нҢ… мӢңмһ‘ лӘ…нҷ•.
  log('');
  log(C.dim('  в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ  мұ„нҢ… мӢңмһ‘  в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ'));
  log(C.dim('  л©”мӢңм§Җ мһ…л Ҙ нӣ„ Enter В· ') + C.cy('"/"') + C.dim(' мһ…л Ҙ мӢң лӘ…л № list В· ') + C.cy(':help') + C.dim(' мңјлЎңлҸ„ к°ҖлҠҘ В· Ctrl+C лЎң мў…лЈҢ'));
  // 1.9.155: REPL м§„мһ… мӢң handoff м»Ён…ҚмҠӨнҠё мһҗлҸҷ л…ём¶ң (UX к°ңм„  вҖ” мӮ¬мҡ©мһҗк°Җ л§ӨлІҲ :handoff м•Ҳ н•ҙлҸ„ м»Ён…ҚмҠӨнҠё мқём§Җ)
  try {
    const hf = cp.spawnSync(process.execPath, [__filename, 'handoff', root, '--compact', '--no-drift-check', '--no-headline'], {
      encoding: 'utf8', timeout: 8000,
      env: { ...process.env, LEERNESS_INTERNAL: '1', LEERNESS_NO_BANNER: '1', LEERNESS_NO_PROMPT: '1', LEERNESS_NO_DRIFT_CHECK: '1', LEERNESS_NO_LESSONS: '1' }
    });
    if (hf.status === 0 && hf.stdout) {
      const preview = hf.stdout.split('\n').slice(0, 4).map(l => l.replace(/^\s+/, '')).filter(Boolean).slice(0, 3).join(' В· ');
      if (preview) {
        log('');
        log(C.dim(`  рҹ“Қ context: ${preview.slice(0, 220)}${preview.length > 220 ? 'вҖҰ' : ''}`));
      }
    }
  } catch {}
  log('');
  // 1.9.188 (мӮ¬мҡ©мһҗ лӘ…мӢң): prompt мң„/м•„лһҳ кө¬л¶„м„  + м„ёл¶Җ лӘЁлҚё лӘ…мӢң (мӮ¬мҡ©мһҗ мһ…л Ҙм№ё мӢңк°Ғ к°•мЎ°).
  //   л§Ө мқ‘лӢө м§Ғнӣ„ readline.question нҳём¶ң м „м—җ _printInputDivider() нҳём¶ңн•ҳм—¬ мһ…л Ҙ мҳҒм—ӯ лӘ…нҷ•нҷ”.
  const _termCols = () => {
    try { return Math.max(40, (process.stdout.columns || 80)); } catch { return 80; }
  };
  const _printInputDivider = () => {
    if (!isTty) return;
    const cols = _termCols();
    const line = 'в”Җ'.repeat(Math.min(cols - 4, 120));
    process.stdout.write('\n' + C.dim('  ' + line) + '\n');
  };
  // prompt м—җ м„ёл¶Җ лӘЁлҚё н‘ңмӢң (мӮ¬мҡ©мһҗ лӘ…мӢң): agent[claude В· claude-opus-4-7 / actor / в–¶]>
  const prompt = () => {
    if (!isTty) return 'agent> ';
    const modelShort = (state.model || '').replace(/^(claude|gpt|gemini|antigravity)-/, '').slice(0, 18);
    const modelTag = modelShort ? C.dim(' В· ') + C.mag(modelShort) : '';
    return C.cy(`agent[${state.provider}${modelTag}${C.cy('/' + state.role)}${state.streamMode ? C.cy('/в–¶') : ''}${C.cy(']>')} `);
  };
  // 1.9.246: REPL UX/UI к°ңм„  (мӮ¬мҡ©мһҗ лӘ…мӢң UR-0016) вҖ” м»Ён…ҚмҠӨнҠё кІҢмқҙм§Җ + м„ңлёҢ м—җмқҙм „нҠё к°ҖмӢңнҷ” + м •мғҒ мһ‘м—… к°•мЎ°
  //   3мў… нҶөн•© status barлҘј мұ„нҢ… мһ…л Ҙм№ё м§Ғм „м—җ н‘ңмӢң.
  const _maxContextTokens = (provider, model) => {
    // provider/model лі„ м»Ён…ҚмҠӨнҠё мңҲлҸ„мҡ° (лҢҖлһөк°’, мӮ¬мҡ©мһҗ м •ліҙ м ңкіөмҡ©)
    const m = (model || '').toLowerCase();
    if (provider === 'claude') {
      if (m.includes('opus-4-7') || m.includes('sonnet-4-7') || m.includes('4-7')) return 1000000; // 1M extended
      if (m.includes('opus') || m.includes('sonnet') || m.includes('haiku')) return 200000;
      return 200000;
    }
    if (provider === 'codex' || provider === 'openai') {
      if (m.includes('gpt-5') || m.includes('5.5')) return 200000;
      if (m.includes('gpt-4-1') || m.includes('4.1')) return 1000000;
      if (m.includes('gpt-4')) return 128000;
      return 128000;
    }
    if (provider === 'agy') return 1000000;       // 2Mк№Ңм§Җ к°ҖлҠҘн•ҳм§Җл§Ң ліҙмҲҳм ҒмңјлЎң 1M
    if (provider === 'copilot') return 64000;
    if (provider === 'ollama') return 8000;          // лӘЁлҚёлі„ лӢӨлҘҙлӮҳ default 8k
    return 100000;
  };
  const _estimateTokens = (history) => {
    // лӢЁмҲң нңҙлҰ¬мҠӨнӢұ: мҳҒл¬ё 4chars=1tok, CJK 2chars=1tok нҸүк· м№ҳ вҶ’ 3.5chars/tok
    let totalChars = 0;
    for (const m of (history || [])) totalChars += (m.content || '').length;
    return Math.round(totalChars / 3.5);
  };
  const _renderStatusBar = () => {
    if (!isTty) return;
    try {
      // (1) м»Ён…ҚмҠӨнҠё кІҢмқҙм§Җ
      const msgs = (state.history || []).length;
      const tokens = _estimateTokens(state.history);
      const maxTok = _maxContextTokens(state.provider, state.model);
      const ratio = Math.min(1, tokens / maxTok);
      const pct = Math.round(ratio * 100);
      const barWidth = 14;
      const filled = Math.round(ratio * barWidth);
      const bar = 'в–Ҳ'.repeat(filled) + 'в–‘'.repeat(barWidth - filled);
      const barColor = pct >= 80 ? C.yel : (pct >= 50 ? C.cy : C.green);
      const tokStr = tokens >= 1000 ? `${(tokens / 1000).toFixed(1)}k` : `${tokens}`;
      const maxStr = maxTok >= 1000 ? `${Math.round(maxTok / 1000)}k` : `${maxTok}`;
      // (2) м„ңлёҢ м—җмқҙм „нҠё нҷңм„ұнҷ” вҖ” EXTERNAL_AGENTS 5мў… + ollama
      let ready = [];
      try {
        ready = EXTERNAL_AGENTS
          .map(a => ({ id: a.id, st: _checkAgent(a).status }))
          .filter(x => x.st === 'ready');
      } catch {}
      const allAgents = ['claude', 'codex', 'agy', 'copilot'];
      const subBar = allAgents.map(id => {
        if (id === state.provider) return C.bold(C.green(`*${id}`));
        const isReady = ready.find(r => r.id === id);
        return isReady ? C.green(`вң“${id}`) : C.dim(`В·${id}`);
      }).join(' ');
      // (3) н•ң мӨ„ м¶ңл Ҙ
      const line = '  ' + C.dim('рҹ’¬ ctx ') + C.bold(`${msgs}msg`) + C.dim(` ~${tokStr}/${maxStr} `) + barColor(bar) + C.dim(` ${pct}%`)
                 + C.dim('  В·  agents: ') + subBar
                 + C.dim('  В·  ') + (state.streamMode ? C.green('в–¶stream') : C.dim('в–Ўstream'));
      process.stdout.write(line + '\n');
    } catch {}
  };
  // 1.9.246: rl.prompt() wrapper вҖ” status bar мһҗлҸҷ н‘ңмӢң (мӮ¬мҡ©мһҗ лӘ…мӢң UR-0016)
  const promptWithStatus = (forceRedraw) => {
    _renderStatusBar();
    if (forceRedraw === true) rl.prompt(true);
    else rl.prompt();
  };
  rl.setPrompt(prompt());

  // 1.9.244 HOTFIX: _lastCycleLines лҘј outer мҠӨмҪ”н”„лЎң hoist
  //   1.9.189 нҡҢк·Җ лІ„к·ё fix вҖ” rl.on('line') н•ёл“Өлҹ¬к°Җ try лё”лЎқ мҷёл¶Җм—җм„ң м ‘к·ј мӢң ReferenceError л°ңмғқн–ҲмқҢ.
  //   мӮ¬мҡ©мһҗ ліҙкі : REPL agent м§„мһ… нӣ„ мұ„нҢ… мһ…л Ҙ мӢң "_lastCycleLines is not defined" нҒ¬лһҳмӢң.
  let _lastCycleLines = 0;  // м§Ғм „ cycle м¶ңл Ҙ лқјмқё мҲҳ (overwrite мҡ©) вҖ” 1.9.189/244

  // 1.9.170: Tab cycle вҖ” provider (Tab) / model within provider (Shift+Tab)
  //   мӮ¬мҡ©мһҗ лӘ…мӢң мҡ”мІӯ: "нғӯ нӮӨ л“ұмңјлЎң provider/лӘЁлҚё м…Җл үкіј м„ нғқмқ„ к°„нҺён•ҳкІҢ"
  //   readlineмқҳ default tab=completion лҸҷмһ‘мқ„ keypress лҰ¬мҠӨл„ҲлЎң к°ҖлЎңмұ„м„ң cycle мҲҳн–ү.
  if (isTty) {
    try {
      const readlineLib = require('readline');
      readlineLib.emitKeypressEvents(process.stdin, rl);
      const getProviders = () => {
        // л№ҢнҠёмқё 5мў… + мӮ¬мҡ©мһҗ м •мқҳ provider (.harness/providers.json)
        try {
          const userPath = path.join(absRoot(root), '.harness', 'providers.json');
          if (fs.existsSync(userPath)) {
            const j = JSON.parse(fs.readFileSync(userPath, 'utf8'));
            const userIds = (j.providers || []).map(p => p.id).filter(id => !_PROVIDER_CYCLE_ORDER.includes(id));
            return [..._PROVIDER_CYCLE_ORDER, ...userIds];
          }
        } catch {}
        return _PROVIDER_CYCLE_ORDER.slice();
      };
      // 1.9.180+1.9.189: cycleProvider/cycleModel вҖ” н•ң мӨ„ к°ұмӢ  (in-place overwrite).
      //   1.9.180к№Ңм§Җ: л§Ө Tab лҲ„лҰ„л§ҲлӢӨ мғҲ мӨ„ м¶ңл Ҙ вҶ’ мұ„нҢ… мқҙл ҘмңјлЎң лҲ„м Ғ (мӮ¬мҡ©мһҗ лӘ…мӢң: "м§Җм ёл¶„н•ҙліҙм—¬").
      //   1.9.189: ANSI cursor up + line clear лЎң мқҙм „ cycle лқјмқё лҚ®м–ҙм”Җ вҶ’ л§Ҳм§Җл§ү 1кұҙл§Ң н‘ңмӢң.
      //   1.9.244: _lastCycleLines лҠ” outer мҠӨмҪ”н”„ (мң„)м—җм„ң м„ м–ё вҖ” rl.on('line') н•ёл“Өлҹ¬мҷҖ кіөмң .
      const _clearLastCycle = () => {
        if (!isTty || _lastCycleLines === 0) return;
        // нҳ„мһ¬ prompt лқјмқё + мқҙм „ cycle лқјмқёл“Ө нҒҙлҰ¬м–ҙ
        // нҳ„мһ¬ cursorлҠ” prompt мӨ„. мң„лЎң _lastCycleLines+1 л§ҢнҒј мҳ¬лқјк°Җм„ң нҒҙлҰ¬м–ҙ.
        process.stdout.write('\r\x1b[K');                  // нҳ„мһ¬ prompt мӨ„ нҒҙлҰ¬м–ҙ
        for (let i = 0; i < _lastCycleLines; i++) {
          process.stdout.write('\x1b[1A\x1b[K');           // н•ң мӨ„ мң„лЎң + нҒҙлҰ¬м–ҙ
        }
        _lastCycleLines = 0;
      };
      const cycleProvider = (reverse) => {
        _clearLastCycle();
        const list = getProviders();
        let idx = list.indexOf(state.provider);
        if (idx < 0) idx = 0;
        idx = reverse ? (idx - 1 + list.length) % list.length : (idx + 1) % list.length;
        state.provider = list[idx];
        state.model = null;
        // 1.9.188: state.model auto-default вҶ’ лӢӨмқҢ cycle/prompt м—җ catalog мІ« лӘЁлҚё
        const cat = _PROVIDER_MODEL_CATALOG[state.provider];
        if (cat && cat.length) state.model = cat[0].id;
        let activeMark = '';
        try {
          if (state.provider !== 'ollama') {
            const agent = EXTERNAL_AGENTS.find(a => a.id === state.provider);
            if (agent) {
              const st = _checkAgent(agent);
              activeMark = st.status === 'ready' ? C.green(' вң“ ready') : C.yel(` вҡ  ${st.status}`);
            }
          }
        } catch {}
        process.stdout.write(C.bold(C.green(`  вҮ„ provider [${idx + 1}/${list.length}]: ${state.provider}`)) + activeMark + '\n');
        _lastCycleLines = 1;
        if (cat?.length) {
          process.stdout.write(C.dim(`    в”” ${cat.length}к°ң лӘЁлҚё catalog В· Shift+TabмңјлЎң model cycle\n`));
          _lastCycleLines = 2;
        }
        rl.setPrompt(prompt());
        rl.prompt(true);
      };
      const cycleModel = (reverse) => {
        _clearLastCycle();
        const cat = _PROVIDER_MODEL_CATALOG[state.provider] || [];
        if (cat.length === 0) {
          process.stdout.write(C.yel(`  вҡ  ${state.provider} м¶”мІң лӘЁлҚё catalog м—ҶмқҢ (/model <name> мңјлЎң м§Ғм ‘ м§Җм •)\n`));
          _lastCycleLines = 1;
          rl.prompt(true);
          return;
        }
        let idx = cat.findIndex(m => m.id === state.model);
        if (idx < 0) idx = -1;
        idx = reverse ? (idx - 1 + cat.length) % cat.length : (idx + 1) % cat.length;
        state.model = cat[idx].id;
        process.stdout.write(C.bold(C.mag(`  вҮ„ model [${idx + 1}/${cat.length}]: ${state.model}`)) + '\n');
        _lastCycleLines = 1;
        if (cat[idx].note) {
          process.stdout.write(C.dim(`    в”” ${cat[idx].note}\n`));
          _lastCycleLines = 2;
        }
        rl.setPrompt(prompt());
        rl.prompt(true);
      };
      // 1.9.189: мӮ¬мҡ©мһҗк°Җ лӢӨлҘё мһ…л Ҙ мӢңмһ‘н•ҳл©ҙ cycle line clear нқ”м Ғ м •лҰ¬ (лӢӨмқҢ Tabк№Ңм§Җ мң м§Җн•ҳл©ҙ cycle мң„м№ҳ ліҙмһ„)
      // лӢЁмҲңнҷ”: мӮ¬мҡ©мһҗк°Җ enter лҲ„лҘҙл©ҙ _lastCycleLines=0 мңјлЎң reset (мқ‘лӢө нӣ„ лӢӨмӢң cycle м¶ңл Ҙ мӢң мғҲлЎң мӢңмһ‘).
      process.stdin.on('keypress', (str, key) => {
        if (!key) return;
        if (key.name === 'tab') {
          // 1.9.180 fix: Shift+Tab вҶ’ cycleModel (мӮ¬мҡ©мһҗ лӘ…мӢң мқҳлҸ„).
          //   мқҙм „ (1.9.170): cycleProvider(key.shift) вҖ” Shift+Tab мӢң provider reverse cycleл§Ң лҗҳм–ҙ model м „нҷҳмқҙ л¶Ҳк°ҖлҠҘн–ҲмқҢ.
          //   мӮ¬мҡ©мһҗ лӘ…мӢң: "Tab=provider, Shift+Tab=model м„ нғқкіј м „нҷҳмқҙ к°„нҺён•ҳкІҢ".
          if (key.shift === true) {
            cycleModel(false);  // Shift+Tab вҶ’ нҳ„мһ¬ providerмқҳ лӢӨмқҢ model
          } else {
            cycleProvider(false);  // Tab вҶ’ лӢӨмқҢ provider
          }
        }
      });
    } catch (e) {
      log(C.dim(`  (Tab cycle л№„нҷңм„ұ: ${e.message})`));
    }
  }

  // 1.9.189 (мӮ¬мҡ©мһҗ лӘ…мӢң): "/" мһ…л Ҙл§ҢмңјлЎң лӘ…л № list н‘ңмӢң (claude code мҳҒк°җ вҖ” autocomplete UX).
  //   "/" лҳҗлҠ” "/?" вҶ’ лӘ…л № м№ҙнғҲлЎңк·ё м¶ңл Ҙ нӣ„ prompt ліөк·Җ. мқҙлҜём§Җ к°ҷмқҖ list мҠӨнғҖмқј (лӘ…л № + н•ң мӨ„ м„ӨлӘ…).
  const _showSlashCommandList = () => {
    log('');
    log(C.bold('  Available commands') + C.dim('  (also accepts ":" prefix)'));
    log(C.dim('  в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ'));
    const groups = [
      { title: 'meta', items: [
        ['/help', 'лӘ…л № лӘ©лЎқ (мқҙ нҷ”л©ҙ) вҖ” лҳҗлҠ” ":?"'],
        ['/quit', 'REPL мў…лЈҢ (м„ём…ҳ мһҗлҸҷ м ҖмһҘ)'],
        ['/clear', 'лҢҖнҷ” нһҲмҠӨнҶ лҰ¬ мҙҲкё°нҷ”'],
        ['/status', 'нҳ„мһ¬ provider / model / role / perms мғҒнғң'],
        ['/provider <id>', 'provider м „нҷҳ (ollama, claude, codex, agy, copilot)'],
        ['/model <id>', 'нҳ„мһ¬ providerмқҳ лӘЁлҚё м „нҷҳ'],
        ['/role <id>', 'м—ӯн•  м „нҷҳ (actor / planner / reviewer)'],
        ['/stream on|off', 'мӢӨмӢңк°„ мҠӨнҠёлҰ¬л°Қ нҶ кёҖ (default ON)']
      ]},
      { title: 'review', items: [
        ['/review "<req>"', 'л¬ҙмЎ°кұҙ кө¬нҳ„ м „ мӮ¬м „ кІҖнҶ  (1.9.176)'],
        ['/permissions <m>', 'к¶Ңн•ң ліҖкІҪ basic|extended|full (1.9.174)']
      ]},
      { title: 'internal', items: [
        ['/verify', 'task evidence кІҖмҰқ'],
        ['/audit', 'audit мӢӨн–ү'],
        ['/handoff', 'handoff context м¶ңл Ҙ'],
        ['/health', 'health check']
      ]},
      { title: 'memory', items: [
        ['/lessons', 'lessons.md нҡҢмҲҳ'],
        ['/brainstorm <q>', 'brainstorm нҡҢмҲҳ (memory + code + tasks)'],
        ['/tasks', 'нҳ„мһ¬ task list'],
        ['/plan', 'plan.md milestones']
      ]},
      { title: 'bridge', items: [
        ['/web <op>', 'playwright bridge (check/screenshot/extract)'],
        ['/pc <op>', 'robotjs bridge (check/click/type/screenshot)'],
        ['/lsp <op>', 'LSP adapter (check/symbols/references)']
      ]}
    ];
    for (const g of groups) {
      log(C.bold(`  ${g.title}`));
      for (const [name, desc] of g.items) {
        log('    ' + C.cy(name.padEnd(22)) + C.dim(desc));
      }
    }
    log(C.dim('  в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ'));
    log(C.dim('  рҹ’Ў л©”мӢңм§ҖлҠ” м§Ғм ‘ мһ…л Ҙ В· "/" лҳҗлҠ” ":" м ‘л‘җмӮ¬лЎң лӘ…л № нҳём¶ң В· Tab=provider В· Shift+Tab=model'));
    log('');
  };
  // 1.9.246: мІ« prompt н‘ңмӢң м „м—җлҸ„ status bar л…ём¶ң (мӮ¬мҡ©мһҗ лӘ…мӢң UR-0016)
  promptWithStatus();
  const handleMeta = async (cmd) => {
    const [op, ...rest] = cmd.slice(1).split(/\s+/);
    if (op === 'quit' || op === 'exit' || op === 'q') {
      saveSession();
      log(C.dim(`  м„ём…ҳ м ҖмһҘ: ${rel(root, sessionPath())}`));
      rl.close(); return true;
    }
    if (op === 'help' || op === '?') {
      log(C.bold('\n  л©”нғҖ лӘ…л № (provider/лӘЁлҚё/м—ӯн•  м „нҷҳ):'));
      log('    :help / :?            вҖ” мқҙ лҸ„мӣҖл§җ');
      log('    :model <name>         вҖ” лӘЁлҚё ліҖкІҪ (1.9.155 лӘЁл“  provider м§Җмӣҗ, мҳҲ: :model claude-opus-4-7)');
      log('    :models               вҖ” provider лі„ лӘЁлҚё лӘ©лЎқ (ollama мӢӨмӢңк°„ / к·ё мҷё м¶”мІң м№ҙнғҲлЎңк·ё)');
      log('    :role <r>             вҖ” м—ӯн•  ліҖкІҪ (planner / reviewer / actor)');
      log('    :provider <p>         вҖ” provider ліҖкІҪ (ollama / claude / codex / agy / copilot вҖ” ready кІҖмҰқ)');
      log('    :stream on|off        вҖ” рҹҶ• 1.9.170 мӢӨмӢңк°„ мҠӨнҠёлҰ¬л°Қ нҶ кёҖ (м¶”лЎ мӨ‘/diff/thinking мӢӨмӢңк°„ н‘ңмӢң)');
      log('    :status               вҖ” нҳ„мһ¬ м„ём…ҳ мғҒнғң мһҗм„ёнһҲ (1.9.155)');
      log('    :clear                вҖ” нҷ”л©ҙ нҒҙлҰ¬м–ҙ + history мң м§Җ');
      log('    :reset                вҖ” history мҙҲкё°нҷ”');
      log('    :history              вҖ” лҢҖнҷ” history н‘ңмӢң');
      log('    :save                 вҖ” м„ём…ҳ мҰүмӢң м ҖмһҘ');
      log('    :permissions [mode]   вҖ” рҹҶ• 1.9.174 нҳ„мһ¬ лӘЁл“ң н‘ңмӢң / лҳҗлҠ” мҰүмӢң ліҖкІҪ (basic/extended/full)');
      log('    :perm [mode]          вҖ” :permissions лӢЁм¶• alias');
      log('    :quit / :exit / :q    вҖ” мў…лЈҢ (мһҗлҸҷ м ҖмһҘ)');
      log(C.bold('\n  рҹҶ• 1.9.170 нӮӨліҙл“ң лӢЁм¶•нӮӨ:'));
      log('    Tab                   вҖ” лӢӨмқҢ provider лЎң cycle (ollama вҶ’ claude вҶ’ codex вҶ’ agy вҶ’ copilot)');
      log('    Shift+Tab             вҖ” нҳ„мһ¬ provider мқҳ лӢӨмқҢ model лЎң cycle (catalog кё°мӨҖ)');
      log(C.bold('\n  Slash лӘ…л № (1.9.150) вҖ” leerness лӮҙл¶Җ лӘ…л № м§Ғм ‘ нҳём¶ң:'));
      log('    :verify               вҖ” leerness verify-code (н…ҢмҠӨнҠё/нғҖмһ…/лҰ°нҠё мһҗлҸҷ кІҖмҲҳ)');
      log('    :audit                вҖ” leerness audit (ліҙм•Ҳ + drift + lazy)');
      log('    :handoff              вҖ” leerness handoff --quiet (нҳ„мһ¬ м»Ён…ҚмҠӨнҠё мҡ”м•Ҫ)');
      log('    :health               вҖ” leerness health --json (мў…н•© н—¬мҠӨ мІҙнҒ¬)');
      log(C.bold('\n  Memory Slash (1.9.161) вҖ” Memory Surface мҰүмӢң мЎ°нҡҢ:'));
      log('    :lessons [query]      вҖ” leerness lessons (кіјкұ° кІ°м •/мӢӨмҲҳ нҡҢмҲҳ)');
      log('    :brainstorm <topic>   вҖ” leerness brainstorm "topic" (кҙҖл Ё м»Ён…ҚмҠӨнҠё нҡҢмҲҳ)');
      log('    :tasks                вҖ” leerness task list (нҳ„мһ¬ task мғҒнғң)');
      log('    :plan                 вҖ” leerness plan show (нҳ„мһ¬ milestone)');
      log(C.bold('\n  рҹҶ• Review Slash (1.9.176) вҖ” мӮ¬мҡ©мһҗ мҡ”мІӯ мӮ¬м „ кІҖнҶ :'));
      log('    :review "<request>"   вҖ” м¶©лҸҢ/мһ¬мӮ¬мҡ©/нҡЁмңЁ/к¶ҢмһҘ лӢЁкі„ л¶„м„қ нӣ„ кө¬нҳ„ к¶ҢмһҘ');
      log(C.bold('\n  рҹҶ• Bridge Slash (1.9.175) вҖ” REPL м•Ҳм—җм„ң мҰүмӢң Bridge нҳём¶ң:'));
      log('    :web check                            вҖ” playwright м„Өм№ҳ нҷ•мқё (opt-in)');
      log('    :web screenshot <url> [--out f.png]   вҖ” URL вҶ’ PNG');
      log('    :web extract <url> --selector "css"   вҖ” DOM н…ҚмҠӨнҠё м¶”м¶ң');
      log('    :pc check                             вҖ” robotjs/nut-tree м„Өм№ҳ нҷ•мқё (вҡ  full к¶Ңн•ң)');
      log('    :pc click <x> <y>                     вҖ” мўҢн‘ң нҒҙлҰӯ');
      log('    :pc type "<text>"                     вҖ” нӮӨліҙл“ң мһ…л Ҙ');
      log('    :pc screenshot --out shot.png         вҖ” PC нҷ”л©ҙ мәЎмІҳ');
      log('    :lsp check                            вҖ” typescript м„Өм№ҳ + лӢӨкөӯм–ҙ fallback');
      log('    :lsp symbols <file>                   вҖ” мӢ¬ліј м¶”м¶ң (JS/TS/Py/Go/Rust/Java)');
      log('    :lsp references <name> [--in <dir>]   вҖ” мӢ¬ліј м°ёмЎ° кІҖмғү');
      return false;
    }
    if (op === 'model') {
      // 1.9.155: provider лі„ лӘЁлҚё лӘ…мӢң (мӮ¬мҡ©мһҗ лӘ…мӢң мҡ”мІӯ вҖ” м„ нғқн•ң CLI лӘЁлҚё ліҖкІҪ к°ҖлҠҘ)
      const m = rest.join(' ').trim();
      if (!m) {
        log(C.dim(`  нҳ„мһ¬ model: ${state.model || '(provider кё°ліё)'} В· provider: ${state.provider}`));
        log(C.dim(`  мӮ¬мҡ©: :model <name> вҖ” мҳҲ: :model qwen2.5-coder (ollama) / :model claude-opus-4-5 (claude) / :model gpt-5 (codex)`));
        return false;
      }
      state.model = m;
      log(C.green(`  model = ${state.model}  (provider: ${state.provider})`));
      log(C.dim(`     вҖ» лӢӨмқҢ л©”мӢңм§Җл¶Җн„° мғҲ лӘЁлҚёлЎң нҳём¶ң. provider к°Җ ${state.provider} мқём§Җ :provider лЎң мһ¬нҷ•мқё к¶ҢмһҘ.`));
      return false;
    }
    if (op === 'models') {
      // 1.9.155: provider лі„ лӘЁлҚё лӘ©лЎқ вҖ” ollama лҠ” мӢӨмӢңк°„ мЎ°нҡҢ, к·ё мҷёлҠ” м¶”мІң м№ҙнғҲлЎңк·ё л…ём¶ң
      if (state.provider === 'ollama') {
        const r = await _ollamaListModels();
        if (r.ok && r.models.length) {
          log(C.green(`  [ollama мӢӨмӢңк°„] ${r.models.length}к°ң лӘЁлҚё:`));
          r.models.forEach(m => log('    вҖў ' + m));
        } else log(C.yel('  вҡ  Ollama лҜёк°ҖлҸҷ вҖ” ollama serve + ollama pull <model>'));
      } else {
        const catalog = _PROVIDER_MODEL_CATALOG[state.provider] || [];
        if (catalog.length) {
          log(C.green(`  [${state.provider} м¶”мІң лӘЁлҚё м№ҙнғҲлЎңк·ё]`));
          catalog.forEach(m => log(`    вҖў ${m.id}${m.note ? '  вҖ” ' + m.note : ''}`));
          log(C.dim('     вҖ» мӢӨм ң к°Җмҡ© лӘЁлҚёмқҖ н•ҙлӢ№ CLI мқҳ --help / кіөмӢқ л¬ём„ң м°ёкі . :model <name> мңјлЎң ліҖкІҪ.'));
        } else {
          log(C.dim(`  ${state.provider} мқҳ м¶”мІң лӘЁлҚё м№ҙнғҲлЎңк·ё м—ҶмқҢ вҖ” :model <name> мңјлЎң м§Ғм ‘ м§Җм •`));
        }
      }
      return false;
    }
    if (op === 'role') {
      const r = rest[0] || 'actor';
      if (!['planner', 'reviewer', 'actor'].includes(r)) { log(C.yel(`  вҡ  role мқҖ planner/reviewer/actor`)); return false; }
      state.role = r; rl.setPrompt(prompt()); log(C.green(`  role = ${r}`)); return false;
    }
    if (op === 'provider') {
      const newProv = rest[0] || state.provider;
      const validProviders = ['ollama', 'claude', 'codex', 'agy', 'copilot'];
      if (!validProviders.includes(newProv)) {
        log(C.yel(`  вҡ  provider лҠ” ${validProviders.join(' / ')} (л°ӣмқҢ: ${newProv})`));
        return false;
      }
      // 1.9.154: provider м „нҷҳ мӢң нҷңм„ұ ready мӮ¬м „ кІҖмҰқ вҖ” л№„нҷңм„ұ/лҜём„Өм№ҳмқҙл©ҙ м№ңм Ҳн•ң м•ҲлӮҙ нӣ„ кұ°л¶Җ (мӢӨм ң нҳём¶ң мӢң мӢӨнҢЁ л°©м§Җ)
      if (newProv === 'ollama') {
        // Ollama лҠ” HTTP кё°л°ҳ вҖ” лӢЁмҲңнһҲ LEERNESS_OLLAMA_BASE_URL нҷ•мқё
        const url = process.env.LEERNESS_OLLAMA_BASE_URL || '';
        if (!url) {
          log(C.yel(`  вҡ  ollama base URL лҜём„Өм • (LEERNESS_OLLAMA_BASE_URL) вҖ” кё°ліё http://localhost:11434 мӢңлҸ„`));
        }
      } else {
        const agent = EXTERNAL_AGENTS.find(a => a.id === newProv);
        if (agent) {
          const st = _checkAgent(agent);
          if (st.status !== 'ready') {
            log(C.yel(`  вҡ  ${newProv} л№„нҷңм„ұ (${st.status}) вҖ” .env м—җм„ң LEERNESS_ENABLE_${newProv.toUpperCase()}=1 + CLI м„Өм№ҳ н•„мҡ”`));
            log(C.dim(`     (leerness agents list лЎң мғҒнғң нҷ•мқё)  вҖ” provider м „нҷҳ м·ЁмҶҢ`));
            return false;
          }
        }
      }
      state.provider = newProv;
      rl.setPrompt(prompt());
      log(C.green(`  provider = ${state.provider}`));
      return false;
    }
    if (op === 'stream') {
      // 1.9.170: мӢӨмӢңк°„ мҠӨнҠёлҰ¬л°Қ лӘЁл“ң нҶ кёҖ (мӮ¬мҡ©мһҗ лӘ…мӢң вҖ” м¶”лЎ мӨ‘/diff/thinking мӢӨмӢңк°„ н‘ңмӢң)
      const v = (rest[0] || '').toLowerCase();
      if (v === 'on' || v === '1' || v === 'true') {
        state.streamMode = true;
        log(C.green('  в–¶ streaming mode: ON  (CLI stdout мӢӨмӢңк°„ н‘ңмӢң)'));
      } else if (v === 'off' || v === '0' || v === 'false') {
        state.streamMode = false;
        log(C.dim('  в–Ў streaming mode: OFF  (л°°м№ҳ мқ‘лӢө)'));
      } else {
        log(C.dim(`  нҳ„мһ¬ streaming: ${state.streamMode ? 'ON в–¶' : 'OFF в–Ў'}  вҖ” мӮ¬мҡ©: :stream on|off`));
      }
      rl.setPrompt(prompt());
      return false;
    }
    // 1.9.247 (UR-0016 2лӢЁкі„): :fallback on|off вҖ” provider мӢӨнҢЁ мӢң лӢӨмқҢ ready agent мһҗлҸҷ м „нҷҳ (opt-in)
    if (op === 'fallback') {
      const v = (rest[0] || '').toLowerCase();
      if (v === 'on' || v === '1' || v === 'true') {
        state.autoFallback = true;
        log(C.green('  вҶӘ auto-fallback: ON (1.9.247) вҖ” нҳ„мһ¬ provider transient мӢӨнҢЁ (timeout/exit=null) мӢң лӢӨмқҢ ready agent мһҗлҸҷ м „нҷҳ + мһ¬мӢңлҸ„'));
      } else if (v === 'off' || v === '0' || v === 'false') {
        state.autoFallback = false;
        log(C.dim('  вҶӘ auto-fallback: OFF вҖ” мӢӨнҢЁ мӢң мӮ¬мҡ©мһҗк°Җ м§Ғм ‘ :provider м „нҷҳ'));
      } else {
        log(C.dim(`  нҳ„мһ¬ auto-fallback: ${state.autoFallback ? 'ON вҶӘ' : 'OFF'}  вҖ” мӮ¬мҡ©: :fallback on|off`));
      }
      return false;
    }
    if (op === 'clear') { process.stdout.write('\x1b[2J\x1b[H'); return false; }
    if (op === 'reset') { state.history = []; log(C.dim('  history мҙҲкё°нҷ”лҗЁ')); return false; }
    if (op === 'history') {
      log(C.bold(`\n  лҢҖнҷ” history ${state.history.length}кұҙ:`));
      state.history.slice(-10).forEach((m, i) => log(`    [${m.role}] ${m.content.slice(0, 80)}${m.content.length > 80 ? 'вҖҰ' : ''}`));
      return false;
    }
    if (op === 'save') { saveSession(); log(C.dim(`  вҶ’ ${rel(root, sessionPath())}`)); return false; }
    if (op === 'permissions' || op === 'perm') {
      // 1.9.174: REPLм—җм„ң к¶Ңн•ң ліҖкІҪ к°ҖлҠҘ (мӮ¬мҡ©мһҗ лӘ…мӢң мҡ”мІӯ).
      //   :permissions       вҖ” нҳ„мһ¬ лӘЁл“ң н‘ңмӢң + ліҖкІҪ мҳөм…ҳ м•ҲлӮҙ
      //   :permissions basic вҖ” к¶Ңн•ң лӘЁл“ң мҰүмӢң ліҖкІҪ
      const target = (rest[0] || '').toLowerCase();
      if (!target) {
        const p = _readPermissions(root);
        log('');
        log(C.bold(`  рҹ”җ нҳ„мһ¬ к¶Ңн•ң лӘЁл“ң: ${C.cy(p.mode || 'basic')}`));
        log('');
        log(C.dim('  ліҖкІҪ:'));
        log(`    ${C.green(':permissions basic')}     вҖ” м•Ҳм „ (.harness л§Ң м“°кё°, к¶ҢмһҘ)`);
        log(`    ${C.yel(':permissions extended')}  вҖ” н”„лЎңм қнҠё нҸҙлҚ” + shell allowlist`);
        log(`    ${C.mag(':permissions full')}      вҖ” вҡ  м „мІҙ (л§Ҳмҡ°мҠӨ/нӮӨліҙл“ң/мӣ№, IDE нҶөн•© мӢңл§Ң)`);
        log('');
        log(C.dim('  м„ёл¶Җ к¶Ңн•ң (mouse/keyboard/browser/admin):'));
        Object.entries(p).filter(([k]) => k !== 'mode' && typeof p[k] === 'boolean').forEach(([k, v]) => {
          log(`    ${k}: ${v ? C.green('вң“ н—Ҳмҡ©') : C.dim('вң— кұ°л¶Җ')}`);
        });
        return false;
      }
      if (!['basic', 'extended', 'full'].includes(target)) {
        log(C.yel(`  вҡ  мһҳлӘ»лҗң лӘЁл“ң: ${target}  (basic | extended | full)`));
        return false;
      }
      try {
        permissionsSetCmd(root, target);
        log(C.green(`  вң“ к¶Ңн•ң лӘЁл“ң ліҖкІҪ: ${target}  (мҰүмӢң м Ғмҡ© вҖ” лӢӨмқҢ лӘ…л №л¶Җн„°)`));
        if (target === 'full') {
          log(C.yel('  вҡ  full лӘЁл“ң вҖ” л§Ҳмҡ°мҠӨ/нӮӨліҙл“ң/мӣ№/кҙҖлҰ¬мһҗ м „мІҙ н—Ҳмҡ©. IDE нҶөн•© мҷё нҷҳкІҪм—җм„ңлҠ” мң„н—ҳ.'));
        }
      } catch (e) {
        log(C.yel(`  вҡ  к¶Ңн•ң ліҖкІҪ мӢӨнҢЁ: ${e.message}`));
      }
      return false;
    }
    if (op === 'status') {
      // 1.9.155: REPL м•Ҳм—җм„ң нҳ„мһ¬ м„ём…ҳ мғҒнғң мһҗм„ёнһҲ (provider/model/role/permissions/history/runs)
      log(C.bold('\n  рҹ“Ҡ REPL м„ём…ҳ мғҒнғң (1.9.155)'));
      log(`    provider:    ${state.provider}`);
      log(`    model:       ${state.model || '(кё°ліё)'}`);
      log(`    role:        ${state.role}  (${_AGENT_ROLE_PROMPTS[state.role]?.slice(0, 60) || ''}...)`);
      log(`    permissions: ${_readPermissions(root).mode || 'basic'}`);
      log(`    history:     ${state.history.length}н„ҙ (л§Ҳм§Җл§ү: ${state.history[state.history.length - 1]?.role || '-'})`);
      log(`    session ID:  ${state.sessionId}`);
      log(`    started:     ${state.startedAt}`);
      try {
        const ready = EXTERNAL_AGENTS.map(a => _checkAgent(a)).filter(c => c.status === 'ready');
        log(`    нҷңм„ұ CLI:    ${ready.length ? ready.map(c => c.id).join(', ') : '(м—ҶмқҢ)'}`);
      } catch {}
      log('');
      return false;
    }
    // 1.9.175: Bridge 3мў… slash вҖ” :web / :pc / :lsp (REPL м•Ҳм—җм„ң мҰүмӢң Bridge нҳём¶ң)
    //   мӮ¬мҡ© мҳҲ:
    //     :web check                              вҖ” playwright м„Өм№ҳ нҷ•мқё
    //     :web screenshot https://example.com     вҖ” URL вҶ’ PNG
    //     :pc check                               вҖ” robotjs м„Өм№ҳ нҷ•мқё
    //     :pc click 800 400                       вҖ” мўҢн‘ң нҒҙлҰӯ (full к¶Ңн•ң н•„мҡ”)
    //     :lsp symbols src/api.ts                 вҖ” нҢҢмқј мӢ¬ліј м¶”м¶ң
    //     :lsp references myFunc --in src         вҖ” мӢ¬ліј м°ёмЎ° кІҖмғү
    if (op === 'web' || op === 'pc' || op === 'lsp') {
      const subParts = rest.length ? rest : ['check'];  // мқёмһҗ м—Ҷмңјл©ҙ check кё°ліё
      const cliArgs = [op, ...subParts];
      // permissions мӮ¬м „ м•ҲлӮҙ (full лӘЁл“ң н•„мҡ”н•ң sub л§Ң)
      if (op === 'pc' && ['click', 'type', 'screenshot'].includes(subParts[0])) {
        const p = _readPermissions(root);
        if (p.mode !== 'full') {
          log(C.yel(`  вҡ  :pc ${subParts[0]} мқҖ permissions=full н•„мҡ” (нҳ„мһ¬: ${p.mode})`));
          log(C.dim(`     :permissions full  лЎң мҰүмӢң ліҖкІҪ к°ҖлҠҘ (1.9.174)`));
          return false;
        }
      }
      log(C.dim(`  вҶ’ leerness ${cliArgs.join(' ')}`));
      const t0 = Date.now();
      const r = runCommandSafe(process.execPath, [__filename, ...cliArgs, '--path', root], {
        cwd: root, root, timeout: 60000, kind: 'agent_repl_slash', label: `repl-${op}`,
        env: { LEERNESS_NO_BANNER: '1', LEERNESS_NO_PROMPT: '1', LEERNESS_NO_DRIFT_CHECK: '1' }
      });
      const dt = Date.now() - t0;
      if (r.stdout) log(r.stdout.trim().split('\n').slice(0, 50).join('\n'));
      if (r.status === 0) log(C.green(`  вң“ :${op} ${subParts[0] || ''} мҷ„лЈҢ (${dt}ms)`));
      else log(C.yel(`  вҡ  :${op} мӢӨнҢЁ (exit ${r.status}, ${dt}ms)`));
      return false;
    }

    // 1.9.176: :review <request> вҖ” мӮ¬мҡ©мһҗ мҡ”мІӯ мӮ¬м „ кІҖнҶ  slash (мӮ¬мҡ©мһҗ лӘ…мӢң)
    //   "мқҙкұ° кө¬нҳ„н•ҙмӨҳ" к°ҷмқҖ мҡ”мІӯмқ„ л°ӣмңјл©ҙ AI к°Җ лЁјм Җ :review нҳём¶ң вҶ’ м¶©лҸҢ/мһ¬мӮ¬мҡ©/нҡЁмңЁ л¶„м„қ.
    if (op === 'review') {
      const reqText = rest.join(' ').trim();
      if (!reqText) {
        log(C.yel(`  вҡ  :review лҠ” мҡ”мІӯ н…ҚмҠӨнҠё н•„мҡ” вҖ” мҳҲ: :review "OAuth лЎңк·ёмқё м¶”к°Җ"`));
        return false;
      }
      log(C.dim(`  вҶ’ leerness review-request "${reqText.slice(0, 60)}${reqText.length > 60 ? 'вҖҰ' : ''}"`));
      const t0 = Date.now();
      const r = runCommandSafe(process.execPath, [__filename, 'review-request', reqText, '--path', root], {
        cwd: root, root, timeout: 30000, kind: 'agent_repl_slash', label: 'repl-review',
        env: { LEERNESS_NO_BANNER: '1', LEERNESS_NO_PROMPT: '1', LEERNESS_NO_DRIFT_CHECK: '1' }
      });
      const dt = Date.now() - t0;
      if (r.stdout) log(r.stdout.trim().split('\n').slice(0, 60).join('\n'));
      if (r.status === 0) log(C.green(`  вң“ :review мҷ„лЈҢ (${dt}ms)`));
      else log(C.yel(`  вҡ  :review мӢӨнҢЁ (exit ${r.status}, ${dt}ms)`));
      return false;
    }

    // 1.9.150: leerness лӮҙл¶Җ лӘ…л № slash-commands вҖ” :verify / :audit / :handoff / :health
    // 1.9.161: Memory Surface мЎ°нҡҢ slash м¶”к°Җ вҖ” :lessons / :brainstorm / :tasks / :plan
    if (op === 'verify' || op === 'audit' || op === 'handoff' || op === 'health'
        || op === 'lessons' || op === 'brainstorm' || op === 'tasks' || op === 'plan') {
      const query = rest.join(' ').trim();
      const subArgs = {
        verify: ['verify-code', root],
        audit: ['audit', root],
        handoff: ['handoff', root, '--quiet', '--no-drift-check'],
        health: ['health', root, '--json'],
        // 1.9.161 Memory Surface slash 4мў…
        lessons: query ? ['lessons', '--query', query, '--path', root] : ['lessons', '--path', root],
        brainstorm: query ? ['brainstorm', query, '--path', root] : ['brainstorm', '--path', root],
        tasks: ['task', 'list', '--path', root],
        plan: ['plan', 'show', '--path', root]
      }[op];
      // мқёмһҗ н•„мҡ”н•ңлҚ° лҲ„лқҪ мӢң м•ҲлӮҙ (brainstorm мқҖ мқёмһҗ н•„мҲҳ)
      if (op === 'brainstorm' && !query) {
        log(C.yel(`  вҡ  :brainstorm мқҖ нӮӨмӣҢл“ң н•„мҡ” вҖ” мҳҲ: :brainstorm "auth bug"`));
        return false;
      }
      log(C.dim(`  вҶ’ leerness ${subArgs.join(' ')}`));
      const t0 = Date.now();
      const r = runCommandSafe(process.execPath, [__filename, ...subArgs], {
        cwd: root, root, timeout: 60000, kind: 'agent_repl_slash', label: `repl-${op}`,
        env: { LEERNESS_NO_BANNER: '1', LEERNESS_NO_PROMPT: '1', LEERNESS_NO_DRIFT_CHECK: '1' }
      });
      const dt = Date.now() - t0;
      if (r.stdout) log(r.stdout.trim().split('\n').slice(0, 30).join('\n'));
      if (r.status === 0) log(C.green(`  вң“ :${op} мҷ„лЈҢ (${dt}ms)`));
      else log(C.yel(`  вҡ  :${op} мӢӨнҢЁ (exit ${r.status}, ${dt}ms)`));
      return false;
    }
    log(C.yel(`  м•Ң мҲҳ м—ҶлҠ” лӘ…л №: :${op}  (:help м°ёкі )`));
    return false;
  };
  return new Promise(resolve => {
    rl.on('line', async (line) => {
      const input = line.trim();
      _lastCycleLines = 0;  // 1.9.189: мӮ¬мҡ©мһҗ мһ…л Ҙ мӢң cycle overwrite м¶”м Ғ reset
      if (!input) { promptWithStatus(); return; }
      // 1.9.189 (мӮ¬мҡ©мһҗ лӘ…мӢң): "/" slash мһ…л Ҙл§ҢмңјлЎң лӘ…л № list н‘ңмӢң (claude code мҳҒк°җ).
      //   "/" лӢЁлҸ… вҶ’ лӘ…л № list м¶ңл Ҙ нӣ„ prompt ліөк·Җ.
      //   "/help", "/quit" л“ұ "/" м ‘л‘җмӮ¬ вҶ’ ":" лҸҷл“ұ мІҳлҰ¬ (alias).
      if (input === '/' || input === '/?') {
        _showSlashCommandList();
        promptWithStatus(); return;
      }
      // 1.9.189: "/" м ‘л‘җмӮ¬лҘј ":" мҷҖ лҸҷл“ұн•ҳкІҢ мІҳлҰ¬ (мӮ¬мҡ©мһҗ лӘ…мӢң вҖ” "/ к°Җ лӘЁл“  лӘЁлҚё кіөнҶө к¶Ңн•ң trigger default")
      if (input.startsWith('/') && !input.startsWith('//')) {
        const shouldQuit = await handleMeta(':' + input.slice(1));
        if (shouldQuit) { resolve(); return; }
        promptWithStatus(); return;
      }
      if (input.startsWith(':')) {
        const shouldQuit = await handleMeta(input);
        if (shouldQuit) { resolve(); return; }
        promptWithStatus(); return;
      }
      // LLM нҳём¶ң
      state.history.push({ role: 'user', content: input });
      const rolePrompt = _AGENT_ROLE_PROMPTS[state.role] || _AGENT_ROLE_PROMPTS.actor;
      const finalPrompt = `${rolePrompt}\n\nConversation so far:\n${state.history.slice(-6).map(m => `[${m.role}] ${m.content}`).join('\n')}\n\nRespond as ${state.role}:`;
      const t0 = Date.now();
      let result;
      // 1.9.153: multi-provider REPL вҖ” ollama мҷё claude/codex/agy/copilot лҸ„ м„ём…ҳ кҙҖлҰ¬ (мӮ¬мҡ©мһҗ лӘ…мӢң)
      // 1.9.170: streamMode === true мқҙл©ҙ _cliChatStream мӮ¬мҡ© (мӮ¬мҡ©мһҗ лӘ…мӢң вҖ” м¶”лЎ мӨ‘/diff мӢӨмӢңк°„ н‘ңмӢң)
      if (state.provider === 'ollama') {
        log(C.dim(`  вҶ’ ollama${state.model ? ' (' + state.model + ')' : ''} нҳём¶ң мӨ‘...`));
        result = await _ollamaChat(finalPrompt, state.model);
      } else if (['claude', 'codex', 'agy', 'copilot'].includes(state.provider)) {
        if (state.streamMode) {
          log(C.dim(`  вҶ’ ${state.provider} CLI stream нҳём¶ң мӨ‘...  (Ctrl+C лЎң мӨ‘лӢЁ)`));
          result = await _cliChatStream(root, state.provider, finalPrompt, { timeout: 120000 });
        } else {
          log(C.dim(`  вҶ’ ${state.provider} CLI нҳём¶ң мӨ‘...`));
          result = await _cliChat(root, state.provider, finalPrompt, { timeout: 90000 });
        }
      } else {
        log(C.yel(`  вҡ  ${state.provider} provider лҜём§Җмӣҗ вҖ” :provider ollama|claude|codex|agy|copilot`));
        promptWithStatus(); return;
      }
      const dt = Date.now() - t0;
      _recordRun(root, { kind: 'agent_repl_turn', provider: state.provider, model: state.model, role: state.role, durationMs: dt, ok: result.ok, error: result.error, promptChars: finalPrompt.length, responseChars: (result.response || '').length });
      if (result.ok) {
        state.history.push({ role: 'assistant', content: result.response });
        // 1.9.170: stream лӘЁл“ңм—җм„ңлҠ” мқҙлҜё мӢӨмӢңк°„мңјлЎң м¶ңл ҘлҗҗмңјлҜҖлЎң н—ӨлҚ”л§Ң н‘ңмӢң (мқ‘лӢө мӨ‘ліө л°©м§Җ)
        // 1.9.246: м •мғҒ мҷ„лЈҢ мһ‘м—…мқҖ мҙҲлЎқмғү вң“ к°•мЎ° (мӮ¬мҡ©мһҗ лӘ…мӢң UR-0016)
        if (state.streamMode && ['claude', 'codex', 'agy', 'copilot'].includes(state.provider)) {
          log(C.green(`  вң“ [assistant: ${state.provider}/${state.model || 'default'}, role=${state.role}, ${dt}ms В· ${result.response.length}мһҗ]`));
        } else {
          log('');
          log(C.green(`вң“ assistant (${state.model || state.provider}, role=${state.role}, ${dt}ms)`));
          log(result.response);
        }
        // 1.9.188 (мӮ¬мҡ©мһҗ лӘ…мӢң): мқ‘лӢө лҒқ + мһ…л Ҙ кө¬л¶„м„  (мһ…л Ҙм№ё мӢңк°Ғ лӘ…нҷ•)
        _printInputDivider();
        if (state.history.length % 6 === 0) saveSession();  // 6н„ҙл§ҲлӢӨ мһҗлҸҷ м ҖмһҘ
      } else {
        // 1.9.185 (мӮ¬мҡ©мһҗ лӘ…мӢң): REPL нҳём¶ң мӢӨнҢЁ м№ңм Ҳн•ң м§„лӢЁ вҖ” м–ҙлҠҗ лӢЁкі„м—җм„ң мӢӨнҢЁн–ҲлҠ”м§Җ + мҰүмӢң кІҖмҰқ лӘ…л № м•ҲлӮҙ
        const errMsg = result.error || 'unknown';
        log(C.yel(`  вҡ  ${state.provider} CLI мқ‘лӢө мӢӨнҢЁ: ${errMsg}`));
        // мӢӨнҢЁ мӣҗмқё л¶„лҘҳ
        if (/exit=null/.test(errMsg) || /timeout/i.test(errMsg)) {
          log(C.dim(`     вҶі к°ҖлҠҘ мӣҗмқё: (1) ${state.provider} CLI мқ‘лӢө мӢңк°„ мҙҲкіј (лӘЁлҚё лЎңл”©/нҒ° мқ‘лӢө лҢҖкё° мӨ‘)`));
          log(C.dim(`                  (2) network/auth л¬ём ң (нҠ№нһҲ codex/agy лҠ” мқён„°л„· + нҶ нҒ° н•„мҡ”)`));
          log(C.dim(`     вҶі м§Ғм ‘ кІҖмҰқ: ${state.provider} --print "ping" ${state.provider === 'agy' ? '--yolo' : ''}`));
        } else if (/exit=1/.test(errMsg) || /unauth/i.test(errMsg) || /login/i.test(errMsg)) {
          log(C.dim(`     вҶі к°ҖлҠҘ мӣҗмқё: мқёмҰқ лҲ„лқҪ (login н•„мҡ”)`));
          log(C.dim(`     вҶі н•ҙкІ°: ${state.provider} login ${state.provider === 'copilot' ? '(gh auth login)' : ''}`));
        }
        // 1.9.247 (UR-0016 2лӢЁкі„): мһҗлҸҷ fallback вҖ” мӮ¬мҡ©мһҗ лӘ…мӢң (`:fallback on` лҳҗлҠ” LEERNESS_REPL_AUTO_FALLBACK=1) мӢң
        //   нҳ„мһ¬ provider к°Җ transient мӢӨнҢЁ (timeout/exit=null/network) мӢң лӢӨмқҢ ready agent лЎң мһҗлҸҷ м „нҷҳ + 1нҡҢ мһ¬мӢңлҸ„.
        //   мӮ¬мҡ©мһҗ лӘ…мӢң (мқҙм „ codex CLI exit=null ліҙкі ): "л©ҖнӢ° provider auto-fallback лҸ„ кІҖнҶ ".
        const isTransient = /exit=null|timeout/i.test(errMsg);
        if (state.autoFallback && isTransient) {
          try {
            const others = EXTERNAL_AGENTS.filter(a => a.id !== state.provider)
                                           .map(a => ({ def: a, status: _checkAgent(a) }))
                                           .filter(x => x.status.status === 'ready');
            if (others.length > 0) {
              const next = others[0].def.id;
              log(C.green(`  вҶӘ auto-fallback (1.9.247): ${state.provider} мӢӨнҢЁ вҶ’ ${next} мһҗлҸҷ м „нҷҳ + мһ¬мӢңлҸ„ мӨ‘...`));
              state.provider = next;
              state.model = null;
              const cat = _PROVIDER_MODEL_CATALOG[state.provider];
              if (cat && cat.length) state.model = cat[0].id;
              rl.setPrompt(prompt());
              const t1 = Date.now();
              let retry;
              if (state.streamMode) retry = await _cliChatStream(root, state.provider, finalPrompt, { timeout: 120000 });
              else retry = await _cliChat(root, state.provider, finalPrompt, { timeout: 90000 });
              const dt1 = Date.now() - t1;
              _recordRun(root, { kind: 'agent_repl_turn_fallback', provider: state.provider, model: state.model, role: state.role, durationMs: dt1, ok: retry.ok, error: retry.error, promptChars: finalPrompt.length, responseChars: (retry.response || '').length });
              if (retry.ok) {
                state.history.push({ role: 'assistant', content: retry.response });
                log(C.green(`  вң“ fallback м„ұкіө [${state.provider}/${state.model || 'default'}, ${dt1}ms В· ${retry.response.length}мһҗ]`));
                if (!state.streamMode) log(retry.response);
                _printInputDivider();
                if (state.history.length % 6 === 0) saveSession();
                promptWithStatus();
                return;
              } else {
                log(C.yel(`  вҡ  fallback лҸ„ мӢӨнҢЁ (${next}): ${retry.error || 'unknown'}`));
              }
            } else {
              log(C.dim(`     (auto-fallback: лӢӨлҘё ready provider м—ҶмқҢ)`));
            }
          } catch (e) {
            log(C.dim(`     (auto-fallback мҳӨлҘҳ: ${e.message})`));
          }
        }
        // м „нҷҳ к°ҖлҠҘ provider м•ҲлӮҙ
        try {
          const others = EXTERNAL_AGENTS.filter(a => a.id !== state.provider)
                                         .map(a => ({ def: a, status: _checkAgent(a) }))
                                         .filter(x => x.status.status === 'ready');
          if (others.length) {
            log(C.dim(`     рҹ’Ў мҰүмӢң м „нҷҳ: ${others.map(x => `:provider ${x.def.id}`).join(' В· ')}  лҳҗлҠ” Tab нӮӨ`));
            if (!state.autoFallback) log(C.dim(`     рҹ’Ў лӢӨмқҢ мӢӨнҢЁ мӢң мһҗлҸҷ м „нҷҳ: \`:fallback on\` (1.9.247 UR-0016 2лӢЁкі„)`));
          } else {
            log(C.dim(`     рҹ’Ў лӢӨлҘё provider нҷңм„ұнҷ”: .env м—җм„ң LEERNESS_ENABLE_<CLAUDE|CODEX|AGY|COPILOT>=1`));
          }
        } catch {}
      }
      promptWithStatus();
    });
    rl.on('close', () => { saveSession(); resolve(); });
  });
}

async function agentCmd(root, taskArg) {
  root = absRoot(root || process.cwd());
  const task = (taskArg || arg('--task', '') || '').trim();
  // 1.9.149+1.9.181: REPL м§„мһ… вҖ” мқёмһҗ м—Ҷкұ°лӮҳ --interactive лӘ…мӢң (provider мһҗлҸҷ м„ нғқ)
  if (!task || has('--interactive') || has('--repl')) {
    if (process.stdin.isTTY && !has('--no-repl') && process.env.LEERNESS_NO_PROMPT !== '1') {
      const t0 = Date.now();
      await _agentRepl(root, {
        provider: arg('--provider', null),
        model: arg('--model', null),
        role: arg('--role', 'actor')
      });
      _recordRun(root, { kind: 'agent_repl_session', durationMs: Date.now() - t0, ok: true });
      return;
    }
    // non-TTY: мӮ¬мҡ©лІ•л§Ң м¶ңл Ҙ
    log('# leerness agent вҖ” кІҖмҲҳВ·кё°м–өВ·мғҢл“ңл°•мҠӨ нҶөн•© мһҗмңЁ AI м—җмқҙм „нҠё');
    log('');
    log('мӮ¬мҡ©лІ•:');
    log('  leerness agent                              # REPL лӘЁл“ң (provider мһҗлҸҷ м„ нғқ + мұ„нҢ…)');
    log('  leerness agent "<task>"                     # 1нҡҢ мң„мһ„ (actor м—ӯн•  кё°ліё)');
    log('  leerness agent "<task>" --role planner      # кі„нҡҚл§Ң (1.9.148)');
    log('  leerness agent "<task>" --role reviewer     # л№„нҢҗм Ғ кІҖнҶ  (1.9.148)');
    log('  leerness agent --provider claude            # provider лӘ…мӢң (ollama/claude/codex/agy/copilot)');
    log('  leerness agent --interactive --model qwen2.5-coder  # лӘ…мӢңм Ғ REPL + Ollama лӘЁлҚё м„ нғқ');
    log('');
    log('REPL л©”нғҖ лӘ…л №: :help / :model / :role / :provider / :history / :save / :quit');
    log('REPL Slash лӘ…л № (1.9.150): :verify / :audit / :handoff / :health  (sandboxed runCommandSafe)');
    log('REPL Multi-provider (1.9.153): ollama / claude / codex / agy / copilot вҖ” нҷңм„ұ CLI мһҗлҸҷ к°җм§Җ');
    log('');
    log('нҳ„мһ¬ нҷңм„ұ provider: ' + (_activeCliAgents().join(', ') || '(м—ҶмқҢ) вҖ” .envм—җм„ң LEERNESS_ENABLE_* нҷңм„ұнҷ”'));
    log('к¶Ңн•ң лӘЁл“ң: ' + (_readPermissions(root).mode || 'basic'));
    return;
  }
  const dryRun = has('--dry-run');
  const providerArg = arg('--provider', null);
  const role = arg('--role', 'actor');  // 1.9.148
  const rolePrompt = _AGENT_ROLE_PROMPTS[role] || _AGENT_ROLE_PROMPTS.actor;
  const active = _activeCliAgents();
  const provider = providerArg || active[0] || null;
  log(`# leerness agent (1.9.146/148)`);
  log(`task: ${task.slice(0, 120)}${task.length > 120 ? 'вҖҰ' : ''}`);
  log(`role: ${role}  (${rolePrompt.split('. ')[1] || rolePrompt.slice(0, 60)})`);
  log(`provider: ${provider || '(м—ҶмқҢ вҖ” .env м—җм„ң LEERNESS_ENABLE_* нҷңм„ұнҷ” н•„мҡ”)'}`);
  const perms = _readPermissions(root);
  log(`permission mode: ${perms.mode || 'basic'}`);
  // handoff мһҗлҸҷ нҡҢмҲҳ (compact лӘЁл“ң)
  try {
    const hf = cp.spawnSync(process.execPath, [__filename, 'handoff', root, '--compact', '--no-drift-check'], { encoding: 'utf8', timeout: 10000, env: { ...process.env, LEERNESS_INTERNAL: '1', LEERNESS_NO_BANNER: '1', LEERNESS_NO_PROMPT: '1' } });
    if (hf.status === 0 && hf.stdout) {
      const preview = hf.stdout.split('\n').slice(0, 6).join('\n');
      log('\n[handoff context (preview)]\n' + preview);
    }
  } catch {}
  if (dryRun) { log('\n(dry-run) LLM нҳём¶ң мҠӨнӮө вҖ” provider/к¶Ңн•ң/м»Ён…ҚмҠӨнҠёл§Ң м¶ңл Ҙ'); return; }
  if (!provider) { fail('нҷңм„ұ provider м—ҶмқҢ вҖ” .env м—җм„ң LEERNESS_ENABLE_OLLAMA=1 лҳҗлҠ” LEERNESS_ENABLE_CLAUDE=1 нҷңм„ұнҷ”'); process.exitCode = 1; return; }
  // 1.9.148: role prompt мһҗлҸҷ prepend (лӘЁл“  provider кіөнҶө)
  const finalPrompt = `${rolePrompt}\n\nTask: ${task}`;
  const t0 = Date.now();
  // 1.9.154: 1-shot лӘЁл“ңлҸ„ multi-provider вҖ” Ollama мҷё claude/codex/agy/copilot м§Ғм ‘ нҳём¶ң (1.9.153 _cliChat мһ¬мӮ¬мҡ©)
  let r;
  if (provider === 'ollama') {
    log('\n[ollama нҳём¶ң мӨ‘...]');
    r = await _ollamaChat(finalPrompt);
  } else if (['claude', 'codex', 'agy', 'copilot'].includes(provider)) {
    log(`\n[${provider} CLI нҳём¶ң мӨ‘...]`);
    r = await _cliChat(root, provider, finalPrompt, { timeout: 90000 });
    if (r.ok && !r.model) r.model = provider;  // _cliChat кІ°кіј ліҙк°•
  } else {
    fail(`м•Ң мҲҳ м—ҶлҠ” provider: ${provider} (ollama/claude/codex/agy/copilot)`);
    process.exitCode = 1;
    return;
  }
  const dt = Date.now() - t0;
  // 1.9.149: observability кё°лЎқ
  _recordRun(root, { kind: 'agent_one_shot', provider, model: r.model || provider, role, durationMs: dt, ok: r.ok, error: r.error, task: task.slice(0, 200), responseChars: (r.response || '').length });
  if (r.ok) {
    log(`\n[response (provider=${provider}, model=${r.model || provider}, role=${role}, ${dt}ms)]\n${r.response}`);
    try {
      const tlp = taskLogPath(root);
      const block = `\n## ${today()} leerness agent (${provider}:${r.model || provider}, role=${role})\n- task: ${task.slice(0, 200)}\n- response (preview): ${(r.response || '').slice(0, 240).replace(/\n+/g, ' ')}\n`;
      append(tlp, block);
    } catch {}
  } else {
    fail(`${provider} нҳём¶ң мӢӨнҢЁ: ${r.error || 'unknown'}`);
    if (provider === 'ollama') log(`  вҶ’ ollama serve мӢӨн–ү + LEERNESS_OLLAMA_BASE_URL нҷ•мқё`);
    else log(`  вҶ’ .env м—җм„ң LEERNESS_ENABLE_${provider.toUpperCase()}=1 + CLI м„Өм№ҳ нҷ•мқё (leerness agents list)`);
    process.exitCode = 1;
  }
}

// ===== 1.9.147: мһҗлҸҷ мң м§ҖліҙмҲҳ мӢңмҠӨн…ң (мӮ¬мҡ©мһҗ лӘ…мӢң мҡ”мІӯ) =====
//
// 4 м»ҙнҸ¬л„ҢнҠё:
//   1) webhook listener вҖ” HTTP + HMAC кІҖмҰқмңјлЎң мҷёл¶Җ м—җлҹ¬ ліҙкі  мҲҳмӢ 
//   2) incident handler вҖ” л°ӣмқҖ нҺҳмқҙлЎңл“ңлҘј leerness м»Ён…ҚмҠӨнҠёлЎң л¶„м„қ/fix/test
//   3) credentials registry вҖ” нҷҳкІҪліҖмҲҳ мқҙлҰ„л§Ң л“ұлЎқ (к°’мқҖ мӮ¬мҡ©мһҗ .env / OS keychain вҖ” ліҙм•Ҳ м •мұ…)
//   4) deploy auto вҖ” Firebase/Cloudflare/Vercel adapter (24h нҶ нҒ° л§ҢлЈҢ м•ҢлҰј)
//
// ліҙм•Ҳ м •мұ… (1.9.71/75 м—°мһҘ):
//   - .harness/credentials.local.json м—җ мӢӨм ң нҶ нҒ° м ҲлҢҖ лҜём ҖмһҘ (env-ref л§Ң)
//   - .gitignore + .npmignore мһҗлҸҷ л“ұлЎқ
//   - .harness/incidents/*.json лҸ„ л№„кіөк°ң (мӢңнҒ¬лҰҝ нҺҳмқҙлЎңл“ң лҲ„м¶ң л°©м§Җ)

// ---- (1) Credentials Registry ----
function _credentialsPath(root) { return path.join(absRoot(root), '.harness', 'credentials.local.json'); }
function _readCredentials(root) {
  const p = _credentialsPath(root);
  if (!exists(p)) return { schemaVersion: 1, services: {} };
  try { return JSON.parse(read(p)); } catch { return { schemaVersion: 1, services: {} }; }
}
function _writeCredentials(root, data) {
  const p = _credentialsPath(root);
  mkdirp(path.dirname(p));
  writeUtf8(p, JSON.stringify(data, null, 2) + '\n');
  // 1.9.147: gitignore + npmignore мһҗлҸҷ ліҙк°• (ліҙм•Ҳ)
  try {
    const giPath = path.join(absRoot(root), '.gitignore');
    if (exists(giPath)) {
      const gi = read(giPath);
      if (!gi.includes('credentials.local.json')) {
        writeUtf8(giPath, gi.trimEnd() + '\n.harness/credentials.local.json\n');
      }
    }
  } catch {}
}
function credsListCmd(root) {
  root = absRoot(root || process.cwd());
  const j = _readCredentials(root);
  if (has('--json')) { log(JSON.stringify(j, null, 2)); return; }
  log(`# leerness creds list (1.9.147)`);
  const services = Object.entries(j.services || {});
  if (!services.length) { log('(л“ұлЎқлҗң мһҗкІ©мҰқлӘ… м—ҶмқҢ вҖ” leerness creds register <service> --env-var <NAME>)'); return; }
  log(`мҙқ ${services.length}к°ң м„ңл№„мҠӨ (к°’ лҜём ҖмһҘ вҖ” env-ref л§Ң)`);
  for (const [name, meta] of services) {
    const present = meta.envVars.every(v => process.env[v] !== undefined && process.env[v] !== '');
    const last = meta.lastRefreshed ? new Date(meta.lastRefreshed) : null;
    const ageDays = last ? Math.floor((Date.now() - last.getTime()) / 86400000) : null;
    const ageWarn = (meta.tokenLifetimeHours && last && (Date.now() - last.getTime()) > meta.tokenLifetimeHours * 3600 * 1000);
    log(`  ${name}: env=${meta.envVars.join(',')} В· ${present ? 'вң“ нҷҳкІҪліҖмҲҳ мһҲмқҢ' : 'вҡ  лҜём„Өм •'}${ageDays !== null ? ` В· ${ageDays}мқј м „ refresh${ageWarn ? ' (л§ҢлЈҢ к°ҖлҠҘ)' : ''}` : ''}`);
    if (meta.deployCommand) log(`    deploy: ${meta.deployCommand}`);
  }
}
function credsRegisterCmd(root, service) {
  root = absRoot(root || process.cwd());
  if (!service) return fail('service мқҙлҰ„ н•„мҡ” вҖ” leerness creds register <service> --env-var <NAME[,NAME2]>');
  const envVarArg = arg('--env-var', null);
  if (!envVarArg) return fail('--env-var <NAME> н•„мҡ” (мҪӨл§Ҳ кө¬л¶„ к°ҖлҠҘ)');
  const envVars = envVarArg.split(',').map(s => s.trim()).filter(Boolean);
  const deployCmd = arg('--deploy', null);
  const lifetime = parseInt(arg('--token-lifetime-hours', '0'), 10) || null;
  const j = _readCredentials(root);
  j.services = j.services || {};
  j.services[service] = {
    envVars,
    deployCommand: deployCmd || j.services[service]?.deployCommand || null,
    tokenLifetimeHours: lifetime || j.services[service]?.tokenLifetimeHours || null,
    lastRefreshed: j.services[service]?.lastRefreshed || null,
    registeredAt: j.services[service]?.registeredAt || new Date().toISOString()
  };
  _writeCredentials(root, j);
  ok(`creds registered: ${service} В· env=${envVars.join(',')}${deployCmd ? ` В· deploy="${deployCmd}"` : ''}`);
  // нҷҳкІҪліҖмҲҳ мҰүмӢң нҷ•мқё
  const missing = envVars.filter(v => !process.env[v]);
  if (missing.length) warn(`вҡ  лӢӨмқҢ нҷҳкІҪліҖмҲҳк°Җ нҳ„мһ¬ м…ём—җ м„Өм •лҗҳм§Җ м•ҠмқҢ: ${missing.join(', ')} вҖ” .env лҳҗлҠ” OS keychainм—җм„ң export н•„мҡ”`);
}
function credsCheckCmd(root, service) {
  root = absRoot(root || process.cwd());
  const j = _readCredentials(root);
  const result = { service: service || null, services: {}, ok: true };
  const targets = service ? (j.services[service] ? { [service]: j.services[service] } : {}) : (j.services || {});
  if (!Object.keys(targets).length) { failJson(has('--json'), 'no_service', `л“ұлЎқлҗң м„ңл№„мҠӨ м—ҶмқҢ${service ? ` (${service})` : ''}`); return; }  // 1.9.404 (UR-0105 мһ”м—¬): --json м—җлҹ¬ кө¬мЎ°нҷ”
  for (const [name, meta] of Object.entries(targets)) {
    const missing = (meta.envVars || []).filter(v => !process.env[v]);
    const expired = meta.tokenLifetimeHours && meta.lastRefreshed
      ? (Date.now() - new Date(meta.lastRefreshed).getTime()) > meta.tokenLifetimeHours * 3600 * 1000
      : false;
    result.services[name] = { envSet: !missing.length, missing, expired };
    if (missing.length || expired) result.ok = false;
  }
  if (has('--json')) { log(JSON.stringify(result, null, 2)); if (!result.ok) process.exitCode = 1; return; }
  log(`# leerness creds check (1.9.147)`);
  for (const [name, r] of Object.entries(result.services)) {
    if (r.envSet && !r.expired) log(`  вң“ ${name}: мӮ¬мҡ© мӨҖл№„лҗЁ`);
    else {
      log(`  вҡ  ${name}: ${r.missing.length ? `лҲ„лқҪ ${r.missing.join(',')}` : ''}${r.expired ? ' В· нҶ нҒ° л§ҢлЈҢ (мһ¬лЎңк·ёмқё н•„мҡ”)' : ''}`);
    }
  }
  if (!result.ok) process.exitCode = 1;
}
function credsRefreshTimestampCmd(root, service) {
  root = absRoot(root || process.cwd());
  if (!service) return fail('service мқҙлҰ„ н•„мҡ”');
  const j = _readCredentials(root);
  if (!j.services[service]) return fail(`л“ұлЎқлҗң м„ңл№„мҠӨ м—ҶмқҢ: ${service} вҖ” leerness creds register лЁјм Җ`);
  j.services[service].lastRefreshed = new Date().toISOString();
  _writeCredentials(root, j);
  ok(`creds refreshed: ${service} В· lastRefreshed=${j.services[service].lastRefreshed}`);
}

// ---- (2) Incident Handler ----
function _incidentsDir(root) { return path.join(absRoot(root), '.harness', 'incidents'); }
function _saveIncident(root, payload) {
  const dir = _incidentsDir(root);
  mkdirp(dir);
  const ts = new Date().toISOString().replace(/[:.]/g, '-');
  const id = `inc-${ts}`;
  const fp = path.join(dir, `${id}.json`);
  writeUtf8(fp, JSON.stringify({ id, receivedAt: new Date().toISOString(), payload }, null, 2) + '\n');
  return { id, path: fp };
}
function incidentListCmd(root) {
  root = absRoot(root || process.cwd());
  const dir = _incidentsDir(root);
  // 1.9.387 (UR-0088, 5лІҲм§ё мҷёл¶ҖнҸүк°Җ мқјкҙҖм„ұ): л№Ҳ мјҖмқҙмҠӨлҸ„ --json мӢң кө¬мЎ°нҷ” м¶ңл Ҙ.
  if (!exists(dir)) { if (has('--json')) log(JSON.stringify({ total: 0, items: [] }, null, 2)); else log('(incidents м—ҶмқҢ вҖ” leerness webhook serve лЎң мҲҳмӢ  к°ҖлҠҘ)'); return; }
  const files = fs.readdirSync(dir).filter(f => f.endsWith('.json')).sort().reverse();
  if (has('--json')) {
    const items = files.slice(0, 50).map(f => { try { return JSON.parse(read(path.join(dir, f))); } catch { return null; } }).filter(Boolean);
    log(JSON.stringify({ total: files.length, items }, null, 2));
    return;
  }
  log(`# leerness incident list (1.9.147)`);
  log(`мҙқ ${files.length}кұҙ${files.length > 20 ? ' (мөңк·ј 20)' : ''}`);
  for (const f of files.slice(0, 20)) {
    try {
      const j = JSON.parse(read(path.join(dir, f)));
      const e = j.payload?.error || j.payload?.message || '(no description)';
      log(`  ${j.id}  В·  ${String(e).slice(0, 80)}`);
    } catch {}
  }
}
function incidentShowCmd(root, id) {
  root = absRoot(root || process.cwd());
  const fp = path.join(_incidentsDir(root), `${id}.json`);
  if (!exists(fp)) return fail(`incident м—ҶмқҢ: ${id}`);
  log(read(fp));
}
async function incidentHandleCmd(root, id) {
  root = absRoot(root || process.cwd());
  const dir = _incidentsDir(root);
  let target = id;
  if (!target) {
    if (!exists(dir)) return fail('incidents м—ҶмқҢ');
    const files = fs.readdirSync(dir).filter(f => f.endsWith('.json')).sort();
    if (!files.length) return fail('incidents м—ҶмқҢ');
    target = files[files.length - 1].replace('.json', '');
  }
  const fp = path.join(dir, `${target}.json`);
  if (!exists(fp)) return fail(`incident м—ҶмқҢ: ${target}`);
  const j = JSON.parse(read(fp));
  const p = _readPermissions(root);
  log(`# leerness incident handle (1.9.147)`);
  log(`incident: ${j.id}  В·  permission mode: ${p.mode || 'basic'}`);
  const err = j.payload?.error || j.payload?.message || '';
  const stack = j.payload?.stack || '';
  log(`error: ${String(err).slice(0, 200)}`);
  if (stack) log(`stack head:\n${String(stack).split('\n').slice(0, 4).join('\n')}`);
  // (1) feature impact мһҗлҸҷ нҡҢмҲҳ вҖ” error нӮӨмӣҢл“ң л§Өм№ӯ
  try {
    const { nodes: fn } = _readFeatureGraph(root);
    if (fn.length) {
      const keywords = String(err).toLowerCase().match(/[\wк°Җ-нһЈ]{3,}/g) || [];
      const matched = fn.find(n => keywords.some(k => n.title.toLowerCase().includes(k)));
      if (matched) {
        const impacted = _featureImpactBfs(fn, matched.id);
        log(`\nрҹ”— feature impact: ${matched.id} ${matched.title} вҶ’ ${impacted.length} feature мҳҒн–Ҙ`);
        for (const it of impacted.slice(0, 5)) log(`  вҖў ${it.id} ${it.title}`);
      }
    }
  } catch {}
  // (2) lessons мһҗлҸҷ нҡҢмҲҳ
  try {
    const keywords = String(err).toLowerCase().match(/[\wк°Җ-нһЈ]{4,}/g) || [];
    if (keywords.length) {
      const r = cp.spawnSync(process.execPath, [__filename, 'lessons', '--path', root, '--query', keywords[0], '--limit', '3'],
        { encoding: 'utf8', timeout: 8000, env: { ...process.env, LEERNESS_INTERNAL: '1', LEERNESS_NO_PROMPT: '1' } });
      if (r.status === 0 && /мҙқ \d+кұҙ л°ңкІ¬/.test(r.stdout)) {
        const block = r.stdout.split('\n').slice(0, 12).join('\n');
        log(`\nрҹ“ҡ кҙҖл Ё lessons:\n${block}`);
      }
    }
  } catch {}
  // (3) к¶Ңн•ң нҷ•мқё нӣ„ мһҗлҸҷ fix мӢңлҸ„ (MVP: dry-run вҖ” мӢӨм ң LLM нҳём¶ңмқҖ мӮ¬мҡ©мһҗк°Җ leerness agent лЎң)
  log(`\nрҹ’Ў мһҗлҸҷ fix мӢңлҸ„:`);
  if (permissionCheck(root, 'shell.exec', 'npm')) {
    log(`  вҖў к¶Ңн•ң OK вҖ” verify-code мӢӨн–ү к¶ҢмһҘ: leerness verify-code .`);
  } else {
    log(`  вҡ  basic к¶Ңн•ң лӘЁл“ң вҖ” fix/test мһҗлҸҷ мӢӨн–ү л¶Ҳк°Җ. extended/full лЎң ліҖкІҪ: leerness permissions set extended`);
  }
  // (4) incident мғҒнғң к°ұмӢ 
  j.handledAt = new Date().toISOString();
  j.permissionMode = p.mode || 'basic';
  writeUtf8(fp, JSON.stringify(j, null, 2) + '\n');
  ok(`incident handled: ${j.id} (л¶„м„қ/нҡҢмҲҳ мҷ„лЈҢ)`);
  log(`  вҶ’ нӣ„мҶҚ: leerness agent "fix: ${String(err).slice(0, 80)}" / leerness verify-code . / leerness deploy auto`);
}

// ---- (3) Webhook Listener ----
function _hmacSha256(key, body) {
  const crypto = require('crypto');
  return crypto.createHmac('sha256', key).update(body).digest('hex');
}
async function webhookServeCmd(root) {
  root = absRoot(root || process.cwd());
  const port = parseInt(arg('--port', process.env.LEERNESS_WEBHOOK_PORT || '9876'), 10);
  const secret = arg('--secret', process.env.LEERNESS_WEBHOOK_SECRET || '');
  const http = require('http');
  log(`# leerness webhook serve (1.9.147)`);
  log(`port: ${port}  В·  HMAC: ${secret ? 'нҷңм„ұ (X-Leerness-Signature)' : 'л№„нҷңм„ұ вҖ” LEERNESS_WEBHOOK_SECRET к¶ҢмһҘ'}`);
  log(`incidents dir: ${rel(root, _incidentsDir(root))}`);
  log(`POST endpoint: http://localhost:${port}/incident`);
  log(`н—¬мҠӨ мІҙнҒ¬: curl http://localhost:${port}/health`);
  const server = http.createServer(async (req, res) => {
    const url = req.url || '';
    if (req.method === 'GET' && url === '/health') {
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ ok: true, version: VERSION, port }));
      return;
    }
    if (req.method === 'POST' && url === '/incident') {
      let body = '';
      req.on('data', c => { body += c; if (body.length > 100000) { req.destroy(); } });
      req.on('end', () => {
        try {
          if (secret) {
            const sig = req.headers['x-leerness-signature'] || '';
            const expected = _hmacSha256(secret, body);
            if (sig !== expected) {
              res.writeHead(401, { 'Content-Type': 'application/json' });
              res.end(JSON.stringify({ ok: false, error: 'invalid signature' }));
              return;
            }
          }
          let payload;
          try { payload = JSON.parse(body); } catch { payload = { raw: body }; }
          const saved = _saveIncident(root, payload);
          res.writeHead(202, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: true, incident: saved.id }));
          log(`рҹ“Ҙ incident received: ${saved.id} В· error="${String(payload?.error || payload?.message || '').slice(0, 80)}"`);
        } catch (e) {
          res.writeHead(500, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: false, error: e.message }));
        }
      });
      return;
    }
    res.writeHead(404); res.end('Not Found');
  });
  server.listen(port, () => {
    ok(`listening on port ${port}`);
    log(`(Ctrl+C лЎң мў…лЈҢ)`);
  });
  // мў…лЈҢ мӢңк·ёл„җ (SIGINT/SIGTERM) лҢҖкё° вҖ” auto-close м•Ҳ н•Ё
  process.on('SIGINT', () => { log('\nмӨ‘лӢЁ мӢ нҳё вҖ” м„ңлІ„ мў…лЈҢ'); server.close(); process.exit(0); });
  process.on('SIGTERM', () => { server.close(); process.exit(0); });
}

// ---- (4) Deploy Auto ----
async function deployAutoCmd(root, service) {
  root = absRoot(root || process.cwd());
  const j = _readCredentials(root);
  if (!service) {
    log('# leerness deploy auto (1.9.147)');
    log('мӮ¬мҡ©лІ•: leerness deploy auto <service>');
    log('л“ұлЎқлҗң м„ңл№„мҠӨ:');
    for (const [name, meta] of Object.entries(j.services || {})) {
      log(`  ${name}: ${meta.deployCommand || '(deploy лӘ…л № лҜём„Өм •)'}`);
    }
    if (!Object.keys(j.services || {}).length) log('  (м—ҶмқҢ вҖ” leerness creds register <service> --env-var <NAME> --deploy "<cmd>")');
    return;
  }
  const meta = j.services?.[service];
  if (!meta) return fail(`л“ұлЎқлҗң м„ңл№„мҠӨ м—ҶмқҢ: ${service} вҖ” leerness creds register лЁјм Җ`);
  if (!meta.deployCommand) return fail(`deploy лӘ…л № лҜём„Өм •: ${service} вҖ” leerness creds register --deploy "<cmd>"`);
  // нҷҳкІҪліҖмҲҳ + л§ҢлЈҢ кІҖмҰқ
  const missing = (meta.envVars || []).filter(v => !process.env[v]);
  if (missing.length) { fail(`нҷҳкІҪліҖмҲҳ лҲ„лқҪ: ${missing.join(', ')} вҖ” .env лҳҗлҠ” OS keychainм—җм„ң export`); process.exitCode = 1; return; }
  if (meta.tokenLifetimeHours && meta.lastRefreshed) {
    const age = Date.now() - new Date(meta.lastRefreshed).getTime();
    if (age > meta.tokenLifetimeHours * 3600 * 1000) {
      warn(`вҡ  ${service} нҶ нҒ° л§ҢлЈҢ к°ҖлҠҘ (${Math.floor(age / 3600000)}мӢңк°„ кІҪкіј vs н•ңлҸ„ ${meta.tokenLifetimeHours}h)`);
      log(`  вҶ’ мһ¬лЎңк·ёмқё нӣ„: leerness creds refresh ${service}`);
      if (!has('--force')) { process.exitCode = 1; return; }
    }
  }
  // к¶Ңн•ң нҷ•мқё
  if (!permissionCheck(root, 'shell.exec', meta.deployCommand.split(/\s+/)[0])) {
    return fail(`shell.exec к¶Ңн•ң л¶ҖмЎұ (нҳ„мһ¬: ${_readPermissions(root).mode}) вҖ” leerness permissions set extended к¶ҢмһҘ`);
  }
  log(`# leerness deploy auto (1.9.147)`);
  log(`service: ${service}  В·  command: ${meta.deployCommand}`);
  if (has('--dry-run')) { log('(dry-run) мӢӨм ң мӢӨн–ү мҠӨнӮө'); return; }
  const t0 = Date.now();
  // 1.9.150: runCommandSafe вҖ” deploy лӘ…л № sandbox (env scrub + permissions кІҖмҰқ + observability)
  const r = runCommandSafe(meta.deployCommand, [], { cwd: root, root, timeout: 10 * 60 * 1000, allowShell: true, stdio: 'inherit', kind: 'deploy_auto', label: `deploy-${service}` });
  const dt = Date.now() - t0;
  if (r.status === 0) {
    ok(`deploy м„ұкіө: ${service} (${dt}ms)`);
    // lastRefreshed мһҗлҸҷ к°ұмӢ  вҖ” м„ұкіө мӢң л§ҢлЈҢ м№ҙмҡҙн„° reset
    j.services[service].lastRefreshed = new Date().toISOString();
    _writeCredentials(root, j);
    // task-log кё°лЎқ
    try { append(taskLogPath(root), `\n## ${today()} deploy auto (1.9.147)\n- service: ${service}\n- duration: ${dt}ms\n- status: success\n`); } catch {}
  } else {
    fail(`deploy мӢӨнҢЁ: ${service} (exit ${r.status}, ${dt}ms)`);
    process.exitCode = 1;
  }
}

// 1.9.85: leerness health вҖ” мў…н•© н—¬мҠӨ мІҙнҒ¬ (drift + ліҙм•Ҳ + skill + MCP + лҲ„м Ғ)
const _health = require('../lib/health');
// 1.9.423 (UR-0025/UR-0125 нҒ° н•ёл“Өлҹ¬ лӘЁл“Ҳнҷ” 8лІҲм§ё): healthCmd вҶ’ lib/health.js (DI мң„мһ„, thin wrapper)
function healthCmd(root) { return _health.healthCmd(root, { VERSION, STATUSES, has, arg, harnessPath: __filename, listAllSkills, planPath, readProgressRows, readRules, envDiff, _collectSecretFindings, _readUsageStats, _loadDecisions, _loadLessons, _loadShellFailures, _readFeatureGraph, _scanShellScriptsEncoding, _shellEnvDrift, _computeMilestones, _computeRecentChanges, _computeRoundHistory, _collectPyFiles, _analyzePyFile, _collectRuntimeEnv, _listAPISkills, _matchAPISkills, _mcpToolCount }); }

function usageStatsCmd(root) {
  root = absRoot(root || process.cwd());
  const stats = _readUsageStats(root);
  if (has('--json')) { log(JSON.stringify(stats, null, 2)); return; }
  log(`# leerness usage stats (1.9.38)`);
  log(`since: ${stats.since || '(unknown)'} В· last: ${stats.lastAt || '(none)'}`);
  log('');
  const entries = Object.entries(stats.commands || {}).sort((a, b) => b[1] - a[1]);
  if (!entries.length) {
    log('  (мӮ¬мҡ© кё°лЎқ м—ҶмқҢ)');
    return;
  }
  log(`| лӘ…л № | нҳём¶ң мҲҳ |`);
  log(`|---|---:|`);
  for (const [cmd, n] of entries.slice(0, 30)) log(`| ${cmd} | ${n} |`);
  const total = entries.reduce((s, [, n]) => s + n, 0);
  log('');
  log(`мҙқ ${total} нҡҢ нҳём¶ң В· мў…лҘҳ ${entries.length} к°Җм§Җ`);
  if (stats.drift) {
    log('');
    log(`drift нҶөкі„: critical л°ңкІ¬ ${stats.drift.criticalSeen || 0} В· skip ${stats.drift.skipped || 0} В· мһҗлҸҷ н•ҙмҶҢ ${stats.drift.autoResolved || 0}`);
    if ((stats.drift.skipped || 0) > 5) {
      log(`рҹ’Ў drift кІҪкі  ${stats.drift.skipped}нҡҢ мҠӨнӮө вҶ’ 1.9.38 н•ҷмҠө: мһ„кі„ мһҗлҸҷ мҷ„нҷ” (--no-drift-check л№ҲлҸ„ вүҘ5)`);
    }
  }
  // 1.9.70: MCP tools/call мһҗлҸҷ мӮ¬мҡ© нҶөкі„ вҖ” м–ҙл–Ө лҸ„кө¬к°Җ мһҗмЈј/л“ңл¬јкІҢ нҳём¶ңлҗҳлҠ”м§Җ
  if (stats.mcp && stats.mcp.tools && Object.keys(stats.mcp.tools).length) {
    const mcpEntries = Object.entries(stats.mcp.tools).sort((a, b) => b[1] - a[1]);
    const mcpTotal = mcpEntries.reduce((s, [, n]) => s + n, 0);
    log('');
    log(`## рҹ”Ң MCP tools/call нҶөкі„ (1.9.70) вҖ” last: ${stats.mcp.lastAt || '(none)'}`);
    log(`| MCP лҸ„кө¬ | нҳём¶ң мҲҳ |`);
    log(`|---|---:|`);
    for (const [tool, n] of mcpEntries) log(`| ${tool} | ${n} |`);
    log('');
    log(`мҙқ ${mcpTotal} нҡҢ MCP нҳём¶ң В· лҸ„кө¬ ${mcpEntries.length} к°Җм§Җ мӮ¬мҡ©`);
    // л“ңл¬јкІҢ нҳём¶ңлҗҳлҠ” лҸ„кө¬ мӢқлі„ (м „мІҙмқҳ 5% лҜёл§Ң нҳём¶ң)
    const threshold = Math.max(1, Math.floor(mcpTotal * 0.05));
    const rare = mcpEntries.filter(([, n]) => n <= threshold).map(([t]) => t);
    if (rare.length) log(`рҹ’Ў л“ңл¬јкІҢ нҳём¶ңлҗң лҸ„кө¬ (вүӨ${threshold}): ${rare.slice(0, 6).join(', ')}`);
  }
}

// 1.9.38: task sync вҖ” TodoWrite/мҷёл¶Җ JSONм—җм„ң leerness taskлЎң mirror
// 1.9.60: leerness task export [--to <todo.json>] [--json]
// progress-tracker вҶ’ TodoWrite JSON нҳ•мӢқ (status: completed/in_progress/pending)
function taskExportCmd(root) {
  root = absRoot(root || process.cwd());
  const out = arg('--to', null);
  const rows = readProgressRows(root);
  // leerness status вҶ’ TodoWrite status л§Өн•‘
  const statusMap = { 'done': 'completed', 'in-progress': 'in_progress', 'planned': 'pending', 'requested': 'pending', 'dropped': 'cancelled', 'in_progress': 'in_progress', 'incomplete': 'in_progress', 'blocked': 'in_progress', 'on-hold': 'pending' };
  const todos = rows.map(r => ({
    content: r.request,
    status: statusMap[r.status] || 'pending',
    activeForm: r.nextAction || r.request.slice(0, 40)
  }));
  if (out) {
    writeUtf8(path.resolve(out), JSON.stringify(todos, null, 2) + '\n');
    log(`# leerness task export (1.9.60)`);
    log(`exported: ${todos.length} task вҶ’ ${path.resolve(out)}`);
    log(``);
    log(`рҹ’Ў лӢӨмқҢ: л©”мқё м—җмқҙм „нҠёк°Җ мқҙ JSONмқ„ TodoWriteлЎң import к°ҖлҠҘ`);
    return;
  }
  if (has('--json')) { log(JSON.stringify(todos, null, 2)); return; }
  log(`# leerness task export (1.9.60)`);
  log(`мҙқ ${todos.length} task (--to <file>лЎң м ҖмһҘ)`);
  for (const t of todos.slice(0, 10)) {
    log(`  - [${t.status}] ${t.content.slice(0, 60)}`);
  }
  if (todos.length > 10) log(`  ... ${todos.length - 10}кұҙ лҚ”`);
}

function taskSyncCmd(root) {
  root = absRoot(root || process.cwd());
  const file = arg('--from', null);
  if (!file) {
    fail('мӮ¬мҡ©лІ•: leerness task sync --from <todo.json>\n  нҢҢмқј нҳ•мӢқ: [{"content":"...","status":"completed|in_progress|pending","activeForm":"..."}]');
    return process.exit(1);
  }
  const full = path.resolve(file);
  if (!exists(full)) { fail(`нҢҢмқј м—ҶмқҢ: ${full}`); return process.exit(1); }
  let todos;
  try { todos = JSON.parse(read(full)); }
  catch (e) { fail(`JSON нҢҢмӢұ мӢӨнҢЁ: ${e.message}`); return process.exit(1); }
  if (!Array.isArray(todos)) { fail('JSON мөңмғҒмң„лҠ” л°°м—ҙмқҙм–ҙм•ј н•Ё'); return process.exit(1); }
  let imported = 0, updated = 0;
  for (const t of todos) {
    if (!t || !t.content) continue;
    const status = t.status === 'completed' ? 'done' : t.status === 'in_progress' ? 'in-progress' : 'planned';
    // мқҙлҜё к°ҷмқҖ request мһҲлҠ”м§Җ
    const existing = readProgressRows(root).find(r => r.request === t.content);
    if (existing) {
      if (existing.status !== status) {
        upsertProgress(root, { id: existing.id, status });
        updated++;
      }
    } else {
      const id = nextId(root, 'T');
      upsertProgress(root, { id, status, request: t.content, evidence: 'todowrite-sync', nextAction: t.activeForm || 'лӢӨмқҢ м•Ўм…ҳ' });
      imported++;
    }
  }
  log(`# leerness task sync (1.9.38)`);
  log(`from: ${full}`);
  log(`imported: ${imported} В· updated: ${updated} В· total in source: ${todos.length}`);
  if (has('--json')) log(JSON.stringify({ imported, updated, total: todos.length }, null, 2));
}

// 1.9.35 к°ңм„  #3: contract verify <spec.md> <impl.js>
// мӮ¬м–‘ л¬ём„ң(spec.md)м—җ лӘ…мӢңлҗң н•ЁмҲҳ мқҙлҰ„мқҙ мӢӨм ң module.exportsм—җ лӘЁл‘җ мһҲлҠ”м§Җ кІҖмӮ¬.
// мӮ¬мҡ© мҳҲ: leerness contract verify TICK_SPEC.md src/format.js
function contractVerifyCmd(specPath, implPath) {
  // 1.9.398 (6лІҲм§ё мҷёл¶ҖнҸүк°Җ/codex P1-C, UR-0099): --json лӘЁл“ң м—җлҹ¬лҠ” кө¬мЎ°нҷ” м¶ңл Ҙ(н…ҚмҠӨнҠё лҢҖмӢ ) вҖ” AI м—җмқҙм „нҠё JSON.parse ліҙнҳё.
  const _j = has('--json');
  if (!specPath || !implPath) { failJson(_j, 'missing_args', 'мӮ¬мҡ©лІ•: leerness contract verify <spec.md> <impl.js>'); return process.exit(process.exitCode || 1); }
  const spec = absRoot('.') + path.sep; // dummy to avoid abs
  const specFile = path.resolve(specPath);
  const implFile = path.resolve(implPath);
  if (!exists(specFile)) { failJson(_j, 'spec_not_found', `spec нҢҢмқј м—ҶмқҢ: ${specFile}`); return process.exit(process.exitCode || 1); }
  if (!exists(implFile)) { failJson(_j, 'impl_not_found', `impl нҢҢмқј м—ҶмқҢ: ${implFile}`); return process.exit(process.exitCode || 1); }
  const specText = read(specFile);
  // 1.9.385 (UR-0086, 5thмҷёл¶ҖнҸүк°Җ): spec н•ЁмҲҳ/н•„л“ң м¶”м¶ңмқ„ мҲңмҲҳ нҢҢм„ң _parseContractSpec лЎң мң„мһ„.
  //   declared(к°•м„ м–ё): function мӢңк·ёлӢҲмІҳ + markdown bullet "- name(args)" вҖ” лҲ„лқҪкІҖмӮ¬ лҢҖмғҒ.
  //   mentioned(м•Ҫм–ёкёү): backtick `name(` вҖ” н‘ңмӢңл§Ң(кё°мЎҙ кҙҖлҢҖм„ұ мң м§Җ, мӮ°л¬ё мқёлқјмқё м–ёкёү мҳӨнғҗ л°©м§Җ).
  const parsedSpec = _parseContractSpec(specText);
  const declaredSpec = new Set(parsedSpec.declared);
  const fnSpec = new Set([...parsedSpec.declared, ...parsedSpec.mentioned]);  // н‘ңмӢңмҡ© м „мІҙ
  const fieldSpec = new Set(parsedSpec.fields);
  // 1.9.36 BUG-fix: require()лҠ” side-effect мӢӨн–ү мң„н—ҳ (CLI мҠӨнҒ¬лҰҪнҠёлҠ” requireлЎң мӢӨн–үлҗЁ).
  // лҢҖмӢ  м •м Ғ мҶҢмҠӨ л¶„м„қ вҖ” module.exports = { foo, bar } / exports.foo = ... / module.exports.foo = ... нҢЁн„ҙ grep.
  const implSrc = read(implFile);
  // 1.9.429 (UR-0129): лёҢл ҲмқҙмҠӨ к· нҳ• top-level нӮӨ(л©ҖнӢ°лқјмқё module.exports м•Ҳм „) + ESM export мқёмӢқ вҖ” pure-utils лӢЁмқјм¶ңмІҳ
  const implExports = new Set(_parseImplExports(implSrc));
  // кІҖмӮ¬: spec к°•м„ м–ё(function мӢңк·ёлӢҲмІҳ + markdown bullet) н•ЁмҲҳ мӨ‘ impl exportsм—җ м—ҶлҠ” кІғ.
  // 1.9.385 (UR-0086): кё°мЎҙ `specText.includes('function '+fn)` к°Җл“ңлҠ” bullet/backtick м¶”м¶ңлӘ…мқ„ л¬ҙл Ҙнҷ”н•ҳлҚҳ мһ мһ¬ FN.
  //   вҶ’ declaredSpec(к°•м„ м–ё) кё°мӨҖмңјлЎң көҗмІҙ: bullet н•ЁмҲҳлҸ„ лҲ„лқҪ к°җм§Җ, backtick м•Ҫм–ёкёүмқҖ кҙҖлҢҖ(кІҖмӮ¬ м ңмҷё) мң м§Җ.
  const missing = [];
  for (const fn of declaredSpec) {
    if (!implExports.has(fn)) missing.push(fn);
  }
  const fieldMissing = [];
  for (const f of fieldSpec) {
    if (!new RegExp(`\\b${f}\\b`).test(implSrc)) fieldMissing.push(f);
  }
  // м¶ңл Ҙ
  if (has('--json')) {
    const okJson = missing.length === 0 && fieldMissing.length === 0;
    log(JSON.stringify({
      spec: specFile, impl: implFile,
      specFunctions: [...fnSpec], specFields: [...fieldSpec],
      implExports: [...implExports],
      missingFunctions: missing, missingFields: fieldMissing,
      ok: okJson
    }, null, 2));
    if (!okJson) process.exitCode = 1;  // 1.9.415 (9th мҷёл¶ҖнҸүк°Җ Opus P2): --json л¶Ҳмқјм№ҳлҸ„ exit 1 (кё°мЎҙм—” exit 0 вҶ’ CI к°Җ кі„м•ҪмӢӨнҢЁ лӘ» мһЎмқҢ)
    return;
  }
  log(`# leerness contract verify (1.9.35)`);
  log(`spec: ${rel(process.cwd(), specFile)}`);
  log(`impl: ${rel(process.cwd(), implFile)}`);
  log(``);
  log(`spec лӘ…мӢң н•ЁмҲҳ: ${[...fnSpec].join(', ') || '(м—ҶмқҢ)'}`);
  log(`spec лӘ…мӢң н•„л“ң: ${[...fieldSpec].join(', ') || '(м—ҶмқҢ)'}`);
  log(`impl exports: ${[...implExports].join(', ') || '(м—ҶмқҢ)'}`);
  log(``);
  if (missing.length) {
    log(`вң— лҲ„лқҪлҗң н•ЁмҲҳ (${missing.length}кұҙ):`);
    for (const m of missing) log(`    - ${m}`);
  } else log(`вң“ лӘЁл“  spec н•ЁмҲҳк°Җ implм—җ мЎҙмһ¬`);
  if (fieldMissing.length) {
    log(`вң— лҲ„лқҪлҗң н•„л“ң (${fieldMissing.length}кұҙ):`);
    for (const m of fieldMissing) log(`    - ${m}`);  // 1.9.426 (10th мҷёл¶ҖнҸүк°Җ Opus P3): л Ҳкұ°мӢң 'tick.' н”„лҰ¬н”ҪмҠӨ м ңкұ° вҖ” ## Fields лІ”мҡ©нҷ”(1.9.417) н‘ңмӢң мһ”мһ¬. JSON мқҖ мқҙлҜё м •мғҒ.
  } else log(`вң“ лӘЁл“  spec н•„л“ңк°Җ impl мҶҢмҠӨм—җ мЎҙмһ¬`);
  const ok = missing.length === 0 && fieldMissing.length === 0;
  log('');
  log(ok ? 'вң… contract OK' : 'вқҢ contract л¶Ҳмқјм№ҳ');
  if (!ok) process.exitCode = 1;
}

// 1.9.35 к°ңм„  #2: reuse autodetect [path]
// src/*.jsмқҳ module.exportsлҘј мҠӨмә”н•ҙм„ң reuse-map.mdм—җ capability нӣ„ліҙ л“ұлЎқ.
function reuseAutodetectCmd(root) {
  root = absRoot(root || process.cwd());
  // 1.9.36 BUG-fix: src/л§Ңмқҙ м•„лӢҲлқј bin/, lib/, app/лҸ„ мҠӨмә”. require() лҢҖмӢ  м •м Ғ л¶„м„қ (side-effect м°ЁлӢЁ).
  const candidateDirs = ['src', 'bin', 'lib', 'app'].filter(d => exists(path.join(root, d)));
  if (!candidateDirs.length) { failJson(has('--json'), 'no_scan_dir', `мҠӨмә”н•  л””л үнҶ лҰ¬ м—ҶмқҢ (src/, bin/, lib/, app/ мӨ‘ н•ҳлӮҳ н•„мҡ”): ${root}`); return process.exit(process.exitCode || 1); }  // 1.9.404 (UR-0105 мһ”м—¬): --json м—җлҹ¬ кө¬мЎ°нҷ”
  const found = [];
  for (const dir of candidateDirs) {
    const files = fs.readdirSync(path.join(root, dir)).filter(f => f.endsWith('.js'));
    for (const f of files) {
      const full = path.join(root, dir, f);
      const src = read(full);
      // м •м Ғ л¶„м„қ: module.exports = { foo, bar } / exports.foo = / module.exports.foo =
      const names = new Set();
      for (const m of src.matchAll(/module\.exports\s*=\s*\{([^}]+)\}/g)) {
        for (const k of m[1].split(',')) {
          const name = k.replace(/:.*/, '').trim();
          if (/^[A-Za-z_$][\w$]*$/.test(name)) names.add(name);
        }
      }
      for (const m of src.matchAll(/(?:module\.)?exports\.([A-Za-z_$][\w$]*)\s*=/g)) names.add(m[1]);
      for (const name of names) {
        if (name.startsWith('_')) continue; // internal helpers м ңмҷё
        found.push({ file: `${dir}/${f}`, name });
      }
    }
  }
  if (has('--json')) {
    log(JSON.stringify({ project: path.basename(root), found }, null, 2));
    return;
  }
  log(`# leerness reuse autodetect (1.9.35)`);
  log(`project: ${path.basename(root)}`);
  log(`л°ңкІ¬лҗң capability нӣ„ліҙ: ${found.length}кұҙ`);
  log('');
  log('| Capability | Where | Kind | Note |');
  log('|---|---|---|---|');
  for (const c of found) log(`| ${c.name} | ${c.file} | util | (autodetect from module.exports) |`);
  log('');
  if (has('--apply')) {
    // reuse-map.mdм—җ м¶”к°Җ (н—ӨлҚ” ліҙмЎҙ + нӣ„ліҙ лқјмқё append)
    const reusePath = path.join(root, '.harness', 'reuse-map.md');
    if (!exists(reusePath)) {
      fail(`.harness/reuse-map.md м—ҶмқҢ вҖ” leerness init лЁјм Җ мӢӨн–ү`);
      return process.exit(1);
    }
    let body = read(reusePath);
    let added = 0;
    for (const c of found) {
      if (body.includes(`| ${c.name} |`)) continue; // мқҙлҜё мһҲмқҢ
      body += `| ${c.name} | ${c.file} | util | autodetect 1.9.35 |\n`;
      added++;
    }
    writeUtf8(reusePath, body);
    log(`вң“ ${added}кұҙ reuse-map.mdм—җ м¶”к°ҖлҗЁ`);
  } else {
    log(`(--apply лЎң reuse-map.mdм—җ мһҗлҸҷ м¶”к°Җ)`);
  }
}

// 1.9.165: leerness web вҖ” playwright bridge MVP (opt-in мқҳмЎҙм„ұ, 5лҠҘл Ҙ #1 ліҙк°•)
//   leerness мһҗмІҙм—җлҠ” playwright лҜёнҸ¬н•Ё (мқҳмЎҙм„ұ 0 мӣҗм№ҷ мң м§Җ). мӮ¬мҡ©мһҗк°Җ `npm i -g playwright` лі„лҸ„ м„Өм№ҳ мӢң мһҗлҸҷ detect.
//   permissions.browser=true н•„мҡ” (1.9.146 к¶Ңн•ң мӢңмҠӨн…ң нҶөн•©).
function _tryLoadPlaywright() {
  // мӮ¬мҡ©мһҗ кёҖлЎңлІҢ + лЎңм»¬ лӘЁл‘җ мӢңлҸ„
  const candidates = ['playwright', 'playwright-core'];
  for (const id of candidates) {
    try { return { ok: true, lib: require(id), name: id }; } catch {}
  }
  // кёҖлЎңлІҢ npm root мӢңлҸ„
  try {
    const r = cp.spawnSync('npm', ['root', '-g'], { encoding: 'utf8', timeout: 5000, shell: true });
    if (r.status === 0) {
      const globalRoot = (r.stdout || '').trim();
      for (const id of candidates) {
        try { return { ok: true, lib: require(path.join(globalRoot, id)), name: id, source: 'global' }; } catch {}
      }
    }
  } catch {}
  return { ok: false, error: 'playwright лҜём„Өм№ҳ вҖ” `npm i -g playwright` лҳҗлҠ” н”„лЎңм қнҠём—җ `npm i playwright` нӣ„ лӢӨмӢң мӢңлҸ„' };
}
function webCmd(root, sub, ...args) {
  root = absRoot(root || process.cwd());
  if (!sub || sub === 'check') {
    const r = _tryLoadPlaywright();
    if (has('--json')) {
      log(JSON.stringify({ installed: r.ok, name: r.name || null, source: r.source || 'local', error: r.error || null, permissions: _readPermissions(root).browser || false }, null, 2));
      return;
    }
    log(`# leerness web check (1.9.165)`);
    if (r.ok) {
      log(`вң“ playwright л°ңкІ¬: ${r.name}${r.source ? ` (${r.source})` : ''}`);
      log(`  вҶ’ leerness web screenshot <url> --out file.png мӮ¬мҡ© к°ҖлҠҘ`);
    } else {
      log(`вң— ${r.error}`);
    }
    const perms = _readPermissions(root);
    log(`permissions.browser: ${perms.browser ? 'вң“ н—Ҳмҡ©' : 'вң— кұ°л¶Җ (basic лӘЁл“ң)'}`);
    if (!perms.browser) log(`  вҶ’ leerness permissions set extended  лҳҗлҠ”  set full`);
    return;
  }
  if (sub === 'screenshot') {
    const url = args[0] || arg('--url', '');
    const outPath = arg('--out', '');
    if (!url) return fail('leerness web screenshot <url> --out <file.png> н•„мҡ”');
    if (!outPath) return fail('--out <file.png> кІҪлЎң н•„мҡ”');
    if (!/^https?:\/\//.test(url)) return fail(`URL нҳ•мӢқ мҳӨлҘҳ (http:// лҳҗлҠ” https://): ${url}`);
    if (!permissionCheck(root, 'browser', url)) {
      return fail(`permissions.browser=false (нҳ„мһ¬: ${_readPermissions(root).mode}) вҖ” leerness permissions set extended лҳҗлҠ” full к¶ҢмһҘ`);
    }
    const r = _tryLoadPlaywright();
    if (!r.ok) { fail(r.error); process.exitCode = 1; return; }
    const t0 = Date.now();
    log(`# leerness web screenshot (1.9.165)`);
    log(`URL: ${url}  вҶ’  ${outPath}`);
    return (async () => {
      let browser;
      try {
        const { chromium } = r.lib;
        if (!chromium) { fail('playwright.chromium м—ҶмқҢ вҖ” `npx playwright install chromium` н•„мҡ”'); process.exitCode = 1; return; }
        browser = await chromium.launch({ headless: true });
        const page = await browser.newPage();
        await page.goto(url, { timeout: 30000, waitUntil: 'networkidle' });
        await page.screenshot({ path: outPath, fullPage: true });
        await browser.close();
        const dt = Date.now() - t0;
        ok(`screenshot мҷ„лЈҢ: ${outPath} (${dt}ms)`);
        try { _recordRun(root, { kind: 'web_screenshot', url, outPath, durationMs: dt, ok: true }); } catch {}
      } catch (e) {
        fail(`screenshot мӢӨнҢЁ: ${e.message}`);
        if (browser) try { await browser.close(); } catch {}
        try { _recordRun(root, { kind: 'web_screenshot', url, durationMs: Date.now() - t0, ok: false, error: e.message }); } catch {}
        process.exitCode = 1;
      }
    })();
  }
  if (sub === 'extract') {
    const url = args[0] || arg('--url', '');
    const selector = arg('--selector', '');
    if (!url || !selector) return fail('leerness web extract <url> --selector "css-selector" н•„мҡ”');
    if (!/^https?:\/\//.test(url)) return fail(`URL нҳ•мӢқ мҳӨлҘҳ: ${url}`);
    if (!permissionCheck(root, 'browser', url)) {
      return fail(`permissions.browser=false вҖ” leerness permissions set extended лҳҗлҠ” full`);
    }
    const r = _tryLoadPlaywright();
    if (!r.ok) { fail(r.error); process.exitCode = 1; return; }
    const t0 = Date.now();
    return (async () => {
      let browser;
      try {
        const { chromium } = r.lib;
        if (!chromium) { fail('playwright.chromium м—ҶмқҢ вҖ” `npx playwright install chromium`'); process.exitCode = 1; return; }
        browser = await chromium.launch({ headless: true });
        const page = await browser.newPage();
        await page.goto(url, { timeout: 30000, waitUntil: 'networkidle' });
        const elements = await page.$$eval(selector, els => els.slice(0, 50).map(el => el.textContent?.trim() || ''));
        await browser.close();
        const dt = Date.now() - t0;
        const out = { url, selector, count: elements.length, elements, durationMs: dt };
        if (has('--json')) log(JSON.stringify(out, null, 2));
        else {
          log(`# leerness web extract (1.9.165)`);
          log(`URL: ${url} В· selector: ${selector} В· ${elements.length}к°ң (${dt}ms)`);
          elements.slice(0, 20).forEach((t, i) => log(`  ${i+1}. ${t.slice(0, 200)}${t.length > 200 ? 'вҖҰ' : ''}`));
        }
        try { _recordRun(root, { kind: 'web_extract', url, selector, count: elements.length, durationMs: dt, ok: true }); } catch {}
      } catch (e) {
        fail(`extract мӢӨнҢЁ: ${e.message}`);
        if (browser) try { await browser.close(); } catch {}
        process.exitCode = 1;
      }
    })();
  }
  fail(`м•Ң мҲҳ м—ҶлҠ” sub: ${sub} (check / screenshot / extract)`);
}

// 1.9.166: leerness pc вҖ” robotjs/nut-tree bridge MVP (opt-in мқҳмЎҙм„ұ, 5лҠҘл Ҙ #2 ліҙк°•)
//   leerness мһҗмІҙм—җлҠ” robotjs лҜёнҸ¬н•Ё (мқҳмЎҙм„ұ 0). мӮ¬мҡ©мһҗк°Җ `npm i -g robotjs` лі„лҸ„ м„Өм№ҳ мӢң мһҗлҸҷ detect.
//   permissions.mouse / .keyboard / .browser н•„мҡ” (1.9.146 к¶Ңн•ң мӢңмҠӨн…ң).
//   вҡ  full лӘЁл“ң к¶ҢмһҘ вҖ” IDE нҶөн•© мҷём—җлҠ” мң„н—ҳм„ұ лӘ…мӢң.
function _tryLoadPCAutomation() {
  // robotjs мҡ°м„ , fallback @nut-tree/nut-js
  const candidates = ['robotjs', '@nut-tree/nut-js'];
  for (const id of candidates) {
    try { return { ok: true, lib: require(id), name: id }; } catch {}
  }
  // кёҖлЎңлІҢ npm root мӢңлҸ„
  try {
    const r = cp.spawnSync('npm', ['root', '-g'], { encoding: 'utf8', timeout: 5000, shell: true });
    if (r.status === 0) {
      const globalRoot = (r.stdout || '').trim();
      for (const id of candidates) {
        try { return { ok: true, lib: require(path.join(globalRoot, id)), name: id, source: 'global' }; } catch {}
      }
    }
  } catch {}
  return { ok: false, error: 'robotjs/@nut-tree/nut-js лҜём„Өм№ҳ вҖ” `npm i -g robotjs` лҳҗлҠ” `npm i -g @nut-tree/nut-js` нӣ„ лӢӨмӢң мӢңлҸ„' };
}
function pcCmd(root, sub, ...args) {
  root = absRoot(root || process.cwd());
  if (!sub || sub === 'check') {
    const r = _tryLoadPCAutomation();
    const perms = _readPermissions(root);
    if (has('--json')) {
      log(JSON.stringify({
        installed: r.ok,
        name: r.name || null,
        source: r.source || 'local',
        error: r.error || null,
        permissions: {
          mouse: perms.mouse || false,
          keyboard: perms.keyboard || false,
          mode: perms.mode || 'basic'
        }
      }, null, 2));
      return;
    }
    log(`# leerness pc check (1.9.166)`);
    if (r.ok) {
      log(`вң“ ${r.name} л°ңкІ¬${r.source ? ` (${r.source})` : ''}`);
      log(`  вҶ’ leerness pc click / type / screenshot мӮ¬мҡ© к°ҖлҠҘ`);
    } else {
      log(`вң— ${r.error}`);
    }
    log('');
    log(`## к¶Ңн•ң (1.9.146)`);
    log(`  permissions.mouse:    ${perms.mouse ? 'вң“ н—Ҳмҡ©' : 'вң— кұ°л¶Җ'}`);
    log(`  permissions.keyboard: ${perms.keyboard ? 'вң“ н—Ҳмҡ©' : 'вң— кұ°л¶Җ'}`);
    log(`  нҳ„мһ¬ лӘЁл“ң: ${perms.mode || 'basic'}`);
    if (!perms.mouse || !perms.keyboard) {
      log('');
      log(`  рҹ’Ў нҷңм„ұнҷ”: leerness permissions set full  (вҡ  IDE нҶөн•© мҷём—җлҠ” мң„н—ҳ)`);
    }
    return;
  }
  if (sub === 'click') {
    const x = parseInt(args[0] || arg('--x', ''), 10);
    const y = parseInt(args[1] || arg('--y', ''), 10);
    if (!Number.isFinite(x) || !Number.isFinite(y)) return fail('leerness pc click <x> <y> н•„мҡ” (м •мҲҳ мўҢн‘ң)');
    if (!permissionCheck(root, 'mouse', `${x},${y}`)) {
      return fail(`permissions.mouse=false (нҳ„мһ¬: ${_readPermissions(root).mode}) вҖ” leerness permissions set full`);
    }
    const r = _tryLoadPCAutomation();
    if (!r.ok) { fail(r.error); process.exitCode = 1; return; }
    const t0 = Date.now();
    try {
      if (r.name === 'robotjs') {
        r.lib.moveMouse(x, y);
        r.lib.mouseClick();
      } else if (r.name === '@nut-tree/nut-js') {
        // nut-js лҠ” л№„лҸҷкё°
        return (async () => {
          const { mouse, Point, Button } = r.lib;
          await mouse.move([new Point(x, y)]);
          await mouse.click(Button.LEFT);
          const dt = Date.now() - t0;
          ok(`click (${x}, ${y}) вҖ” ${dt}ms`);
          try { _recordRun(root, { kind: 'pc_click', x, y, lib: r.name, durationMs: dt, ok: true }); } catch {}
        })();
      }
      const dt = Date.now() - t0;
      ok(`click (${x}, ${y}) вҖ” ${dt}ms`);
      try { _recordRun(root, { kind: 'pc_click', x, y, lib: r.name, durationMs: dt, ok: true }); } catch {}
    } catch (e) {
      fail(`click мӢӨнҢЁ: ${e.message}`);
      try { _recordRun(root, { kind: 'pc_click', x, y, lib: r.name, durationMs: Date.now() - t0, ok: false, error: e.message }); } catch {}
      process.exitCode = 1;
    }
    return;
  }
  if (sub === 'type') {
    const text = args[0] || arg('--text', '');
    if (!text) return fail('leerness pc type "<text>" н•„мҡ”');
    if (!permissionCheck(root, 'keyboard', text)) {
      return fail(`permissions.keyboard=false вҖ” leerness permissions set full`);
    }
    const r = _tryLoadPCAutomation();
    if (!r.ok) { fail(r.error); process.exitCode = 1; return; }
    const t0 = Date.now();
    try {
      if (r.name === 'robotjs') {
        r.lib.typeString(text);
      } else if (r.name === '@nut-tree/nut-js') {
        return (async () => {
          const { keyboard } = r.lib;
          await keyboard.type(text);
          const dt = Date.now() - t0;
          ok(`type ${text.length}мһҗ вҖ” ${dt}ms`);
          try { _recordRun(root, { kind: 'pc_type', chars: text.length, lib: r.name, durationMs: dt, ok: true }); } catch {}
        })();
      }
      const dt = Date.now() - t0;
      ok(`type ${text.length}мһҗ вҖ” ${dt}ms`);
      try { _recordRun(root, { kind: 'pc_type', chars: text.length, lib: r.name, durationMs: dt, ok: true }); } catch {}
    } catch (e) {
      fail(`type мӢӨнҢЁ: ${e.message}`);
      process.exitCode = 1;
    }
    return;
  }
  if (sub === 'screenshot') {
    // OS-level screenshot (robotjs.screen лҳҗлҠ” nut-js screen.capture)
    const outPath = arg('--out', '');
    if (!outPath) return fail('--out <file.png> кІҪлЎң н•„мҡ”');
    if (!permissionCheck(root, 'mouse', outPath)) {
      // mouse к¶Ңн•ңмңјлЎң screenshot лҸ„ м ңм–ҙ (л””мҠӨн”Ңл Ҳмқҙ м ‘к·ј)
      return fail(`permissions.mouse=false (нҳ„мһ¬: ${_readPermissions(root).mode}) вҖ” leerness permissions set full`);
    }
    const r = _tryLoadPCAutomation();
    if (!r.ok) { fail(r.error); process.exitCode = 1; return; }
    const t0 = Date.now();
    try {
      if (r.name === 'robotjs') {
        const img = r.lib.screen.capture();
        // robotjs мқҳ raw bitmap вҶ’ PNG ліҖнҷҳ н•„мҡ” вҖ” MVP м—җм„  raw м ҖмһҘ
        fs.writeFileSync(outPath, Buffer.from(img.image));
        const dt = Date.now() - t0;
        ok(`screenshot (raw) вҖ” ${dt}ms В· ${outPath}  (PNG ліҖнҷҳ: pngjs лҳҗлҠ” sharp лі„лҸ„)`);
        try { _recordRun(root, { kind: 'pc_screenshot', outPath, lib: r.name, durationMs: dt, ok: true }); } catch {}
      } else if (r.name === '@nut-tree/nut-js') {
        return (async () => {
          const { screen } = r.lib;
          const img = await screen.capture(outPath);
          const dt = Date.now() - t0;
          ok(`screenshot вҖ” ${dt}ms В· ${outPath}`);
          try { _recordRun(root, { kind: 'pc_screenshot', outPath, lib: r.name, durationMs: dt, ok: true }); } catch {}
        })();
      }
    } catch (e) {
      fail(`screenshot мӢӨнҢЁ: ${e.message}`);
      process.exitCode = 1;
    }
    return;
  }
  fail(`м•Ң мҲҳ м—ҶлҠ” sub: ${sub} (check / click / type / screenshot)`);
}

// 1.9.167: LSP м–ҙлҢ‘н„° MVP вҖ” мҪ”л“ң мқён…”лҰ¬м „мҠӨ bridge (opt-in мқҳмЎҙм„ұ)
//   typescript лӘЁл“Ҳ detect вҶ’ мӢӨм ң TypeScript Compiler API мӮ¬мҡ©
//   лҜём„Өм№ҳ мӢң м •к·ңмӢқ fallback (к·ёлһҳлҸ„ лҸҷмһ‘) вҶ’ score 5/50/90 м°Ёл“ұ
function _tryLoadLSP() {
  // typescript мҡ°м„  (Compiler API), м¶”нӣ„ pyright/vscode-languageserver нӣ„ліҙ
  const candidates = ['typescript'];
  for (const id of candidates) {
    try { return { ok: true, lib: require(id), name: id }; } catch {}
  }
  // кёҖлЎңлІҢ npm root мӢңлҸ„
  try {
    const r = cp.spawnSync('npm', ['root', '-g'], { encoding: 'utf8', timeout: 5000, shell: true });
    if (r.status === 0) {
      const globalRoot = (r.stdout || '').trim();
      for (const id of candidates) {
        try { return { ok: true, lib: require(path.join(globalRoot, id)), name: id, source: 'global' }; } catch {}
      }
    }
  } catch {}
  return { ok: false, error: 'typescript лҜём„Өм№ҳ вҖ” `npm i -g typescript` нӣ„ лӢӨмӢң мӢңлҸ„ (лҳҗлҠ” м •к·ңмӢқ fallback мӮ¬мҡ©)' };
}

// 1.9.173: лӢӨкөӯм–ҙ нҷ•мһҘ вҖ” Python/Go/Rust/Java нҢЁн„ҙ м¶”к°Җ (regex fallback)
//   нҢҢмқј нҷ•мһҘмһҗ кё°л°ҳ мһҗлҸҷ лқјмҡ°нҢ…. TypeScript Compiler API лҜём„Өм№ҳ мӢңм—җлҸ„ 5к°ң м–ём–ҙ м§Җмӣҗ.
// 1.9.335 (UR-0025 мӢ¬мёө): _LSP_LANG_PATTERNS (6м–ём–ҙ мӢ¬ліј нҢЁн„ҙ catalog) лҠ” lib/catalogs.js лЎң мқҙм „ (import).
// 1.9.335 (UR-0025 мӢ¬мёө): _detectLspLang лҠ” lib/pure-utils.js лЎң мқҙм „ (мҲңмҲҳ м–ём–ҙк°җм§Җ).

// м •к·ңмӢқ fallback вҖ” 6к°ң м–ём–ҙ (JS/TS/Python/Go/Rust/Java) symbol м¶”м¶ң (LSP м—ҶмқҙлҸ„ лҸҷмһ‘)
// 1.9.335 (UR-0025 мӢ¬мёө): мҲңмҲҳ л§ӨмІҳ _matchLspSymbols(catalog, content, lang) лЎң л¶„лҰ¬ вҖ” м—¬кё°лҠ” catalog мЈјмһ… л°•л§ү.
function _lspRegexSymbols(content, lang) {
  return _matchLspSymbols(_LSP_LANG_PATTERNS, content, lang);
}

// TypeScript Compiler API кё°л°ҳ symbol м¶”м¶ң (м •нҷ•)
function _lspTsSymbols(ts, content, fileName) {
  const symbols = [];
  const sf = ts.createSourceFile(fileName, content, ts.ScriptTarget.Latest, true);
  function visit(node) {
    let name = null, kind = null;
    if (ts.isFunctionDeclaration(node) && node.name) { name = node.name.text; kind = 'function'; }
    else if (ts.isClassDeclaration(node) && node.name) { name = node.name.text; kind = 'class'; }
    else if (ts.isInterfaceDeclaration(node)) { name = node.name.text; kind = 'interface'; }
    else if (ts.isTypeAliasDeclaration(node)) { name = node.name.text; kind = 'type'; }
    else if (ts.isEnumDeclaration(node)) { name = node.name.text; kind = 'enum'; }
    else if (ts.isVariableStatement(node)) {
      node.declarationList.declarations.forEach(d => {
        if (d.name && d.name.text && d.initializer
            && (ts.isArrowFunction(d.initializer) || ts.isFunctionExpression(d.initializer))) {
          const { line } = sf.getLineAndCharacterOfPosition(d.getStart());
          symbols.push({ name: d.name.text, kind: 'function', line: line + 1 });
        }
      });
    }
    if (name) {
      const { line } = sf.getLineAndCharacterOfPosition(node.getStart());
      symbols.push({ name, kind, line: line + 1 });
    }
    ts.forEachChild(node, visit);
  }
  visit(sf);
  return symbols;
}

function lspCmd(root, sub, ...args) {
  root = absRoot(root || process.cwd());
  if (!sub || sub === 'check') {
    const r = _tryLoadLSP();
    if (has('--json')) {
      log(JSON.stringify({
        installed: r.ok,
        name: r.name || null,
        source: r.source || 'local',
        error: r.error || null,
        fallback: 'regex (always available)'
      }, null, 2));
      return;
    }
    log(`# leerness lsp check (1.9.167)`);
    if (r.ok) {
      log(`вң“ ${r.name} л°ңкІ¬${r.source ? ` (${r.source})` : ''}`);
      log(`  вҶ’ leerness lsp symbols / references м •нҷ• лӘЁл“ң (Compiler API) мӮ¬мҡ©`);
    } else {
      log(`вҡ  ${r.error}`);
      log(`  вҶ’ м •к·ңмӢқ fallback мңјлЎң лҸҷмһ‘ (TS/JS н•ңм •, м •нҷ•лҸ„ м•Ҫк°„ лӮ®мқҢ)`);
    }
    return;
  }
  if (sub === 'symbols') {
    const file = args[0] || arg('--file', '');
    if (!file) return fail('leerness lsp symbols <file> н•„мҡ”');
    if (!fs.existsSync(file)) return fail(`нҢҢмқј м—ҶмқҢ: ${file}`);
    const content = fs.readFileSync(file, 'utf8');
    const t0 = Date.now();
    const lang = _detectLspLang(file);  // 1.9.173: м–ём–ҙ мһҗлҸҷ к°җм§Җ
    const r = _tryLoadLSP();
    let symbols, mode;
    try {
      if (r.ok && lang === 'javascript' && /\.(ts|tsx|js|jsx|mjs|cjs)$/.test(file)) {
        symbols = _lspTsSymbols(r.lib, content, file);
        mode = 'typescript-compiler';
      } else {
        symbols = _lspRegexSymbols(content, lang);  // 1.9.173: lang м „лӢ¬
        mode = `regex-fallback (${lang})`;
      }
    } catch (e) {
      symbols = _lspRegexSymbols(content, lang);
      mode = `regex-fallback (${lang}, after error: ${e.message})`;
    }
    const dt = Date.now() - t0;
    if (has('--json')) {
      log(JSON.stringify({ file, lang, symbols, count: symbols.length, mode, durationMs: dt }, null, 2));
    } else {
      log(`# leerness lsp symbols (1.9.173 лӢӨкөӯм–ҙ)`);
      log(`file: ${file}  В· lang: ${lang}`);
      log(`mode: ${mode} В· ${symbols.length} symbols В· ${dt}ms`);
      symbols.slice(0, 50).forEach(s => log(`  ${String(s.line).padStart(5)}:${s.kind.padEnd(10)} ${s.name}`));
      if (symbols.length > 50) log(`  ... ${symbols.length - 50} more`);
    }
    try { _recordRun(root, { kind: 'lsp_symbols', file, lang, count: symbols.length, mode, durationMs: dt, ok: true }); } catch {}
    return;
  }
  if (sub === 'references') {
    const name = args[0] || arg('--name', '');
    if (!name) return fail('leerness lsp references <symbol-name> н•„мҡ”');
    const inDir = arg('--in', root);
    const t0 = Date.now();
    // grep кё°л°ҳ fallback (мӢӨ LSP textDocument/references лҢҖмӢ )
    const refs = [];
    const escapedName = name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const reWord = new RegExp(`\\b${escapedName}\\b`);
    function walk(d) {
      let entries; try { entries = fs.readdirSync(d, { withFileTypes: true }); } catch { return; }
      for (const e of entries) {
        if (e.name.startsWith('.') || e.name === 'node_modules' || e.name === 'dist' || e.name === 'build') continue;
        const p = path.join(d, e.name);
        if (e.isDirectory()) walk(p);
        else if (/\.(ts|tsx|js|jsx|mjs|cjs|md|py|pyw|pyi|go|rs|java|kt|scala)$/.test(e.name)) {
          try {
            const lines = fs.readFileSync(p, 'utf8').split(/\r?\n/);
            lines.forEach((ln, idx) => {
              if (reWord.test(ln)) refs.push({ file: path.relative(root, p), line: idx + 1, text: ln.trim().slice(0, 120) });
            });
          } catch {}
        }
      }
    }
    walk(inDir);
    const dt = Date.now() - t0;
    if (has('--json')) {
      log(JSON.stringify({ name, count: refs.length, references: refs.slice(0, 100), durationMs: dt }, null, 2));
    } else {
      log(`# leerness lsp references (1.9.167)`);
      log(`symbol: "${name}" В· ${refs.length} references В· ${dt}ms`);
      refs.slice(0, 30).forEach(r => log(`  ${r.file}:${r.line}  ${r.text}`));
      if (refs.length > 30) log(`  ... ${refs.length - 30} more`);
    }
    try { _recordRun(root, { kind: 'lsp_references', name, count: refs.length, durationMs: dt, ok: true }); } catch {}
    return;
  }
  fail(`м•Ң мҲҳ м—ҶлҠ” sub: ${sub} (check / symbols / references)`);
}

// 1.9.176: мӮ¬мҡ©мһҗ мҡ”мІӯ мӮ¬м „ кІҖнҶ  (мӮ¬мҡ©мһҗ лӘ…мӢң мҡ”мІӯ)
//   AI м—җмқҙм „нҠёк°Җ мӮ¬мҡ©мһҗ мҡ”кө¬лҘј **л¬ҙмЎ°кұҙ кө¬нҳ„н•ҳкё° м „**м—җ лЁјм Җ:
